var SIE_QUESTIONS_OEP = [{"id":"qb-eq-001","section":"2 - Products & Risks","stem":"What type of security represents ownership in a corporation?","choices":{"A":"Corporate bond","B":"Common stock","C":"Municipal bond","D":"Treasury bill"},"answer":"B","explanation":"Common stock represents ownership (equity) in a corporation. Stockholders are part-owners of the company and have voting rights. Bonds are debt instruments where the holder is a creditor, not an owner.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-eq-002","section":"2 - Products & Risks","stem":"Which of the following shareholders has priority in receiving dividends?","choices":{"A":"Common stockholders","B":"Preferred stockholders","C":"Bondholders","D":"Warrant holders"},"answer":"B","explanation":"Preferred stockholders have priority over common stockholders for dividend payments. However, bondholders (creditors) must be paid interest before any dividends are distributed to shareholders.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-eq-003","section":"2 - Products & Risks","stem":"Common stockholders typically have which of the following rights?","choices":{"A":"Guaranteed dividends","B":"Voting rights on corporate matters","C":"Priority claim in bankruptcy","D":"Fixed interest payments"},"answer":"B","explanation":"Common stockholders have voting rights, typically one vote per share, on major corporate matters such as electing the board of directors and approving mergers.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-eq-004","section":"2 - Products & Risks","stem":"Which type of preferred stock allows unpaid dividends to accumulate?","choices":{"A":"Participating preferred","B":"Convertible preferred","C":"Cumulative preferred","D":"Callable preferred"},"answer":"C","explanation":"Cumulative preferred stock accumulates any unpaid dividends (dividends in arrears). These must be paid before any dividends can be paid to common stockholders.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-eq-005","section":"2 - Products & Risks","stem":"An American Depositary Receipt (ADR) represents:","choices":{"A":"Ownership in a U.S. company traded overseas","B":"Ownership in a foreign company traded in U.S. markets","C":"A type of U.S. government bond","D":"A derivative contract on foreign currency"},"answer":"B","explanation":"ADRs are certificates issued by U.S. banks representing shares of foreign companies. They allow U.S. investors to easily invest in foreign companies through U.S. exchanges.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-eq-006","section":"2 - Products & Risks","stem":"Rights and warrants are similar in that both:","choices":{"A":"Have unlimited life spans","B":"Are issued by the corporation","C":"Give the holder the right to buy stock at a set price","D":"Pay dividends to the holder"},"answer":"C","explanation":"Both rights and warrants give holders the right to purchase common stock at a specified price. Rights are short-term (weeks) while warrants are long-term (years).","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-debt-001","section":"2 - Products & Risks","stem":"If interest rates rise, what happens to the price of existing bonds?","choices":{"A":"Bond prices rise","B":"Bond prices fall","C":"Bond prices remain unchanged","D":"Bond coupon rates increase"},"answer":"B","explanation":"Bond prices and interest rates have an inverse relationship. When interest rates rise, existing bonds with lower coupon rates become less attractive compared to new bonds issued at higher rates, causing their prices to fall.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-debt-002","section":"2 - Products & Risks","stem":"Municipal bond interest is typically exempt from which type of tax?","choices":{"A":"State income tax only","B":"Federal income tax only","C":"Federal income tax, and possibly state tax if issued in your state","D":"Capital gains tax"},"answer":"C","explanation":"Municipal bond interest is exempt from federal income tax. If the bond is issued in your state of residence, it may also be exempt from state and local taxes (triple tax-free).","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-debt-003","section":"2 - Products & Risks","stem":"A bond trading at 95 is trading at:","choices":{"A":"A premium","B":"A discount","C":"Par value","D":"Face value"},"answer":"B","explanation":"Bond prices are quoted as a percentage of par (face value). A bond at 95 is trading at 95% of par ($950 for a $1,000 bond), which is a discount. Premium = above 100, discount = below 100.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-debt-004","section":"2 - Products & Risks","stem":"Which type of bond is backed by the full faith and credit of the U.S. government?","choices":{"A":"Corporate bonds","B":"Municipal bonds","C":"Treasury securities","D":"Agency bonds"},"answer":"C","explanation":"Treasury securities (T-bills, T-notes, T-bonds) are backed by the full faith and credit of the U.S. government, making them the safest fixed-income investments.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-debt-005","section":"2 - Products & Risks","stem":"Current yield is calculated as:","choices":{"A":"Coupon rate divided by par value","B":"Annual interest divided by current market price","C":"Total return divided by years to maturity","D":"Yield to maturity minus coupon rate"},"answer":"B","explanation":"Current yield = Annual Interest / Current Market Price. It measures the income return on a bond based on what you actually pay, not the par value.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-debt-006","section":"2 - Products & Risks","stem":"Which bond rating indicates investment grade quality?","choices":{"A":"BB","B":"CCC","C":"BBB","D":"D"},"answer":"C","explanation":"BBB (or Baa for Moody's) is the lowest investment grade rating. Anything below BBB/Baa is considered speculative or \"junk\" grade.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-debt-007","section":"2 - Products & Risks","stem":"A zero-coupon bond:","choices":{"A":"Pays interest monthly","B":"Is sold at a discount and matures at par","C":"Has a variable interest rate","D":"Can only be issued by the government"},"answer":"B","explanation":"Zero-coupon bonds pay no periodic interest. They are sold at a deep discount and the investor's return comes from the difference between purchase price and par value at maturity.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-reg-001","section":"4 - Regulatory Framework","stem":"Which organization regulates broker-dealers?","choices":{"A":"Federal Reserve Board (FRB)","B":"FINRA","C":"MSRB","D":"State insurance commissioners"},"answer":"B","explanation":"FINRA (Financial Industry Regulatory Authority) is the self-regulatory organization (SRO) that regulates broker-dealers and their registered representatives.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-reg-002","section":"2 - Products & Risks","stem":"Blue sky laws are:","choices":{"A":"Federal securities regulations","B":"State securities regulations","C":"International securities regulations","D":"Self-regulatory organization rules"},"answer":"B","explanation":"Blue sky laws are STATE-level securities regulations designed to protect investors from fraud. Each state has its own blue sky laws, which may differ from federal regulations.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-reg-003","section":"4 - Regulatory Framework","stem":"The Securities Act of 1933 primarily regulates:","choices":{"A":"Secondary market trading","B":"New issues of securities (primary market)","C":"Investment advisers","D":"Broker-dealer conduct"},"answer":"B","explanation":"The Securities Act of 1933 (Paper Act) regulates the PRIMARY market - new issues of securities. It requires registration and disclosure through a prospectus.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-reg-004","section":"1 - Capital Markets","stem":"Which act created the Securities and Exchange Commission (SEC)?","choices":{"A":"Securities Act of 1933","B":"Securities Exchange Act of 1934","C":"Investment Company Act of 1940","D":"Investment Advisers Act of 1940"},"answer":"B","explanation":"The Securities Exchange Act of 1934 created the SEC and regulates secondary market trading, broker-dealers, and exchanges.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-reg-005","section":"4 - Regulatory Framework","stem":"FINRA Rule 2111 (Suitability) requires that recommendations be suitable based on:","choices":{"A":"Only the customer's age","B":"The customer's investment profile","C":"Only the security's past performance","D":"The broker's commission structure"},"answer":"B","explanation":"Suitability requires that recommendations be based on the customer's investment profile, including risk tolerance, financial situation, investment objectives, time horizon, and other factors.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-opt-001","section":"2 - Products & Risks","stem":"A call option gives the holder the right to:","choices":{"A":"Sell the underlying asset at the strike price","B":"Buy the underlying asset at the strike price","C":"Receive dividends from the underlying stock","D":"Vote on corporate matters"},"answer":"B","explanation":"A call option gives the holder (buyer) the RIGHT to BUY the underlying asset at the strike price before expiration. The call buyer is bullish - expecting the price to rise.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-opt-002","section":"2 - Products & Risks","stem":"A put option gives the holder the right to:","choices":{"A":"Buy the underlying asset at the strike price","B":"Sell the underlying asset at the strike price","C":"Receive a fixed interest payment","D":"Convert to common stock"},"answer":"B","explanation":"A put option gives the holder the RIGHT to SELL the underlying asset at the strike price. Put buyers are bearish - they profit when the price falls below the strike price.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-opt-003","section":"2 - Products & Risks","stem":"What is the maximum loss for a call option buyer?","choices":{"A":"Unlimited","B":"The strike price","C":"The premium paid","D":"The stock price minus the strike price"},"answer":"C","explanation":"The maximum loss for a call buyer is limited to the premium paid for the option. If the stock price stays below the strike price, the option expires worthless, and the buyer loses only the premium.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-opt-004","section":"2 - Products & Risks","stem":"An investor who is bullish on a stock would most likely:","choices":{"A":"Buy a put option","B":"Sell a call option","C":"Buy a call option","D":"Sell stock short"},"answer":"C","explanation":"A bullish investor expects the stock price to rise. Buying a call option profits when the stock goes up - it gives the right to buy at a fixed price while the stock rises.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-opt-005","section":"2 - Products & Risks","stem":"The breakeven point for a call option buyer is:","choices":{"A":"Strike price minus premium","B":"Strike price plus premium","C":"Market price minus premium","D":"Premium only"},"answer":"B","explanation":"For a call buyer, breakeven = Strike Price + Premium. The stock must rise above this point for the buyer to profit. At exactly this price, gains from exercise equal the premium paid.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-pkg-001","section":"2 - Products & Risks","stem":"Open-end mutual funds are priced:","choices":{"A":"Throughout the trading day like stocks","B":"Once per day after market close (forward pricing)","C":"Weekly based on NAV","D":"At a fixed price set by the fund manager"},"answer":"B","explanation":"Open-end mutual funds use forward pricing - shares are priced once daily after the market closes based on Net Asset Value (NAV). Orders placed during the day execute at the next calculated NAV.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-pkg-002","section":"1 - Capital Markets","stem":"Which type of fund trades on an exchange like a stock?","choices":{"A":"Open-end mutual fund","B":"Unit Investment Trust (UIT)","C":"Exchange-Traded Fund (ETF)","D":"Money market fund"},"answer":"C","explanation":"ETFs trade on exchanges throughout the day at market prices, just like stocks. They can be bought/sold anytime during market hours, unlike mutual funds.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-pkg-003","section":"2 - Products & Risks","stem":"A closed-end fund differs from an open-end fund in that a closed-end fund:","choices":{"A":"Has a fixed number of shares that trade on an exchange","B":"Continuously issues and redeems shares","C":"Must maintain a stable NAV of $1","D":"Cannot invest in stocks"},"answer":"A","explanation":"Closed-end funds issue a fixed number of shares through an IPO, which then trade on exchanges. They do NOT continuously issue or redeem shares like open-end funds.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-pkg-004","section":"2 - Products & Risks","stem":"The sales charge on a mutual fund is called:","choices":{"A":"Management fee","B":"12b-1 fee","C":"Load","D":"Expense ratio"},"answer":"C","explanation":"The sales charge on a mutual fund is called a \"load.\" Front-end loads are paid at purchase, back-end loads (CDSC) are paid at redemption. No-load funds have no sales charges.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-pkg-005","section":"2 - Products & Risks","stem":"Variable annuities are considered securities because:","choices":{"A":"They pay a fixed interest rate","B":"The return depends on the performance of underlying investments","C":"They are issued by the federal government","D":"They have a guaranteed death benefit"},"answer":"B","explanation":"Variable annuities are securities because the return varies based on the performance of underlying sub-accounts (similar to mutual funds). This investment risk makes them securities requiring registration.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch1-001","section":"2 - Products & Risks","stem":"Which organization administers the SIE exam and other securities qualification exams?","choices":{"A":"Securities and Exchange Commission (SEC)","B":"Financial Industry Regulatory Authority (FINRA)","C":"Municipal Securities Rulemaking Board (MSRB)","D":"Securities Investor Protection Corporation (SIPC)"},"answer":"B","explanation":"FINRA administers qualification exams including the SIE, Series 7, Series 63, and others. The SEC oversees FINRA but does not directly administer licensing exams. The MSRB only writes rules for municipal securities, and SIPC handles customer protection when firms fail.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch1-002","section":"4 - Regulatory Framework","stem":"SIPC protection covers which of the following?","choices":{"A":"Losses from a decline in stock prices","B":"Missing assets when a brokerage firm fails","C":"Losses from following bad investment advice","D":"Fraud committed by a registered representative"},"answer":"B","explanation":"SIPC protects customers when a brokerage firm fails and customer assets are missing — up to $500,000 per customer. SIPC does NOT cover market losses, bad advice, or fraud. It only addresses the failure of the brokerage firm itself.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch1-003","section":"4 - Regulatory Framework","stem":"Which statement about the MSRB is correct?","choices":{"A":"The MSRB enforces its own rules through fines and suspensions","B":"The MSRB writes rules for municipal securities but does not enforce them","C":"The MSRB regulates all types of bonds, including corporate bonds","D":"The MSRB is a federal government agency"},"answer":"B","explanation":"The MSRB is a rulemaking body that writes rules for municipal securities transactions, but it does not enforce those rules. Enforcement is handled by FINRA (for broker-dealers) and the SEC. The MSRB is a self-regulatory organization, not a government agency.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch1-004","section":"2 - Products & Risks","stem":"What is the origin of the term \"Blue Sky Laws\"?","choices":{"A":"They were first passed in states with clear blue skies","B":"They referred to investments with no more substance than blue sky","C":"Blue was the color of the first securities certificates","D":"The laws were named after Senator Blue Sky"},"answer":"B","explanation":"Blue Sky Laws got their name from early concerns about promoters selling investments with \"no more basis than so many feet of blue sky\" — meaning worthless, speculative schemes. The term reflects the laws' purpose of protecting investors from fraud.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch1-005","section":"4 - Regulatory Framework","stem":"Which organization coordinates securities regulation among the states and developed the Uniform Securities Act?","choices":{"A":"Securities and Exchange Commission (SEC)","B":"Financial Industry Regulatory Authority (FINRA)","C":"North American Securities Administrators Association (NASAA)","D":"Municipal Securities Rulemaking Board (MSRB)"},"answer":"C","explanation":"NASAA (North American Securities Administrators Association) coordinates state securities regulation and developed the Uniform Securities Act to bring consistency across states. The SEC is a federal regulator, FINRA regulates broker-dealers, and the MSRB focuses on municipal securities.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch1-006","section":"2 - Products & Risks","stem":"Under federal preemption rules, which of the following is a \"federal covered security\" that states cannot require to be registered?","choices":{"A":"Securities sold only within one state","B":"Securities listed on the New York Stock Exchange","C":"Securities issued by small private companies","D":"Municipal bonds issued by local governments"},"answer":"B","explanation":"Securities listed on national exchanges like the NYSE or NASDAQ are \"federal covered securities\" under NSMIA. States cannot require registration for these securities, though they may require notice filings and retain anti-fraud authority.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch1-007","section":"4 - Regulatory Framework","stem":"When a broker-dealer sells securities from its own inventory to a customer, it is acting in what capacity?","choices":{"A":"Broker (agent)","B":"Dealer (principal)","C":"Custodian","D":"Transfer agent"},"answer":"B","explanation":"When a broker-dealer sells from its own inventory, it acts as a dealer (principal). When it executes trades on behalf of customers without using its own inventory, it acts as a broker (agent). The capacity affects how the firm is compensated — markup/markdown for principal transactions, commission for agency transactions.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch1-008","section":"4 - Regulatory Framework","stem":"An investment adviser with $150 million in assets under management would register with which regulator?","choices":{"A":"FINRA","B":"The state securities administrator","C":"The Securities and Exchange Commission (SEC)","D":"The Municipal Securities Rulemaking Board (MSRB)"},"answer":"C","explanation":"Investment advisers with $110 million or more in assets under management must register with the SEC. Those with less than $100 million register with state regulators. FINRA regulates broker-dealers, not investment advisers, and the MSRB focuses on municipal securities.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch1-009","section":"4 - Regulatory Framework","stem":"Which market participant maintains the official records of who owns a company's shares?","choices":{"A":"Custodian","B":"Transfer agent","C":"Clearing corporation","D":"Market maker"},"answer":"B","explanation":"The transfer agent maintains the issuer's official shareholder records, including who owns shares and their contact information. Custodians hold securities for safekeeping, clearing corporations settle trades, and market makers provide liquidity.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch1-010","section":"2 - Products & Risks","stem":"In which market does a company receive proceeds when its securities are sold?","choices":{"A":"Secondary market","B":"Primary market","C":"Auction market","D":"Fourth market"},"answer":"B","explanation":"The primary market is where new securities are issued, and the issuing company receives the proceeds. In the secondary market, investors trade with each other and the company receives nothing from those transactions.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch1-011","section":"2 - Products & Risks","stem":"What is the key difference between an auction market and a dealer market?","choices":{"A":"Auction markets only trade bonds; dealer markets trade stocks","B":"In auction markets, buyers and sellers compete on price; in dealer markets, dealers quote prices","C":"Auction markets are unregulated; dealer markets are regulated","D":"Dealer markets are faster than auction markets"},"answer":"B","explanation":"In an auction market (like NYSE), buyers and sellers compete directly, with the highest bid matched to the lowest ask. In a dealer market (like NASDAQ), dealers quote bid and ask prices and trade from their own inventory. Both types trade stocks and both are regulated.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch1-012","section":"2 - Products & Risks","stem":"The NASDAQ is an example of what type of market?","choices":{"A":"Auction market","B":"Dealer market","C":"Primary market","D":"Fourth market"},"answer":"B","explanation":"NASDAQ operates as a dealer market where market makers quote bid and ask prices for securities. The NYSE, by contrast, is an auction market. Both are secondary markets where previously issued securities trade.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch1-013","section":"2 - Products & Risks","stem":"Which statement correctly describes the difference between NYSE and NASDAQ?","choices":{"A":"NYSE is electronic; NASDAQ has a physical trading floor","B":"NYSE is an auction market; NASDAQ is a dealer market","C":"NYSE only lists technology companies; NASDAQ lists all types","D":"NYSE has lower listing requirements than NASDAQ"},"answer":"B","explanation":"The NYSE operates as an auction market where buyers and sellers compete on price, facilitated by Designated Market Makers. NASDAQ is a dealer market where multiple market makers quote prices and trade from inventory. The NYSE has a physical trading floor (though most trading is electronic), while NASDAQ is fully electronic.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch1-014","section":"2 - Products & Risks","stem":"What is the role of a Designated Market Maker (DMM) on the NYSE?","choices":{"A":"To underwrite IPOs for listed companies","B":"To maintain fair and orderly markets in assigned stocks","C":"To set listing requirements for new companies","D":"To regulate trading activities on behalf of the SEC"},"answer":"B","explanation":"Designated Market Makers (DMMs) on the NYSE are responsible for maintaining fair and orderly markets in the stocks assigned to them. They provide liquidity, set opening prices, and step in during imbalances. They do not underwrite IPOs or regulate on behalf of the SEC.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch1-015","section":"2 - Products & Risks","stem":"A company whose stock price falls below $1.00 for an extended period may face what consequence?","choices":{"A":"Automatic transfer to NASDAQ","B":"Delisting from the exchange","C":"Required stock split","D":"SEC investigation"},"answer":"B","explanation":"Both NYSE and NASDAQ require listed companies to maintain a minimum share price (typically $1.00). Companies that fall below this threshold for an extended period and fail to regain compliance may be delisted from the exchange.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch1-016","section":"2 - Products & Risks","stem":"Which tier of the OTC markets has the highest quality standards and requires SEC reporting or equivalent?","choices":{"A":"Pink Market","B":"OTCQB","C":"OTCQX","D":"OTCBB"},"answer":"C","explanation":"OTCQX is the highest tier of OTC Markets, requiring companies to be current in SEC reporting (or equivalent), meet minimum financial standards, and have a third-party sponsor. OTCQB is the middle tier for venture companies, and the Pink Market has minimal requirements.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch1-017","section":"2 - Products & Risks","stem":"What is a key risk associated with securities trading on the Pink Market?","choices":{"A":"They must be held for one year before selling","B":"They have limited liquidity and higher fraud risk","C":"They can only be purchased by institutional investors","D":"They are guaranteed by SIPC"},"answer":"B","explanation":"Pink Market securities carry significant risks including limited liquidity (difficulty selling), price volatility, limited financial disclosure, and higher incidence of fraud and manipulation. They have no holding period requirements and can be purchased by retail investors, but they are not guaranteed by SIPC beyond normal coverage.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch1-018","section":"4 - Regulatory Framework","stem":"Penny stocks traded OTC require broker-dealers to do which of the following?","choices":{"A":"Guarantee the investment against loss","B":"Provide risk disclosure documents to customers","C":"Only sell to accredited investors","D":"Register the securities with the SEC"},"answer":"B","explanation":"When selling penny stocks (generally under $5), broker-dealers must provide risk disclosure documents to customers, obtain signed suitability statements, and disclose information about bid-ask spreads and compensation. They cannot guarantee against loss and penny stocks can be sold to non-accredited investors.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch1-019","section":"2 - Products & Risks","stem":"Which entity is responsible for monetary policy in the United States?","choices":{"A":"U.S. Congress","B":"The President","C":"The Federal Reserve","D":"The Treasury Department"},"answer":"C","explanation":"The Federal Reserve (the Fed) is responsible for monetary policy, which involves managing interest rates and money supply. Fiscal policy (taxes and spending) is controlled by Congress and the President. The Treasury Department manages government finances but does not set monetary policy.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch1-020","section":"2 - Products & Risks","stem":"When the Federal Reserve wants to stimulate the economy, it typically:","choices":{"A":"Raises interest rates and sells securities","B":"Lowers interest rates and buys securities","C":"Increases taxes","D":"Decreases government spending"},"answer":"B","explanation":"To stimulate the economy (expansionary monetary policy), the Fed lowers interest rates and buys securities through open market operations. This increases the money supply and makes borrowing cheaper. Raising rates and selling securities would be contractionary. Taxes and spending are fiscal policy tools controlled by Congress.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch1-021","section":"2 - Products & Risks","stem":"What is the dual mandate of the Federal Reserve?","choices":{"A":"Regulate banks and print currency","B":"Maximum employment and price stability","C":"Set taxes and control spending","D":"Oversee stock exchanges and protect investors"},"answer":"B","explanation":"Congress gave the Federal Reserve a dual mandate: maximum employment and price stability (controlling inflation). The Fed uses monetary policy tools to balance these sometimes competing goals. Bank regulation and currency are Fed functions, but not the mandate. Taxes/spending are Congressional, and securities oversight is the role of the SEC.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch1-022","section":"2 - Products & Risks","stem":"When interest rates rise, what typically happens to existing bond prices?","choices":{"A":"They rise","B":"They fall","C":"They stay the same","D":"They become more volatile but unchanged on average"},"answer":"B","explanation":"Bond prices and interest rates have an inverse relationship. When rates rise, new bonds offer higher yields, making existing bonds (with lower coupon rates) less attractive. To compete, existing bond prices must fall until their yields match the new market rates.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch1-023","section":"2 - Products & Risks","stem":"An inverted yield curve, where short-term rates exceed long-term rates, is often considered a signal of:","choices":{"A":"Strong economic growth ahead","B":"A potential recession","C":"Rising inflation","D":"Stock market gains"},"answer":"B","explanation":"An inverted yield curve occurs when investors expect future interest rates to fall, typically because they anticipate economic slowdown. Historically, inverted yield curves have preceded most U.S. recessions, making them an important economic indicator.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch1-024","section":"2 - Products & Risks","stem":"Which bond would experience the largest price decline if interest rates rose by 1%?","choices":{"A":"A bond with 2-year duration","B":"A bond with 5-year duration","C":"A bond with 10-year duration","D":"All would decline equally"},"answer":"C","explanation":"Duration measures how sensitive a bond price is to interest rate changes. A bond with 10-year duration would decline approximately 10% for a 1% rate increase, while a 5-year duration bond would decline about 5%, and a 2-year duration bond about 2%. Longer duration means greater rate sensitivity.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch1-025","section":"2 - Products & Risks","stem":"Which phase of the business cycle is characterized by falling GDP, rising unemployment, and declining consumer confidence?","choices":{"A":"Expansion","B":"Peak","C":"Contraction","D":"Trough"},"answer":"C","explanation":"The contraction phase (also called recession when severe) is characterized by falling economic output (GDP), rising unemployment, declining consumer spending and confidence, and reduced business investment. This is the opposite of expansion, which features rising GDP and employment.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch1-026","section":"2 - Products & Risks","stem":"Stock market performance is considered what type of economic indicator?","choices":{"A":"Leading indicator","B":"Coincident indicator","C":"Lagging indicator","D":"Counter-cyclical indicator"},"answer":"A","explanation":"The stock market is a leading indicator because it reflects investor expectations about future economic conditions. Stock prices typically rise before the economy recovers and fall before recessions, making them useful for predicting economic direction.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch1-027","section":"2 - Products & Risks","stem":"Which sector would likely perform best during an economic contraction?","choices":{"A":"Consumer discretionary (luxury goods)","B":"Industrial machinery","C":"Consumer staples (food, household products)","D":"Automobile manufacturing"},"answer":"C","explanation":"Consumer staples (food, household products, toiletries) are defensive because people need these items regardless of economic conditions. During contractions, consumers cut back on discretionary spending (luxury goods, cars, travel) but continue buying necessities, making staples stocks more resilient.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch1-028","section":"2 - Products & Risks","stem":"Which of the following would benefit from a stronger U.S. dollar?","choices":{"A":"U.S. exporters selling products abroad","B":"U.S. importers buying foreign goods","C":"U.S. tourists traveling to Europe","D":"U.S. manufacturers competing with foreign companies"},"answer":"B","explanation":"A stronger dollar means U.S. importers can buy more foreign goods with fewer dollars, reducing their costs. U.S. exporters are hurt because their products become more expensive for foreign buyers. U.S. tourists also benefit abroad because their dollars buy more foreign currency.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch1-029","section":"2 - Products & Risks","stem":"What is an American Depositary Receipt (ADR)?","choices":{"A":"A U.S. government bond held by foreign investors","B":"A U.S. security representing shares of a foreign company","C":"A receipt for goods imported into the United States","D":"A currency exchange contract"},"answer":"B","explanation":"An ADR is a certificate issued by a U.S. bank that represents shares of a foreign company. ADRs trade on U.S. exchanges or OTC, are priced in dollars, and pay dividends in dollars, making it convenient for U.S. investors to own foreign stocks without dealing with foreign exchanges.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch1-030","section":"2 - Products & Risks","stem":"An investor buys shares of a European company. The stock price increases 8% in euros, but the euro falls 10% against the dollar. What is the approximate return in dollar terms?","choices":{"A":"Positive 18%","B":"Positive 8%","C":"Negative 2%","D":"Negative 10%"},"answer":"C","explanation":"Currency movements affect returns on foreign investments. While the stock gained 8% in euros, the 10% decline of the euro against the dollar more than offset this gain. The approximate dollar return is 8% - 10% = -2% (the actual calculation is slightly different due to compounding, but negative 2% is the closest answer).","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-001","section":"2 - Products & Risks","stem":"Which of the following rights is MOST commonly associated with common stock ownership?","choices":{"A":"Guaranteed annual dividend payments","B":"Voting for the board of directors","C":"Priority claim in bankruptcy over bondholders","D":"Fixed redemption price at maturity"},"answer":"B","explanation":"Common stockholders have the right to vote for the board of directors. Dividends are not guaranteed, common stockholders are last in line during bankruptcy (after bondholders), and common stock has no maturity date or redemption price.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-002","section":"3 - Trading, Accounts & Prohibited","stem":"In the event of corporate liquidation, what is the order of priority for receiving distributions?","choices":{"A":"Common stockholders, preferred stockholders, bondholders","B":"Preferred stockholders, common stockholders, bondholders","C":"Bondholders, preferred stockholders, common stockholders","D":"Bondholders, common stockholders, preferred stockholders"},"answer":"C","explanation":"In liquidation, creditors (bondholders) are paid first, followed by preferred stockholders, with common stockholders receiving any remaining assets last. This order reflects the risk hierarchy of securities.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-003","section":"2 - Products & Risks","stem":"Preemptive rights allow existing shareholders to:","choices":{"A":"Receive dividends before new shareholders","B":"Vote on all matters before the board of directors","C":"Purchase newly issued shares before the public","D":"Redeem their shares at par value on demand"},"answer":"C","explanation":"Preemptive rights give existing shareholders the opportunity to purchase newly issued shares before they are offered to the public. This allows shareholders to maintain their proportional ownership in the company and avoid dilution.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-004","section":"2 - Products & Risks","stem":"An investor owns 200 shares of XYZ stock at $60 per share. After a 3-for-1 stock split, how many shares will the investor own and at what price?","choices":{"A":"600 shares at $20 per share","B":"67 shares at $180 per share","C":"200 shares at $60 per share","D":"600 shares at $60 per share"},"answer":"A","explanation":"In a 3-for-1 split, the number of shares triples (200 x 3 = 600) while the price is divided by 3 ($60 / 3 = $20). The total value remains unchanged at $12,000.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-005","section":"2 - Products & Risks","stem":"To receive a declared cash dividend, an investor must purchase shares:","choices":{"A":"On or before the payment date","B":"On or before the declaration date","C":"Before the ex-dividend date","D":"On the record date"},"answer":"C","explanation":"To receive a dividend, an investor must purchase shares before the ex-dividend date. Buying on or after the ex-dividend date means the seller, not the buyer, receives the dividend. Under T+1 settlement (since May 2024), the ex-dividend date and record date are the same day.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-006","section":"2 - Products & Risks","stem":"A company announces a 1-for-5 reverse stock split. An investor who owns 500 shares at $4 per share will have:","choices":{"A":"2,500 shares at $0.80 per share","B":"100 shares at $20 per share","C":"500 shares at $20 per share","D":"100 shares at $4 per share"},"answer":"B","explanation":"In a 1-for-5 reverse split, shares are divided by 5 (500 / 5 = 100 shares) and the price is multiplied by 5 ($4 x 5 = $20). The total value stays the same at $2,000.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-007","section":"2 - Products & Risks","stem":"A company has cumulative preferred stock outstanding with an annual dividend of $5 per share. The company failed to pay dividends for the past two years. How much must be paid to preferred shareholders before common shareholders receive any dividend?","choices":{"A":"$5 per share","B":"$10 per share","C":"$15 per share","D":"$20 per share"},"answer":"C","explanation":"Cumulative preferred stock requires all missed dividends (dividends in arrears) plus the current dividend to be paid before common shareholders receive anything. Two years of arrears ($10) plus the current year dividend ($5) equals $15 per share.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-008","section":"2 - Products & Risks","stem":"Which feature distinguishes preferred stock from common stock?","choices":{"A":"Preferred stock has voting rights","B":"Preferred stock has unlimited growth potential","C":"Preferred stock has priority for dividend payments","D":"Preferred stock is always convertible to bonds"},"answer":"C","explanation":"Preferred stock has priority over common stock for dividend payments. Preferred stockholders typically do not have voting rights (common stockholders do), preferred stock has limited growth potential, and preferred stock is not convertible to bonds (though it may be convertible to common stock).","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-009","section":"2 - Products & Risks","stem":"When interest rates rise, what typically happens to the market price of fixed-rate preferred stock?","choices":{"A":"The price increases","B":"The price decreases","C":"The price remains unchanged","D":"The dividend increases"},"answer":"B","explanation":"Preferred stock prices move inversely to interest rates. When interest rates rise, newly issued preferred stocks offer higher dividends, making existing fixed-rate preferred stocks less attractive, which causes their prices to fall.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-011","section":"2 - Products & Risks","stem":"Which level of sponsored ADR can raise new capital in the United States through a public offering?","choices":{"A":"Level I","B":"Level II","C":"Level III","D":"All levels can raise capital equally"},"answer":"C","explanation":"Only Level III ADRs can raise new capital through public offerings in the U.S. Level I ADRs trade OTC with minimal SEC registration, and Level II ADRs can list on exchanges but cannot raise capital. Level III requires full SEC registration and a prospectus for capital raising.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-012","section":"2 - Products & Risks","stem":"An investor holds ADRs of a European company. If the euro weakens against the U.S. dollar, what is the most likely effect on the ADR value?","choices":{"A":"ADR value increases","B":"ADR value decreases","C":"ADR value is unaffected because it trades in U.S. dollars","D":"ADR dividends increase to compensate"},"answer":"B","explanation":"Although ADRs trade in U.S. dollars, they represent foreign shares valued in foreign currency. When the foreign currency weakens against the dollar, the value of the underlying shares decreases in dollar terms, causing the ADR price to decline.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-013","section":"2 - Products & Risks","stem":"A bond with a 5% coupon rate and $1,000 par value pays how much in annual interest?","choices":{"A":"$5","B":"$50","C":"$500","D":"$5,000"},"answer":"B","explanation":"Annual interest is calculated as par value multiplied by the coupon rate: $1,000 x 0.05 = $50 per year. Most bonds pay this semi-annually, so the investor would receive $25 every six months.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-014","section":"2 - Products & Risks","stem":"When market interest rates rise, what happens to the prices of existing bonds?","choices":{"A":"Bond prices rise","B":"Bond prices fall","C":"Bond prices remain unchanged","D":"Bond coupon rates increase"},"answer":"B","explanation":"Bond prices and interest rates have an inverse relationship. When market interest rates rise, existing bonds with lower coupon rates become less attractive, causing their prices to fall. Coupon rates on existing bonds are fixed and do not change.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-015","section":"2 - Products & Risks","stem":"A bond is quoted at 97. What is the dollar price for a bond with a $1,000 par value?","choices":{"A":"$97","B":"$970","C":"$1,097","D":"$9,700"},"answer":"B","explanation":"Bond quotes are expressed as a percentage of par value. A quote of 97 means 97% of par value: $1,000 x 0.97 = $970. This bond is trading at a discount (below par).","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-016","section":"2 - Products & Risks","stem":"A bond with a 5% coupon rate is currently trading at $900. What is the current yield?","choices":{"A":"4.50%","B":"5.00%","C":"5.56%","D":"9.00%"},"answer":"C","explanation":"Current yield = Annual Interest / Market Price. A 5% coupon on $1,000 par pays $50 annually. Current Yield = $50 / $900 = 5.56%. Since the bond trades at a discount, the current yield is higher than the nominal yield.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-017","section":"2 - Products & Risks","stem":"For a bond trading at a premium, which yield is typically the LOWEST?","choices":{"A":"Nominal yield","B":"Current yield","C":"Yield to maturity","D":"Yield to call"},"answer":"D","explanation":"For premium bonds, the yield order from lowest to highest is: YTC < YTM < CY < NY. Yield to call is lowest because if the bond is called, the investor loses the premium faster and receives fewer interest payments.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-018","section":"2 - Products & Risks","stem":"A bond is trading at par. Which statement about its yields is TRUE?","choices":{"A":"Current yield is higher than nominal yield","B":"YTM is lower than current yield","C":"All four yields are approximately equal","D":"YTC is higher than YTM"},"answer":"C","explanation":"When a bond trades at par value, all four yields (nominal, current, YTM, and YTC) are equal. There is no capital gain or loss to affect the total return calculations.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-019","section":"2 - Products & Risks","stem":"Which Treasury security is sold at a discount and pays no periodic interest?","choices":{"A":"Treasury notes","B":"Treasury bonds","C":"Treasury bills","D":"TIPS"},"answer":"C","explanation":"Treasury bills (T-bills) are sold at a discount from face value and pay no periodic interest. The investor's return is the difference between the purchase price and the par value received at maturity. T-notes, T-bonds, and TIPS all pay semi-annual interest.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-020","section":"2 - Products & Risks","stem":"TIPS protect investors against which type of risk?","choices":{"A":"Credit risk","B":"Interest rate risk","C":"Purchasing power (inflation) risk","D":"Liquidity risk"},"answer":"C","explanation":"TIPS (Treasury Inflation-Protected Securities) protect against purchasing power risk by adjusting the principal based on the Consumer Price Index (CPI). As inflation rises, the principal increases, providing inflation protection. However, TIPS are still subject to interest rate risk.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-021","section":"2 - Products & Risks","stem":"Interest from Treasury securities is:","choices":{"A":"Exempt from all taxes","B":"Subject to federal, state, and local taxes","C":"Subject to federal tax but exempt from state and local taxes","D":"Subject to state tax but exempt from federal tax"},"answer":"C","explanation":"Treasury interest is subject to federal income tax but exempt from state and local income taxes. This tax advantage makes Treasuries especially attractive for investors in high-tax states.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-022","section":"1 - Capital Markets","stem":"Which type of corporate bond is backed only by the general creditworthiness of the issuer?","choices":{"A":"Mortgage bond","B":"Equipment trust certificate","C":"Debenture","D":"Collateral trust bond"},"answer":"C","explanation":"A debenture is an unsecured bond backed only by the issuer's ability and promise to pay. Mortgage bonds, equipment trust certificates, and collateral trust bonds are all secured by specific assets that bondholders can claim if the issuer defaults.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-023","section":"2 - Products & Risks","stem":"A bond rated BBB by S&P is considered:","choices":{"A":"Junk bond","B":"Investment grade","C":"In default","D":"Not rated"},"answer":"B","explanation":"BBB is the lowest investment-grade rating from S&P. Bonds rated BBB- or higher (Baa3 for Moody's) are considered investment grade. Bonds rated BB+ or lower are non-investment grade, also known as junk or high-yield bonds.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-024","section":"2 - Products & Risks","stem":"A convertible bond with a par value of $1,000 and a conversion ratio of 20 has a conversion price of:","choices":{"A":"$20","B":"$50","C":"$200","D":"$1,000"},"answer":"B","explanation":"Conversion price = Par Value / Conversion Ratio. $1,000 / 20 = $50. This means the bondholder effectively pays $50 per share when converting. If the stock price rises above $50, conversion becomes attractive.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-025","section":"1 - Capital Markets","stem":"Which type of municipal bond is backed by the taxing authority of the issuer?","choices":{"A":"Revenue bond","B":"Industrial development bond","C":"General obligation bond","D":"Private activity bond"},"answer":"C","explanation":"General obligation (GO) bonds are backed by the full faith and credit of the issuer, including its power to levy taxes. Revenue bonds are backed only by income from a specific project, not by taxing authority.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-026","section":"2 - Products & Risks","stem":"An investor in the 32% tax bracket is comparing a municipal bond yielding 4% to taxable bonds. What is the tax-equivalent yield of the municipal bond?","choices":{"A":"2.72%","B":"4.00%","C":"5.28%","D":"5.88%"},"answer":"D","explanation":"Tax-equivalent yield = Muni yield / (1 - tax rate) = 4% / (1 - 0.32) = 4% / 0.68 = 5.88%. This means the investor would need a taxable bond yielding 5.88% to equal the 4% municipal bond on an after-tax basis.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-028","section":"2 - Products & Risks","stem":"Commercial paper has a maximum maturity of:","choices":{"A":"90 days","B":"180 days","C":"270 days","D":"365 days"},"answer":"C","explanation":"Commercial paper has a maximum maturity of 270 days. This limit allows issuers to avoid SEC registration requirements. If maturity exceeded 270 days, the issuer would need to register the securities with the SEC.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-029","section":"2 - Products & Risks","stem":"Which money market instrument is primarily used to facilitate international trade?","choices":{"A":"Treasury bills","B":"Commercial paper","C":"Banker's acceptances","D":"Negotiable CDs"},"answer":"C","explanation":"Banker's acceptances (BAs) are primarily used in international trade. They are time drafts guaranteed by a bank, allowing exporters to receive payment assurance and importers to defer payment. BAs can be sold in the secondary market.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-030","section":"2 - Products & Risks","stem":"In a repurchase agreement (repo), the borrower:","choices":{"A":"Sells securities and agrees to repurchase them at a higher price","B":"Buys securities and agrees to sell them at a lower price","C":"Deposits cash and receives interest at maturity","D":"Issues unsecured promissory notes"},"answer":"A","explanation":"In a repo, the borrower sells securities to a lender and agrees to repurchase them at a higher price on a specified date. The difference between the sale price and repurchase price represents the interest earned by the lender.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-031","section":"2 - Products & Risks","stem":"A call option is \"in the money\" when:","choices":{"A":"The market price is below the strike price","B":"The market price equals the strike price","C":"The market price is above the strike price","D":"The option has expired"},"answer":"C","explanation":"A call option is in the money when the market price of the underlying stock is above the strike price. This means the holder could exercise the option to buy at the lower strike price and immediately sell at the higher market price for a profit.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-033","section":"2 - Products & Risks","stem":"A stock is trading at $48. A call option with a strike price of $45 has a premium of $5. What is the time value of this option?","choices":{"A":"$0","B":"$2","C":"$3","D":"$5"},"answer":"B","explanation":"Intrinsic value = Market price - Strike price = $48 - $45 = $3. Time value = Premium - Intrinsic value = $5 - $3 = $2. The $5 premium consists of $3 intrinsic value and $2 time value.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-034","section":"2 - Products & Risks","stem":"An investor owns 100 shares of stock and buys a put option on those shares. This strategy is called a:","choices":{"A":"Covered call","B":"Naked put","C":"Protective put","D":"Collar"},"answer":"C","explanation":"A protective put (also called a married put) involves owning stock and buying a put option on that stock. The put provides downside protection by giving the investor the right to sell shares at the strike price, regardless of how far the stock falls.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-035","section":"2 - Products & Risks","stem":"A covered call strategy is MOST appropriate for an investor who:","choices":{"A":"Expects the stock to rise dramatically","B":"Expects the stock to decline significantly","C":"Has a neutral to slightly bullish outlook","D":"Wants unlimited upside potential"},"answer":"C","explanation":"Covered call writing is best for investors with a neutral to slightly bullish outlook. The premium income provides some downside cushion, but the strategy caps gains if the stock rises above the strike price. It is not ideal for strongly bullish investors.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-036","section":"2 - Products & Risks","stem":"In a collar strategy, the investor:","choices":{"A":"Buys both a call and a put","B":"Sells both a call and a put","C":"Buys a put and sells a call","D":"Buys a call and sells a put"},"answer":"C","explanation":"A collar involves owning stock, buying a protective put (for downside protection), and selling a covered call (to offset the put cost). The put creates a floor, and the call creates a ceiling for the stock position.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-037","section":"2 - Products & Risks","stem":"An investor wants to purchase shares of an open-end mutual fund. At what price will the investor buy?","choices":{"A":"The market price on the exchange","B":"The net asset value (NAV)","C":"A price negotiated with the seller","D":"The previous day closing price"},"answer":"B","explanation":"Open-end mutual fund shares are always bought and sold at the net asset value (NAV), calculated at the end of each trading day. Unlike closed-end funds or stocks, mutual fund shares do not trade on exchanges at fluctuating market prices.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-038","section":"2 - Products & Risks","stem":"Which type of fund can trade at a discount to its net asset value?","choices":{"A":"Open-end mutual fund","B":"Money market fund","C":"Closed-end fund","D":"All mutual funds can trade at a discount"},"answer":"C","explanation":"Only closed-end funds can trade at a discount (or premium) to NAV because they trade on exchanges at market prices determined by supply and demand. Open-end mutual funds always transact at NAV.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-039","section":"2 - Products & Risks","stem":"Under the 75-5-10 diversification rule, a diversified mutual fund may invest no more than what percentage of its assets in any single company?","choices":{"A":"5%","B":"10%","C":"25%","D":"75%"},"answer":"A","explanation":"The 75-5-10 rule requires that no more than 5% of a diversified fund's assets be invested in any single company. Additionally, 75% of assets must be diversified, and the fund cannot own more than 10% of any company's voting stock.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-040","section":"2 - Products & Risks","stem":"Which mutual fund share class typically has the highest ongoing 12b-1 fees?","choices":{"A":"Class A","B":"Class B or C","C":"No-load shares","D":"All share classes have the same 12b-1 fees"},"answer":"B","explanation":"Class B and C shares typically have higher 12b-1 fees (up to 1%) because they do not charge upfront sales loads. Class A shares charge a front-end load but have lower ongoing 12b-1 fees (usually 0.25% or less).","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-041","section":"2 - Products & Risks","stem":"Which of the following is included in a mutual fund expense ratio?","choices":{"A":"Front-end sales load","B":"Back-end sales load (CDSC)","C":"12b-1 fees","D":"Brokerage commissions on trades"},"answer":"C","explanation":"The expense ratio includes ongoing fees: management fees, 12b-1 fees, and administrative expenses. Sales loads (front and back-end) and trading costs are not included in the expense ratio.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-042","section":"2 - Products & Risks","stem":"An investor wants to invest $45,000 in a mutual fund. The fund has a breakpoint at $50,000 that reduces the sales charge from 5% to 4%. A representative who recommends investing only $45,000 to earn the higher commission has committed:","choices":{"A":"A suitable recommendation","B":"A breakpoint sale violation","C":"A forward pricing violation","D":"No violation—breakpoints are optional"},"answer":"B","explanation":"A breakpoint sale is a prohibited practice where a representative intentionally keeps an investment below a breakpoint to earn a higher commission. The representative should inform the customer about the breakpoint and the benefit of investing slightly more to qualify for the lower sales charge.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-043","section":"3 - Trading, Accounts & Prohibited","stem":"An investor places an order to purchase an ETF at 2:00 PM. When will the order execute and at what price?","choices":{"A":"At 4:00 PM at the NAV","B":"Immediately at the current market price","C":"The next business day at opening price","D":"At the closing price of the underlying securities"},"answer":"B","explanation":"ETFs trade on exchanges throughout the day like stocks. Orders execute immediately at the current market price, not at end-of-day NAV like mutual funds. This intraday trading is a key distinction between ETFs and mutual funds.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-044","section":"2 - Products & Risks","stem":"ETFs are generally more tax-efficient than mutual funds primarily because of:","choices":{"A":"Lower expense ratios","B":"The in-kind creation and redemption process","C":"Intraday trading capability","D":"Daily disclosure of holdings"},"answer":"B","explanation":"ETFs are more tax-efficient primarily due to the in-kind creation/redemption process. When authorized participants redeem shares, they receive underlying securities rather than cash, avoiding the need to sell securities and trigger capital gains that would be distributed to shareholders.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-045","section":"2 - Products & Risks","stem":"Which of the following can an investor do with ETFs but NOT with open-end mutual funds?","choices":{"A":"Receive dividends","B":"Achieve diversification","C":"Place limit orders","D":"Invest in index funds"},"answer":"C","explanation":"Investors can place limit orders for ETFs because they trade on exchanges at real-time prices. Mutual fund orders can only be market orders executed at end-of-day NAV. Both ETFs and mutual funds offer dividends, diversification, and index investing options.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-046","section":"3 - Trading, Accounts & Prohibited","stem":"Which of the following is a characteristic of a Unit Investment Trust (UIT)?","choices":{"A":"Actively managed portfolio that changes daily","B":"Fixed portfolio with a predetermined termination date","C":"Perpetual existence with no termination date","D":"Managed by a board of directors"},"answer":"B","explanation":"UITs hold a fixed portfolio of securities that does not change after creation and have a predetermined termination date when the trust dissolves. Unlike mutual funds, UITs are not actively managed and have no board of directors or investment adviser.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-047","section":"2 - Products & Risks","stem":"To qualify as a REIT, a company must distribute what percentage of its taxable income to shareholders?","choices":{"A":"50%","B":"75%","C":"90%","D":"100%"},"answer":"C","explanation":"REITs must distribute at least 90% of their taxable income to shareholders annually to maintain their special tax status. This requirement is why REITs typically offer high dividend yields.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-048","section":"2 - Products & Risks","stem":"Dividends from REITs are generally taxed as:","choices":{"A":"Capital gains","B":"Qualified dividends at reduced rates","C":"Tax-exempt income","D":"Ordinary income"},"answer":"D","explanation":"REIT dividends are generally taxed as ordinary income, not at the lower qualified dividend tax rate that applies to most corporate stock dividends. This is an important distinction for tax planning purposes.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-049","section":"2 - Products & Risks","stem":"A key difference between DPPs and REITs is that DPPs:","choices":{"A":"Are publicly traded on exchanges","B":"Cannot pass through income to investors","C":"Can pass through losses to investors","D":"Must distribute 90% of income"},"answer":"C","explanation":"DPPs can pass through both income AND losses to investors, while REITs can only pass through income (not losses). This flow-through of losses is a key tax benefit that distinguishes DPPs from other investment vehicles.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-050","section":"2 - Products & Risks","stem":"In a limited partnership DPP, which partner has unlimited liability?","choices":{"A":"Limited partners only","B":"General partner only","C":"Both general and limited partners","D":"Neither partner has unlimited liability"},"answer":"B","explanation":"The general partner (GP) has unlimited personal liability for partnership obligations. Limited partners have liability limited to their investment amount, as long as they do not participate in management decisions.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-051","section":"2 - Products & Risks","stem":"Losses from a DPP can be used to offset which type of income?","choices":{"A":"Wages and salary","B":"Portfolio income (dividends, interest)","C":"Passive income","D":"All types of income"},"answer":"C","explanation":"Under IRS passive activity rules, losses from DPPs can only offset passive income (such as rental income or income from other DPPs). DPP losses cannot be used to offset wages, salary, or portfolio income like dividends and interest.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-052","section":"2 - Products & Risks","stem":"Which of the following is an example of systematic risk?","choices":{"A":"A company CEO resigns unexpectedly","B":"A product recall damages a company reputation","C":"The Federal Reserve raises interest rates","D":"A company loses a major customer"},"answer":"C","explanation":"Federal Reserve interest rate changes affect the entire market and economy, making it systematic (market) risk. The other options are company-specific events that represent unsystematic risk, which can be reduced through diversification.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-053","section":"2 - Products & Risks","stem":"A stock with a beta of 1.5 would be expected to:","choices":{"A":"Move 50% less than the market","B":"Move exactly with the market","C":"Move 50% more than the market","D":"Move in the opposite direction of the market"},"answer":"C","explanation":"A beta of 1.5 means the stock is 50% more volatile than the market. If the market moves 10%, this stock would be expected to move 15% (1.5 x 10%) in the same direction.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-054","section":"2 - Products & Risks","stem":"Which statement about systematic risk is TRUE?","choices":{"A":"It can be eliminated through diversification","B":"It only affects bonds, not stocks","C":"It is measured by beta","D":"It is also called business risk"},"answer":"C","explanation":"Systematic risk is measured by beta, which indicates a security volatility relative to the overall market. Systematic risk cannot be eliminated through diversification (that is unsystematic risk), affects all securities including stocks, and is also called market risk (not business risk).","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-055","section":"2 - Products & Risks","stem":"Which of the following is an example of unsystematic risk?","choices":{"A":"Rising inflation nationwide","B":"A recession affecting all industries","C":"A product recall by a single company","D":"The Federal Reserve changing interest rates"},"answer":"C","explanation":"A product recall affects only one company, making it unsystematic (company-specific) risk. Inflation, recession, and Fed interest rate changes affect the entire market and are systematic risks.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-056","section":"2 - Products & Risks","stem":"How many stocks are generally needed to eliminate most unsystematic risk?","choices":{"A":"5 stocks","B":"10 stocks","C":"20-30 stocks","D":"100+ stocks"},"answer":"C","explanation":"Research shows that 20-30 properly diversified stocks (across different sectors) can eliminate most unsystematic risk from a portfolio. Beyond this number, additional diversification provides diminishing benefits.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-057","section":"2 - Products & Risks","stem":"Financial risk is associated with:","choices":{"A":"Changes in interest rates affecting the entire market","B":"A company use of debt and ability to meet obligations","C":"The overall stock market declining","D":"Inflation eroding purchasing power"},"answer":"B","explanation":"Financial risk is a type of unsystematic risk related to how a company finances its operations, particularly its debt levels and ability to meet interest payments. It is company-specific, not a market-wide factor.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-058","section":"2 - Products & Risks","stem":"Which strategy is MOST effective for reducing unsystematic risk?","choices":{"A":"Hedging with put options","B":"Diversification across many securities","C":"Dollar-cost averaging","D":"Increasing cash holdings"},"answer":"B","explanation":"Diversification across many securities is the most effective way to reduce unsystematic (company-specific) risk. By holding 20-30 different stocks across various sectors, the impact of any single company problems is minimized.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-059","section":"2 - Products & Risks","stem":"Dollar-cost averaging helps reduce:","choices":{"A":"Interest rate risk","B":"Credit risk","C":"Timing risk","D":"Currency risk"},"answer":"C","explanation":"Dollar-cost averaging reduces timing risk by investing fixed amounts at regular intervals. This approach eliminates the need to time the market and results in buying more shares when prices are low and fewer when prices are high.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch2-060","section":"2 - Products & Risks","stem":"An investor rebalances their portfolio from 70% stocks/30% bonds back to their target of 60%/40%. This strategy helps to:","choices":{"A":"Maximize returns in all market conditions","B":"Eliminate systematic risk","C":"Maintain the intended risk level","D":"Avoid paying taxes on gains"},"answer":"C","explanation":"Rebalancing maintains the intended risk level of a portfolio. When stocks outperform and grow to 70% of the portfolio, the risk has increased beyond the target. Selling stocks and buying bonds brings the portfolio back to the desired 60/40 allocation and risk profile.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch3-001","section":"2 - Products & Risks","stem":"An investor owns 100 shares of XYZ stock currently trading at $50. To protect against a decline in price, the investor should place a:","choices":{"A":"Buy stop order below $50","B":"Sell stop order below $50","C":"Buy limit order above $50","D":"Sell limit order below $50"},"answer":"B","explanation":"A sell stop order placed below the current market price protects a long position. If the stock declines to the stop price, the order triggers and sells the shares to limit losses. Remember \"BLiSS\" - Buy Limit and Sell Stop go below the market.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch3-002","section":"3 - Trading, Accounts & Prohibited","stem":"Which order type guarantees execution but NOT price?","choices":{"A":"Limit order","B":"Stop-limit order","C":"Market order","D":"Good-til-canceled order"},"answer":"C","explanation":"A market order guarantees execution at the next available price but does not guarantee a specific price. Limit orders guarantee price but not execution. GTC refers to order duration, not order type.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch3-003","section":"3 - Trading, Accounts & Prohibited","stem":"Using the SLoBS and BLiSS memory trick, which orders are placed ABOVE the current market price?","choices":{"A":"Buy limit and sell stop","B":"Sell limit and buy stop","C":"Buy limit and buy stop","D":"Sell limit and sell stop"},"answer":"B","explanation":"SLoBS stands for \"Sell Limit or Buy Stop\" - these orders are placed ABOVE the market. A sell limit is placed above because you want to sell at a higher price. A buy stop is placed above to protect a short position if prices rise.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch3-004","section":"3 - Trading, Accounts & Prohibited","stem":"Under current SEC rules, what is the regular way settlement for corporate stocks?","choices":{"A":"Same day (T+0)","B":"T+1 (one business day)","C":"T+2 (two business days)","D":"T+3 (three business days)"},"answer":"B","explanation":"As of May 28, 2024, regular way settlement for most securities including corporate stocks is T+1 (one business day after trade date). The SEC shortened the cycle from T+2 to reduce market risk and improve efficiency.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch3-005","section":"4 - Regulatory Framework","stem":"Under T+1 settlement, when is the ex-dividend date relative to the record date?","choices":{"A":"Two business days before the record date","B":"One business day before the record date","C":"The same day as the record date","D":"One business day after the record date"},"answer":"C","explanation":"With T+1 settlement, the ex-dividend date is the SAME day as the record date. To receive the dividend, an investor must purchase the stock at least one business day before the record date so the trade settles by the record date.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch3-006","section":"4 - Regulatory Framework","stem":"According to Regulation T, by when must a customer in a cash account pay for a securities purchase?","choices":{"A":"Trade date (T)","B":"Settlement date (T+1)","C":"Two business days after settlement (T+3)","D":"Five business days after trade date (T+5)"},"answer":"C","explanation":"Regulation T requires customer payment within 2 business days after settlement (S+2). With T+1 settlement, this means payment is due by T+3. In a cash account, the customer must pay 100% of the purchase price.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch3-007","section":"2 - Products & Risks","stem":"A stock is quoted at $45.50 bid, $45.75 ask. If a customer wants to buy 100 shares, what price will they pay?","choices":{"A":"$45.50 (the bid)","B":"$45.625 (the midpoint)","C":"$45.75 (the ask)","D":"$45.25 (below the bid)"},"answer":"C","explanation":"When buying, customers pay the ask (offer) price. The ask of $45.75 is the price at which the market maker is willing to sell. The bid of $45.50 is what the market maker would pay to buy from a customer.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch3-008","section":"2 - Products & Risks","stem":"A narrow bid-ask spread typically indicates:","choices":{"A":"Low trading volume and illiquidity","B":"High trading volume and liquidity","C":"High price volatility","D":"Limited market maker participation"},"answer":"B","explanation":"A narrow (tight) spread indicates high liquidity and an efficient market. When trading volume is high and many market makers compete, spreads narrow. Wide spreads typically indicate less liquid securities with fewer market makers.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch3-009","section":"2 - Products & Risks","stem":"What type of market is Nasdaq considered?","choices":{"A":"Auction market","B":"Dealer (negotiated) market","C":"Physical exchange market","D":"Single market maker market"},"answer":"B","explanation":"Nasdaq is a dealer (negotiated) market where multiple market makers compete to trade securities. Each market maker posts their own bid-ask quotes. The NYSE, in contrast, is an auction market with a single Designated Market Maker (DMM) per stock.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch3-010","section":"4 - Regulatory Framework","stem":"Under Regulation T, what is the minimum initial margin requirement for purchasing securities in a margin account?","choices":{"A":"25%","B":"30%","C":"50%","D":"100%"},"answer":"C","explanation":"Regulation T requires a 50% initial margin for most securities purchases. This means the customer must deposit at least 50% of the purchase price. The 25% figure is the FINRA minimum maintenance margin for long positions.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch3-011","section":"3 - Trading, Accounts & Prohibited","stem":"In a Joint Tenants with Rights of Survivorship (JTWROS) account, what happens to the assets when one owner dies?","choices":{"A":"Assets go to the deceased owners estate","B":"Assets go to the surviving owner(s)","C":"Assets are frozen until probate is complete","D":"Assets are divided between estate and survivors"},"answer":"B","explanation":"In a JTWROS account, when one owner dies, the assets automatically pass to the surviving owner(s), avoiding probate. This differs from Tenants in Common (TIC), where the deceased owners share goes to their estate.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch3-012","section":"3 - Trading, Accounts & Prohibited","stem":"Which of the following is TRUE about UGMA/UTMA custodial accounts?","choices":{"A":"Margin trading is permitted with custodian approval","B":"The gift to the minor can be revoked if needed","C":"The account can have multiple custodians","D":"Gifts are irrevocable and margin trading is prohibited"},"answer":"D","explanation":"UGMA/UTMA custodial accounts have specific restrictions: gifts are irrevocable (cannot be taken back), margin trading is not permitted, and there can only be one custodian and one minor per account.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch3-013","section":"4 - Regulatory Framework","stem":"Under FINRA Rule 4512, which of the following is the firm required to make a reasonable effort to obtain for non-institutional customer accounts?","choices":{"A":"Power of attorney authorization","B":"Trusted Contact Person information","C":"Annual financial statements","D":"Investment adviser registration"},"answer":"B","explanation":"FINRA Rule 4512 requires firms to make a reasonable effort to obtain the name and contact information of a Trusted Contact Person (TCP) age 18 or older for non-institutional accounts. The TCP helps protect investors, especially seniors, from financial exploitation.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch3-014","section":"4 - Regulatory Framework","stem":"How long must a broker-dealer maintain customer account records after the account is closed?","choices":{"A":"3 years","B":"4 years","C":"6 years","D":"10 years"},"answer":"C","explanation":"FINRA and SEC rules require broker-dealers to maintain customer account records for 6 years after the account is closed. This includes the original or final account information and any updates made while the account was active.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch3-015","section":"3 - Trading, Accounts & Prohibited","stem":"The Trusted Contact Person (TCP) for an account:","choices":{"A":"Has authority to make trades in the account","B":"Must be related to the account holder","C":"Is contacted to help protect the customer from exploitation","D":"Must be a registered representative"},"answer":"C","explanation":"The TCP is a resource the firm may contact when there are concerns about the customer, such as possible financial exploitation or diminished capacity. The TCP does NOT have authority to trade and does not need to be related to the customer or be a registered representative.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch3-016","section":"3 - Trading, Accounts & Prohibited","stem":"What is the primary difference between a Traditional IRA and a Roth IRA?","choices":{"A":"Traditional IRAs have higher contribution limits","B":"Roth IRAs require minimum distributions at age 73","C":"Traditional IRA contributions may be tax-deductible while Roth contributions are made after-tax","D":"Only Roth IRAs allow catch-up contributions"},"answer":"C","explanation":"Traditional IRA contributions may be tax-deductible (depending on income and workplace plan status), with withdrawals taxed as ordinary income. Roth IRA contributions are made with after-tax dollars, but qualified withdrawals are tax-free. Both have the same contribution limits.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch3-017","section":"3 - Trading, Accounts & Prohibited","stem":"Under current law, at what age must an individual begin taking Required Minimum Distributions (RMDs) from a Traditional IRA?","choices":{"A":"59 1/2","B":"70 1/2","C":"72","D":"73"},"answer":"D","explanation":"Under the SECURE Act 2.0, Required Minimum Distributions (RMDs) must begin at age 73. This was increased from age 72 (SECURE Act) and 70 1/2 (pre-SECURE Act). Roth IRAs do not require RMDs during the owners lifetime.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch3-018","section":"3 - Trading, Accounts & Prohibited","stem":"An employee receives a distribution from their 401(k) and wants to roll it into an IRA. How many days do they have to complete the rollover to avoid taxes and penalties?","choices":{"A":"30 days","B":"60 days","C":"90 days","D":"120 days"},"answer":"B","explanation":"The IRS allows 60 days to complete an indirect rollover. If the funds are not deposited into another qualified retirement account within 60 days, the distribution is taxable and may be subject to a 10% early withdrawal penalty if under age 59 1/2.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch3-019","section":"3 - Trading, Accounts & Prohibited","stem":"What is the annual contribution limit for a Coverdell Education Savings Account?","choices":{"A":"$2,000 per beneficiary","B":"$7,000 per beneficiary","C":"$10,000 per beneficiary","D":"No annual limit"},"answer":"A","explanation":"Coverdell ESAs have an annual contribution limit of $2,000 per beneficiary. This is much lower than 529 plans, which have no federal annual limit. However, Coverdell ESAs offer more flexibility for K-12 expenses.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch3-020","section":"3 - Trading, Accounts & Prohibited","stem":"Which statement is TRUE regarding 529 plans?","choices":{"A":"Contributors must meet income limits to contribute","B":"K-12 tuition expenses are limited to $10,000 per year","C":"Funds must be used before the beneficiary reaches age 30","D":"Only parents can contribute to their childs account"},"answer":"B","explanation":"529 plans limit K-12 tuition expenses to $10,000 per year. Unlike Coverdell ESAs, 529 plans have no income limits for contributors, no age restrictions, and anyone can contribute to an account.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch3-021","section":"3 - Trading, Accounts & Prohibited","stem":"If a 529 plan beneficiary receives a full scholarship, what happens to the funds in the account?","choices":{"A":"Funds must remain in the account until the beneficiary has qualified expenses","B":"Funds can be withdrawn up to the scholarship amount without the 10% penalty","C":"All funds become taxable immediately","D":"Funds must be transferred to another family member"},"answer":"B","explanation":"If the beneficiary receives a scholarship, up to the scholarship amount can be withdrawn without the 10% penalty. However, the earnings portion would still be subject to income tax. This is one of several exceptions to the early withdrawal penalty.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch3-022","section":"2 - Products & Risks","stem":"A Currency Transaction Report (CTR) must be filed for cash transactions exceeding:","choices":{"A":"$3,000","B":"$5,000","C":"$10,000","D":"$25,000"},"answer":"C","explanation":"A CTR must be filed with FinCEN for any cash transaction exceeding $10,000, whether its a deposit, withdrawal, or exchange. Multiple cash transactions by the same person on the same day must be aggregated.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch3-023","section":"2 - Products & Risks","stem":"A customer makes several cash deposits of $9,500 over consecutive days to avoid the CTR reporting threshold. This practice is known as:","choices":{"A":"Layering","B":"Integration","C":"Structuring","D":"Placement"},"answer":"C","explanation":"Structuring (also called \"smurfing\") is intentionally breaking up transactions to avoid the $10,000 CTR reporting threshold. This is illegal and should be reported via a Suspicious Activity Report (SAR), even though individual transactions are below the threshold.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch3-024","section":"4 - Regulatory Framework","stem":"Under AML rules, a broker-dealer representative who files a SAR:","choices":{"A":"Must notify the customer within 30 days","B":"Is protected by safe harbor from liability","C":"Can be held liable if the suspicion proves unfounded","D":"Must obtain customer consent before filing"},"answer":"B","explanation":"Safe harbor protection shields financial institutions and employees who file SARs in good faith from civil and criminal liability. It is actually prohibited to notify (\"tip off\") the customer about the SAR filing, and customer consent is never required.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch3-025","section":"3 - Trading, Accounts & Prohibited","stem":"A trader places multiple large sell orders with no intention of executing them, then buys shares at a lower price and cancels the sell orders. This practice is known as:","choices":{"A":"Wash trading","B":"Spoofing or layering","C":"Front running","D":"Marking the close"},"answer":"B","explanation":"Spoofing and layering involve placing non-bona fide orders to manipulate other traders behavior, then canceling before execution. Placing multiple orders at different price levels to move the market is specifically called layering.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch3-026","section":"4 - Regulatory Framework","stem":"A broker-dealer representative learns a large institutional client is about to place a major buy order. Before entering the clients order, the representative buys shares for their personal account. This is an example of:","choices":{"A":"Churning","B":"Painting the tape","C":"Front running","D":"Pump and dump"},"answer":"C","explanation":"Front running is trading ahead of a known customer order to profit from the expected price movement. The representative is using confidential information about the customers pending order to benefit personally, which is a breach of fiduciary duty.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch3-027","section":"2 - Products & Risks","stem":"Which of the following BEST describes a \"pump and dump\" scheme?","choices":{"A":"Excessive trading to generate commissions","B":"Placing and canceling orders to manipulate prices","C":"Spreading false positive information about a stock, then selling at inflated prices","D":"Refusing to honor quoted prices"},"answer":"C","explanation":"Pump and dump schemes involve artificially inflating (\"pumping\") a stocks price through false or misleading positive statements, then selling (\"dumping\") shares at the inflated price. Innocent investors are left holding devalued stock when the truth emerges.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch3-028","section":"4 - Regulatory Framework","stem":"Which of the following BEST describes \"material\" information for purposes of insider trading rules?","choices":{"A":"Any information about a company","B":"Information a reasonable investor would consider important in making an investment decision","C":"Information that is publicly available","D":"Information that has been verified by the SEC"},"answer":"B","explanation":"Information is considered \"material\" if a reasonable investor would consider it important when making an investment decision. This includes information about earnings, mergers, major contracts, or other significant events that could affect the stock price.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch3-029","section":"2 - Products & Risks","stem":"A corporate executive learns that their company will announce better-than-expected earnings tomorrow. The executive immediately buys shares. This is an example of:","choices":{"A":"Front running","B":"Market manipulation","C":"Insider trading","D":"Churning"},"answer":"C","explanation":"This is insider trading - the executive traded on material nonpublic information (MNPI). The pending earnings announcement is material (would affect investment decisions) and nonpublic (not yet announced). Trading while aware of this information violates SEC Rule 10b-5.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch3-030","section":"2 - Products & Risks","stem":"What is the purpose of a Rule 10b5-1 trading plan?","choices":{"A":"To allow insiders to trade during blackout periods","B":"To provide an affirmative defense against insider trading liability when trades are pre-planned","C":"To eliminate the requirement to report insider transactions","D":"To allow tipping of material nonpublic information"},"answer":"B","explanation":"Rule 10b5-1 trading plans provide an affirmative defense against insider trading liability. If an insider establishes a written trading plan when they do not possess MNPI, and the plan specifies the trades in advance, they can execute the trades even if they later acquire MNPI.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch3-031","section":"4 - Regulatory Framework","stem":"Under SEC Rule 15c3-3, broker-dealers are required to:","choices":{"A":"Trade only in securities approved by the SEC","B":"Keep customer securities and cash separate from the firms proprietary assets","C":"Guarantee customer accounts against losses","D":"Provide investment advice to all customers"},"answer":"B","explanation":"SEC Rule 15c3-3 (Customer Protection Rule) requires broker-dealers to maintain possession or control of customer securities and keep customer cash in a separate reserve account. This protects customer assets if the firm experiences financial difficulties.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch3-032","section":"4 - Regulatory Framework","stem":"FINRA Rule 2111 (Suitability) requires broker-dealers to consider all of the following EXCEPT:","choices":{"A":"The customers investment objectives","B":"The customers risk tolerance","C":"The brokers compensation structure","D":"The customers financial situation"},"answer":"C","explanation":"Suitability analysis focuses on customer factors: investment objectives, risk tolerance, financial situation, time horizon, liquidity needs, and tax status. While conflicts of interest (including compensation) must be disclosed under Reg BI, they are not part of the suitability analysis itself.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch3-033","section":"4 - Regulatory Framework","stem":"Under Regulation Best Interest (Reg BI), broker-dealers must:","choices":{"A":"Guarantee the best possible returns for customers","B":"Act in the best interest of the customer when making recommendations","C":"Only recommend proprietary products","D":"Charge the lowest fees in the industry"},"answer":"B","explanation":"Regulation Best Interest requires broker-dealers to act in the best interest of the retail customer when making recommendations. This includes a care obligation (understanding risks, considering customer profile), conflict mitigation, and proper disclosure through Form CRS.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch4-001","section":"2 - Products & Risks","stem":"How long are SIE exam results valid?","choices":{"A":"2 years","B":"4 years","C":"6 years","D":"Indefinitely"},"answer":"B","explanation":"SIE exam results are valid for 4 years. During this time, a candidate can become associated with a firm and take a representative-level exam (like Series 6 or 7) to complete registration. After 4 years, the SIE must be retaken.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch4-002","section":"2 - Products & Risks","stem":"Which form is filed when a registered representative leaves their employing firm?","choices":{"A":"Form U4","B":"Form U5","C":"Form BD","D":"Form ADV"},"answer":"B","explanation":"Form U5 (Uniform Termination Notice) is filed when a registered representative leaves a firm, whether voluntarily or involuntarily. Form U4 is for registration, Form BD is for broker-dealer registration, and Form ADV is for investment advisers.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch4-003","section":"2 - Products & Risks","stem":"If a registered representative leaves the securities industry for 3 years and wants to return, they must:","choices":{"A":"Simply re-register with a new firm","B":"Retake only the SIE exam","C":"Retake the representative-level exam but not the SIE","D":"Retake both the SIE and representative-level exam"},"answer":"C","explanation":"If a person leaves the industry for 2-4 years, they must retake the representative-level exam (like Series 7) but not the SIE, which remains valid for 4 years. After 4 years out of the industry, both the SIE and representative exam must be retaken.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch4-004","section":"4 - Regulatory Framework","stem":"How often must registered persons complete the Regulatory Element of continuing education?","choices":{"A":"Every 2 years","B":"Every 3 years","C":"Annually by December 31","D":"Within 120 days of registration anniversary"},"answer":"C","explanation":"Beginning January 1, 2023, FINRA requires registered persons to complete the Regulatory Element annually by December 31. Failure to complete by the deadline results in CE Inactive status.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch4-005","section":"2 - Products & Risks","stem":"Which element of continuing education is developed and administered by individual member firms?","choices":{"A":"Regulatory Element","B":"Firm Element","C":"Both elements","D":"Neither - FINRA administers both"},"answer":"B","explanation":"The Firm Element is developed and administered by each member firm based on their specific business needs and an annual needs analysis. The Regulatory Element is administered by FINRA and covers industry-wide regulatory and compliance topics.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch4-006","section":"4 - Regulatory Framework","stem":"What happens to a registered representative who fails to complete the Regulatory Element by the December 31 deadline?","choices":{"A":"They receive a warning but can continue working","B":"They are designated CE Inactive and cannot perform registered activities","C":"They must pay a fine but registration continues","D":"Their registration is immediately terminated"},"answer":"B","explanation":"Registered persons who fail to complete the Regulatory Element by December 31 are designated as CE Inactive by FINRA. While CE Inactive, they cannot engage in any activities requiring registration. If still inactive after 120 days, registration may be suspended.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch4-007","section":"4 - Regulatory Framework","stem":"Under FINRA Rule 3270, before engaging in an outside business activity, a registered representative must:","choices":{"A":"Complete the activity and report it within 30 days","B":"Provide prior written notice to their firm","C":"File a disclosure with FINRA directly","D":"Obtain customer consent"},"answer":"B","explanation":"FINRA Rule 3270 requires registered representatives to provide prior written notice to their firm before engaging in any outside business activity. The firm then decides whether to approve, restrict, or deny the activity.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch4-008","section":"2 - Products & Risks","stem":"A registered representative sells a security to a customer that is not offered by their employing firm, without the firm's knowledge. This is known as:","choices":{"A":"Front running","B":"Churning","C":"Selling away","D":"Marking the close"},"answer":"C","explanation":"Selling away is a private securities transaction (PST) conducted without proper firm notice and approval. Under FINRA Rule 3280, all PSTs require prior written notice, and if compensation is involved, the firm must approve and supervise the transaction.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch4-009","section":"2 - Products & Risks","stem":"What is the maximum annual value of gifts a registered representative can give to a customer?","choices":{"A":"$50","B":"$100","C":"$250","D":"$500"},"answer":"B","explanation":"Under FINRA Rule 3220, registered representatives and member firms are limited to giving gifts valued at no more than $100 per person per year. This includes the aggregate value from all representatives at a firm to a single recipient.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch4-010","section":"4 - Regulatory Framework","stem":"Under FINRA Rule 2210, an email sent to 20 retail customers within a 30-day period would be classified as:","choices":{"A":"Retail communication","B":"Correspondence","C":"Institutional communication","D":"Advertising"},"answer":"B","explanation":"Correspondence is defined as written communication to 25 or fewer retail investors within a 30-day period. Since the email was sent to only 20 retail customers, it qualifies as correspondence, which has lighter regulatory requirements than retail communications.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch4-011","section":"4 - Regulatory Framework","stem":"Which type of communication generally requires principal pre-approval before use?","choices":{"A":"Correspondence","B":"Retail communications","C":"Institutional communications","D":"All of the above"},"answer":"B","explanation":"Retail communications generally require principal (supervisor) pre-approval before use because they reach a larger audience (more than 25 retail investors). Correspondence and institutional communications do not require pre-approval, though they are subject to supervision and review.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-ch4-012","section":"4 - Regulatory Framework","stem":"A new FINRA member firm must file with FINRA:","choices":{"A":"Only advertisements","B":"Only communications about options","C":"All retail communications during its first year","D":"Only correspondence"},"answer":"C","explanation":"New FINRA member firms (those in their first year of membership) are required to file all retail communications with FINRA's Advertising Regulation Department. This heightened requirement helps FINRA monitor new firms' communications for compliance.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch1-001","section":"4 - Regulatory Framework","stem":"Which federal law primarily regulates mutual funds and other investment companies?","choices":{"A":"Securities Act of 1933","B":"Securities Exchange Act of 1934","C":"Investment Company Act of 1940","D":"Investment Advisers Act of 1940"},"answer":"C","explanation":"The Investment Company Act of 1940 specifically regulates investment companies, including mutual funds, closed-end funds, and UITs. The '33 Act covers new issuances (prospectuses), the '34 Act covers secondary market trading, and the Advisers Act covers investment advisers.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch1-002","section":"4 - Regulatory Framework","stem":"The Securities Act of 1933 primarily regulates which market?","choices":{"A":"The secondary market (trading)","B":"The primary market (new issuances)","C":"The over-the-counter market","D":"The municipal bond market"},"answer":"B","explanation":"The Securities Act of 1933 regulates the primary market — the initial sale of securities to the public. It requires registration and prospectus delivery for new offerings. The Securities Exchange Act of 1934 regulates the secondary market where existing securities are traded.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch1-003","section":"4 - Regulatory Framework","stem":"What is FINRA's role in the securities industry?","choices":{"A":"A federal government agency that writes securities laws","B":"A self-regulatory organization that regulates broker-dealers","C":"A state agency that enforces Blue Sky Laws","D":"An exchange where securities are traded"},"answer":"B","explanation":"FINRA (Financial Industry Regulatory Authority) is a self-regulatory organization (SRO) that regulates member broker-dealers and their registered representatives. It is not a government agency — the SEC is the federal regulator that oversees FINRA.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch1-004","section":"4 - Regulatory Framework","stem":"Within how many days must a registered representative update Form U4 after a material change?","choices":{"A":"10 days","B":"30 days","C":"45 days","D":"60 days"},"answer":"B","explanation":"Form U4 must be updated within 30 days of any material change, such as a change in address, new outside business activity, or a disclosure event. Failure to update timely can result in regulatory action.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch1-005","section":"4 - Regulatory Framework","stem":"What system do broker-dealers use to register firms and individuals with FINRA?","choices":{"A":"Electronic Data Gathering System (EDGAR)","B":"Central Registration Depository (CRD)","C":"Automated Customer Account Transfer Service (ACATS)","D":"Securities Information Center (SIC)"},"answer":"B","explanation":"The Central Registration Depository (CRD) is the securities industry's centralized licensing and registration system. Firms file Form BD and representatives file Form U4 through the CRD. EDGAR is the SEC's system for company filings.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch1-006","section":"4 - Regulatory Framework","stem":"FINRA Rule 2111 (Suitability) requires which three components?","choices":{"A":"Registration, supervision, and compliance","B":"Disclosure, care, and conflict management","C":"Reasonable-basis, customer-specific, and quantitative suitability","D":"Product, customer, and firm suitability"},"answer":"C","explanation":"FINRA Rule 2111 requires three types of suitability: (1) reasonable-basis suitability (understanding the product), (2) customer-specific suitability (matching to customer needs), and (3) quantitative suitability (ensuring trading is not excessive).","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch1-009","section":"4 - Regulatory Framework","stem":"Which of the following is PROHIBITED in communications with the public?","choices":{"A":"Disclosing the risks of an investment","B":"Comparing two investment options","C":"Predicting future investment performance","D":"Describing a mutual fund's investment objective"},"answer":"C","explanation":"FINRA Rule 2210 prohibits predictions of future performance in communications with the public. Such promises are considered misleading. Risk disclosure, fair comparisons, and describing investment objectives are all permitted and often required.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch1-010","section":"4 - Regulatory Framework","stem":"When must a mutual fund prospectus be delivered to an investor?","choices":{"A":"Within 30 days of purchase","B":"At or before the time of sale","C":"Only if the investor requests it","D":"Within 10 business days of purchase"},"answer":"B","explanation":"A mutual fund prospectus (or summary prospectus) must be delivered at or before the time of sale — meaning at or before the customer receives their trade confirmation. This ensures investors have material information before their purchase is complete.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch1-011","section":"2 - Products & Risks","stem":"Which document must a fund provide only upon request, not automatically?","choices":{"A":"Prospectus","B":"Summary prospectus","C":"Statement of Additional Information (SAI)","D":"Annual report"},"answer":"C","explanation":"The Statement of Additional Information (SAI) is not automatically delivered — it must be provided only when an investor requests it. The prospectus (or summary prospectus) must be delivered automatically at or before sale.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch1-013","section":"4 - Regulatory Framework","stem":"Under FINRA Rule 3220, what is the maximum value gift a representative can give to an employee of another firm per year?","choices":{"A":"$50","B":"$100","C":"$250","D":"$500"},"answer":"B","explanation":"FINRA Rule 3220 limits gifts to $100 per person, per year when the gift relates to the recipient's employer's business. This limit has been in place since 1992, though FINRA has proposed increasing it to $250-$300.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch1-014","section":"2 - Products & Risks","stem":"A registered representative wants to start a part-time real estate business. What must they do FIRST?","choices":{"A":"Notify FINRA directly","B":"File an amended Form U4","C":"Provide prior written notice to their firm","D":"Wait until the activity generates income"},"answer":"C","explanation":"Under FINRA Rule 3270, a registered representative must provide prior written notice to their firm BEFORE engaging in any outside business activity. The firm then evaluates whether to approve, disapprove, or impose conditions on the activity.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch1-015","section":"2 - Products & Risks","stem":"A representative sells securities to a customer that are not offered through their firm and does not inform the firm. This is known as:","choices":{"A":"Outside business activity","B":"Selling away","C":"Churning","D":"Front running"},"answer":"B","explanation":"\"Selling away\" refers to private securities transactions conducted without the firm's knowledge or approval (FINRA Rule 3280). This is a serious violation because it bypasses the firm's supervisory and compliance procedures, putting customers at risk.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch2-001","section":"2 - Products & Risks","stem":"A mutual fund has total assets of $50 million, liabilities of $1 million, and 4 million shares outstanding. What is the NAV per share?","choices":{"A":"$11.25","B":"$12.25","C":"$12.50","D":"$13.00"},"answer":"B","explanation":"NAV = (Total Assets - Liabilities) ÷ Shares Outstanding = ($50M - $1M) ÷ 4M = $49M ÷ 4M = $12.25 per share.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch2-002","section":"3 - Trading, Accounts & Prohibited","stem":"Under forward pricing, an investor places a mutual fund order at 2:00 PM ET. At what price will the order be executed?","choices":{"A":"The previous day's closing NAV","B":"The current real-time NAV","C":"The NAV calculated at 4:00 PM ET that day","D":"The next morning's opening NAV"},"answer":"C","explanation":"Forward pricing means orders receive the next calculated NAV. Since the order was placed before the 4:00 PM ET cutoff, it will be executed at that day's closing NAV, calculated after markets close.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch2-003","section":"2 - Products & Risks","stem":"When a mutual fund pays a dividend distribution to shareholders, what happens to the NAV?","choices":{"A":"NAV increases by the dividend amount","B":"NAV decreases by the dividend amount","C":"NAV remains unchanged","D":"NAV is not affected by distributions"},"answer":"B","explanation":"When a fund pays dividends or capital gains distributions, the NAV decreases by the amount of the distribution. The fund's assets decrease as cash is paid out to shareholders.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch2-004","section":"2 - Products & Risks","stem":"Which type of mutual fund would be MOST suitable for a retiree seeking regular monthly income?","choices":{"A":"Small-cap growth fund","B":"Sector fund focused on technology","C":"Bond income fund","D":"Target-date 2065 fund"},"answer":"C","explanation":"A bond income fund is designed to provide regular income through interest payments, making it suitable for retirees. Growth funds, sector funds, and long-dated target funds are more aggressive and focused on appreciation, not income.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch2-005","section":"2 - Products & Risks","stem":"What is a key characteristic of index funds?","choices":{"A":"They are actively managed to beat the market","B":"They track a specific market index with passive management","C":"They focus only on small-cap stocks","D":"They are only available in retirement accounts"},"answer":"B","explanation":"Index funds use passive management to track a specific market index like the S&P 500. They don't try to beat the market — instead, they aim to match the index's performance, typically with lower expense ratios than actively managed funds.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch2-006","section":"2 - Products & Risks","stem":"A target-date 2040 fund is designed for an investor who plans to retire around 2040. How will the fund's asset allocation change over time?","choices":{"A":"It will become more aggressive (more stocks) as 2040 approaches","B":"It will become more conservative (more bonds) as 2040 approaches","C":"It will maintain the same allocation throughout","D":"It will only invest in bonds starting in 2040"},"answer":"B","explanation":"Target-date funds use a \"glide path\" that starts aggressive (more stocks) when the target date is far away and gradually shifts to more conservative investments (more bonds) as the target retirement date approaches.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch2-007","section":"2 - Products & Risks","stem":"An investor purchases $10,000 of Class A shares with a 5% front-end load. How much is actually invested in the fund?","choices":{"A":"$9,000","B":"$9,500","C":"$10,000","D":"$10,500"},"answer":"B","explanation":"With a 5% front-end load, $500 is deducted as a sales charge ($10,000 × 5% = $500). The remaining $9,500 is actually invested in the fund.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch2-008","section":"2 - Products & Risks","stem":"What is the maximum 12b-1 fee a fund can charge and still call itself a \"no-load\" fund?","choices":{"A":"0%","B":"0.25%","C":"0.75%","D":"1.00%"},"answer":"B","explanation":"A fund can charge up to 0.25% in 12b-1 fees and still market itself as a \"no-load\" fund. Any 12b-1 fee above 0.25% means the fund cannot use the no-load designation.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch2-009","section":"2 - Products & Risks","stem":"Which share class typically converts to Class A shares after a holding period of approximately 5-7 years?","choices":{"A":"Class A shares","B":"Class B shares","C":"Class C shares","D":"No-load shares"},"answer":"B","explanation":"Class B shares typically convert to Class A shares after approximately 5-7 years. This conversion reduces ongoing expenses since Class A shares have lower 12b-1 fees than Class B shares.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch2-010","section":"2 - Products & Risks","stem":"An investor signs a Letter of Intent (LOI) to invest $100,000 in a mutual fund. Over what time period must they fulfill this commitment?","choices":{"A":"6 months","B":"12 months","C":"13 months","D":"24 months"},"answer":"C","explanation":"A Letter of Intent gives investors 13 months to fulfill their commitment and qualify for breakpoint discounts. The LOI can also be backdated up to 90 days to include recent purchases.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch2-011","section":"2 - Products & Risks","stem":"An investor has $45,000 invested in a mutual fund and wants to invest an additional $10,000. Using rights of accumulation (ROA), how should the sales charge be calculated?","choices":{"A":"Based on the $10,000 new investment only","B":"Based on the combined $55,000 total","C":"Based on the average of the two amounts","D":"ROA does not apply to additional purchases"},"answer":"B","explanation":"Rights of Accumulation (ROA) allow investors to combine existing holdings with new purchases to qualify for breakpoints. The sales charge on the new $10,000 would be calculated based on the combined $55,000 total, potentially qualifying for a lower rate.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch2-012","section":"2 - Products & Risks","stem":"A representative recommends that a client invest $49,000 in a mutual fund when the client has $50,000 available. The breakpoint at $50,000 would reduce the sales charge from 5% to 4.5%. This practice is known as:","choices":{"A":"Dollar cost averaging","B":"Breakpoint selling","C":"Rights of accumulation","D":"Forward pricing"},"answer":"B","explanation":"Breakpoint selling is a violation where a representative fails to help clients reach available breakpoints or deliberately keeps investments just below breakpoint thresholds. Representatives must always inform clients about breakpoint opportunities.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch2-013","section":"2 - Products & Risks","stem":"An investor receives a long-term capital gains distribution from a mutual fund they've owned for only 3 months. How is this distribution taxed?","choices":{"A":"As short-term capital gains because the investor held shares less than 1 year","B":"As long-term capital gains regardless of the investor's holding period","C":"As ordinary income","D":"It is not taxable until shares are sold"},"answer":"B","explanation":"Capital gains distributions from mutual funds are always treated as long-term capital gains for tax purposes, regardless of how long the investor has owned the fund shares. The fund's holding period of the securities determines the character of the gain.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch2-014","section":"2 - Products & Risks","stem":"An investor reinvests a $1,000 dividend distribution from a mutual fund. Which statement is TRUE?","choices":{"A":"No taxes are owed because the distribution was reinvested","B":"The investor owes taxes on the $1,000 and their cost basis increases","C":"Taxes are deferred until the shares are sold","D":"Only half the distribution is taxable"},"answer":"B","explanation":"Even when dividends are reinvested, they are taxable in the year received. However, the reinvested amount increases the investor's cost basis, which reduces the taxable gain when shares are eventually sold.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch2-015","section":"2 - Products & Risks","stem":"Which type of mutual fund would provide the MOST tax advantage for an investor in the highest federal tax bracket?","choices":{"A":"Growth stock fund","B":"Corporate bond fund","C":"Municipal bond fund","D":"Money market fund"},"answer":"C","explanation":"Municipal bond funds provide federally tax-exempt income, making them most valuable for investors in high tax brackets. The higher the tax bracket, the more valuable the tax exemption becomes.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch2-016","section":"2 - Products & Risks","stem":"An investor uses dollar cost averaging to invest $300 monthly in a mutual fund. In Month 1 the NAV is $30, and in Month 2 the NAV is $15. How many total shares did the investor purchase?","choices":{"A":"15 shares","B":"20 shares","C":"25 shares","D":"30 shares"},"answer":"D","explanation":"Month 1: $300 ÷ $30 = 10 shares. Month 2: $300 ÷ $15 = 20 shares. Total: 10 + 20 = 30 shares. Dollar cost averaging results in buying more shares when prices are low.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch2-017","section":"1 - Capital Markets","stem":"When an investor exchanges from one mutual fund to another within the same fund family, which of the following is TRUE?","choices":{"A":"The exchange is never a taxable event","B":"A new sales charge must always be paid","C":"The exchange may trigger capital gains taxes","D":"Exchanges are prohibited by SEC rules"},"answer":"C","explanation":"An exchange between funds is a taxable event — the investor has effectively sold one fund and purchased another. While no new sales charge may apply within a fund family, any gains on the sold fund are taxable.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch2-018","section":"3 - Trading, Accounts & Prohibited","stem":"What is the standard settlement period for mutual fund transactions?","choices":{"A":"Same day","B":"T+1 (one business day)","C":"T+2 (two business days)","D":"T+3 (three business days)"},"answer":"B","explanation":"Mutual fund transactions settle T+1, meaning one business day after the trade date. This is the same settlement period as stocks and most other securities since the SEC shortened settlement to T+1 in May 2024.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch2-019","section":"2 - Products & Risks","stem":"Which of the following is a key characteristic that distinguishes a UIT from a mutual fund?","choices":{"A":"UITs are not registered with the SEC","B":"UITs have a fixed, unmanaged portfolio with a termination date","C":"UITs charge higher management fees","D":"UITs cannot be redeemed by investors"},"answer":"B","explanation":"UITs have a fixed, unmanaged portfolio and a specific termination date, unlike mutual funds which are actively managed (or track an index) and operate indefinitely. UITs are SEC-registered and can be redeemed.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch2-020","section":"2 - Products & Risks","stem":"A UIT does NOT have which of the following?","choices":{"A":"A prospectus","B":"A board of directors","C":"A termination date","D":"Redeemable units"},"answer":"B","explanation":"UITs do not have a board of directors — they are unmanaged trusts. Mutual funds are required to have a board of directors (with at least 40% independent), but UITs operate without one since no ongoing management decisions are made.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch2-021","section":"2 - Products & Risks","stem":"What typically happens to a UIT when it reaches its termination date?","choices":{"A":"It converts to a mutual fund","B":"The portfolio is liquidated and proceeds distributed to unitholders","C":"Units continue trading indefinitely","D":"The trust automatically renews for another term"},"answer":"B","explanation":"When a UIT reaches its termination date, the trust liquidates all securities in the portfolio and distributes the cash proceeds to unitholders. The trust ceases to exist after termination.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch2-022","section":"2 - Products & Risks","stem":"What is a key difference between ETFs and mutual funds?","choices":{"A":"ETFs cannot hold bonds","B":"ETFs trade throughout the day on exchanges while mutual funds trade once daily at NAV","C":"Mutual funds have lower expense ratios than ETFs","D":"ETFs must be held for at least one year"},"answer":"B","explanation":"The key difference is trading: ETFs trade throughout the day on exchanges at real-time market prices, while mutual fund shares are bought and sold at the end-of-day NAV. ETFs can also use limit orders, stop orders, and be sold short.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch2-023","section":"2 - Products & Risks","stem":"Why are ETFs generally more tax-efficient than mutual funds?","choices":{"A":"ETFs are exempt from capital gains taxes","B":"The creation/redemption mechanism minimizes capital gains distributions","C":"ETF dividends are not taxable","D":"ETFs only hold tax-exempt securities"},"answer":"B","explanation":"ETFs use an \"in-kind\" creation/redemption mechanism with Authorized Participants. This allows the ETF to avoid selling securities (which would trigger capital gains) when investors redeem shares, making ETFs more tax-efficient than mutual funds.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch2-024","section":"2 - Products & Risks","stem":"Which of the following is TRUE about leveraged ETFs?","choices":{"A":"They are designed for long-term buy-and-hold investors","B":"They reset daily and may not achieve expected multiples over longer periods","C":"They have lower risk than standard index ETFs","D":"They are not allowed to use derivatives"},"answer":"B","explanation":"Leveraged ETFs reset daily, meaning their returns are designed to match a multiple of the index's daily return, not long-term returns. Due to compounding effects, returns over longer periods may differ significantly from the expected multiple.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch2-025","section":"2 - Products & Risks","stem":"A closed-end fund has a NAV of $15 per share and is trading at $13.50 per share. This fund is trading at:","choices":{"A":"A 10% premium to NAV","B":"A 10% discount to NAV","C":"NAV","D":"A 15% discount to NAV"},"answer":"B","explanation":"Discount = (NAV - Market Price) / NAV = ($15 - $13.50) / $15 = $1.50 / $15 = 10% discount. When market price is below NAV, the fund trades at a discount.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch2-026","section":"2 - Products & Risks","stem":"What is a key risk associated with closed-end funds that use leverage?","choices":{"A":"They cannot trade on exchanges","B":"Leverage magnifies both gains and losses","C":"They must redeem shares at NAV","D":"They cannot hold bonds"},"answer":"B","explanation":"Leverage amplifies returns in both directions. If the portfolio gains, the fund gains more than an unleveraged fund. But if the portfolio loses, the fund loses more. Rising interest rates also increase borrowing costs for leveraged funds.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch2-027","section":"1 - Capital Markets","stem":"Why might buying a closed-end fund at its IPO NOT be recommended?","choices":{"A":"Closed-end funds cannot be purchased at IPO","B":"IPO investors pay NAV plus underwriting costs, and most CEFs later trade at discounts","C":"The SEC prohibits individual investors from buying CEFs at IPO","D":"CEFs do not have IPOs"},"answer":"B","explanation":"At IPO, investors pay NAV plus underwriting costs (typically 5-7%). Since most closed-end funds eventually trade at discounts to NAV in the secondary market, IPO buyers often see immediate paper losses. It's generally better to buy CEFs in the secondary market.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch3-001","section":"3 - Trading, Accounts & Prohibited","stem":"What type of account holds the investments in a variable annuity?","choices":{"A":"General account","B":"Separate account","C":"Trust account","D":"Escrow account"},"answer":"B","explanation":"Variable annuity investments are held in a separate account, which is legally segregated from the insurance company's general account. This protects the investor's assets from the company's creditors and allows the value to fluctuate based on investment performance.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch3-002","section":"2 - Products & Risks","stem":"Why must a representative hold both a securities license and an insurance license to sell variable annuities?","choices":{"A":"It is a federal requirement for all annuity products","B":"Variable annuities are both insurance products and securities with investment risk","C":"The insurance license covers the sales charge and the securities license covers the investment","D":"State laws require dual licensing for any retirement product"},"answer":"B","explanation":"Variable annuities are hybrid products - they are insurance contracts (requiring insurance licensing) that also involve securities investments in the separate account (requiring securities licensing). The investment risk and securities registration make them subject to SEC and FINRA regulation.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch3-003","section":"2 - Products & Risks","stem":"In a variable annuity, who bears the investment risk?","choices":{"A":"The insurance company","B":"The state insurance commissioner","C":"The contract owner","D":"FINRA"},"answer":"C","explanation":"In a variable annuity, the contract owner bears the investment risk. The value of the annuity fluctuates based on the performance of the chosen subaccounts. This is different from a fixed annuity, where the insurance company guarantees a minimum return and bears the investment risk.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch3-004","section":"2 - Products & Risks","stem":"During the annuity phase, when will monthly payments increase?","choices":{"A":"When the separate account has any positive return","B":"When the separate account return exceeds the AIR","C":"When the number of annuity units increases","D":"When the owner makes additional premium payments"},"answer":"B","explanation":"During the annuity phase, payments increase only when the separate account's actual return EXCEEDS the Assumed Interest Rate (AIR). A positive return that is still below the AIR will result in decreased payments. The number of annuity units is fixed at annuitization and does not change.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch3-005","section":"3 - Trading, Accounts & Prohibited","stem":"If a variable annuity has an AIR of 5% and the separate account earns 5%, what happens to the annuity payment?","choices":{"A":"The payment increases","B":"The payment decreases","C":"The payment remains the same","D":"The payment is recalculated based on new actuarial tables"},"answer":"C","explanation":"When the separate account's actual return EQUALS the Assumed Interest Rate (AIR), the annuity payment remains unchanged. Payments only increase when performance exceeds AIR, and decrease when performance falls below AIR.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch3-006","section":"2 - Products & Risks","stem":"At annuitization, which of the following is true about annuity units?","choices":{"A":"The number of units continues to increase with each payment received","B":"The number of units is fixed, but the value per unit fluctuates","C":"Both the number and value of units are guaranteed","D":"The number of units decreases as payments are made"},"answer":"B","explanation":"At annuitization, the number of annuity units is calculated and then FIXED for the life of the payout. The number never changes. However, the VALUE per annuity unit fluctuates based on the separate account's performance relative to the AIR, which is why payments can vary.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch3-007","section":"2 - Products & Risks","stem":"Which annuity payout option provides the HIGHEST monthly payment amount?","choices":{"A":"Joint and survivor","B":"Life with 20-year period certain","C":"Life only","D":"Life with 10-year period certain"},"answer":"C","explanation":"Life only (straight life) provides the highest monthly payment because there is no guarantee to beneficiaries - when the annuitant dies, payments stop and the insurance company keeps any remaining funds. The less guarantee provided, the higher the payment.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch3-008","section":"2 - Products & Risks","stem":"A client selects life with 10-year period certain and dies after 3 years. What happens?","choices":{"A":"Payments stop immediately","B":"The beneficiary receives payments for the remaining 7 years","C":"The beneficiary receives a lump sum equal to 10 years of payments","D":"The beneficiary receives payments for life"},"answer":"B","explanation":"With a life with period certain option, payments are guaranteed for the minimum period (10 years in this case) regardless of when the annuitant dies. Since the annuitant died after only 3 years, the beneficiary receives the remaining 7 years of payments.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch3-009","section":"2 - Products & Risks","stem":"Which payout option would be MOST suitable for a married couple where both spouses need the income to continue after the first death?","choices":{"A":"Life only","B":"Period certain only","C":"Joint and survivor","D":"Life with 5-year period certain"},"answer":"C","explanation":"Joint and survivor is designed specifically for couples. It continues payments until BOTH people have died, ensuring the surviving spouse continues to receive income. While it provides the lowest payment amount, it offers the most protection for couples who depend on the income.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch3-010","section":"2 - Products & Risks","stem":"A GMIB (Guaranteed Minimum Income Benefit) rider guarantees:","choices":{"A":"The account value will never fall below the original investment","B":"A minimum income amount when the contract is annuitized","C":"The ability to withdraw a percentage of principal annually","D":"A stepped-up death benefit based on market highs"},"answer":"B","explanation":"GMIB guarantees a minimum income amount when the contract is annuitized, typically based on a benefit base that grows at a guaranteed rate. The key distinguishing feature is that the contract MUST be annuitized to receive the benefit. GMAB protects account value; GMWB guarantees withdrawals.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch3-011","section":"2 - Products & Risks","stem":"Which living benefit rider does NOT require annuitization to receive the guarantee?","choices":{"A":"GMIB - Guaranteed Minimum Income Benefit","B":"GMWB - Guaranteed Minimum Withdrawal Benefit","C":"Both require annuitization","D":"Neither requires annuitization"},"answer":"B","explanation":"GMWB (Guaranteed Minimum Withdrawal Benefit) does NOT require annuitization. It allows the contract owner to withdraw a percentage of their principal annually regardless of market performance. GMIB DOES require annuitization to receive its income guarantee.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch3-013","section":"2 - Products & Risks","stem":"A non-qualified annuity has a cost basis of $80,000 and a current value of $120,000. If the owner withdraws $30,000, how much is taxable?","choices":{"A":"$0 - withdrawals are tax-free until basis is recovered","B":"$20,000 - only the amount exceeding basis","C":"$30,000 - entire withdrawal is taxable under LIFO rules","D":"$10,000 - prorated based on the earnings ratio"},"answer":"C","explanation":"Non-qualified annuity withdrawals use LIFO (Last-In, First-Out) taxation, meaning earnings come out first. With $40,000 in earnings ($120,000 - $80,000), the entire $30,000 withdrawal is considered earnings and is 100% taxable as ordinary income.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch3-014","section":"1 - Capital Markets","stem":"Which of the following 1035 exchanges is NOT permitted?","choices":{"A":"Life insurance policy to variable annuity","B":"Variable annuity to another variable annuity","C":"Variable annuity to life insurance policy","D":"Whole life policy to another whole life policy"},"answer":"C","explanation":"A 1035 exchange cannot go from an annuity to a life insurance policy. Exchanges can go \"down\" (life insurance to annuity) or \"across\" (annuity to annuity, life to life), but not \"up\" (annuity to life insurance).","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch3-015","section":"2 - Products & Risks","stem":"A 52-year-old withdraws money from a non-qualified variable annuity. What penalties or taxes may apply?","choices":{"A":"Only the 10% early withdrawal penalty","B":"Only ordinary income tax on the earnings portion","C":"Both ordinary income tax and a 10% early withdrawal penalty on the earnings","D":"No tax or penalty because non-qualified annuities use after-tax dollars"},"answer":"C","explanation":"For withdrawals before age 59 1/2 from a non-qualified annuity, the earnings portion is subject to BOTH ordinary income tax AND the 10% early withdrawal penalty. The after-tax basis is not double-taxed, but the earnings are fully taxable plus the penalty.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch3-016","section":"2 - Products & Risks","stem":"What distinguishes Variable Universal Life (VUL) from scheduled premium Variable Life?","choices":{"A":"VUL has no cash value component","B":"VUL allows flexible premium payments","C":"VUL does not require a securities license to sell","D":"VUL provides a higher guaranteed death benefit"},"answer":"B","explanation":"Variable Universal Life (VUL) combines variable life's investment component with universal life's premium flexibility. Policy owners can adjust premium payments, pay more, less, or even skip premiums (as long as cash value covers policy costs). Scheduled premium variable life requires fixed, mandatory premiums.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch3-017","section":"2 - Products & Risks","stem":"In a variable life insurance policy, the cash value:","choices":{"A":"Is guaranteed to grow at a minimum rate","B":"Fluctuates based on the performance of the separate account","C":"Is held in the insurance company's general account","D":"Cannot be borrowed against"},"answer":"B","explanation":"In variable life insurance, the cash value is invested in a separate account and fluctuates based on investment performance. Unlike whole life insurance, there is no guaranteed minimum growth. The policy owner bears the investment risk and can see cash value decrease.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch3-018","section":"2 - Products & Risks","stem":"A VUL policy has a $400,000 face amount and $75,000 in cash value. Under Option B (increasing death benefit), what is the death benefit?","choices":{"A":"$400,000","B":"$475,000","C":"$325,000","D":"$75,000"},"answer":"B","explanation":"Under Option B (increasing death benefit), the death benefit equals the face amount PLUS the cash value. So $400,000 + $75,000 = $475,000. Under Option A (level), the death benefit would be just $400,000 regardless of cash value.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch3-019","section":"2 - Products & Risks","stem":"How are withdrawals from a non-MEC variable life insurance policy taxed?","choices":{"A":"LIFO - earnings come out first and are taxable","B":"FIFO - basis comes out first and is tax-free","C":"All withdrawals are fully taxable regardless of basis","D":"All withdrawals are tax-free regardless of gains"},"answer":"B","explanation":"Non-MEC life insurance policies use FIFO (First-In, First-Out) taxation, meaning withdrawals are considered a return of basis (premiums paid) first and are tax-free until all basis is recovered. This is the opposite of annuities, which use LIFO (earnings first).","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch3-020","section":"2 - Products & Risks","stem":"What is the primary consequence of a life insurance policy becoming a Modified Endowment Contract (MEC)?","choices":{"A":"The death benefit becomes taxable to beneficiaries","B":"The policy must be surrendered within 60 days","C":"Loans and withdrawals are taxed like annuity distributions (LIFO)","D":"The policy loses its cash value component"},"answer":"C","explanation":"When a policy becomes a MEC, it loses the favorable FIFO treatment for withdrawals and loans. Instead, MECs are taxed like annuities - LIFO (earnings first), loans are taxable, and there's a 10% penalty for distributions before age 59 1/2. The death benefit remains income tax-free.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch3-021","section":"2 - Products & Risks","stem":"A client purchases a single-premium variable life insurance policy. What is the tax status of this policy?","choices":{"A":"It has standard life insurance tax treatment","B":"It is automatically a Modified Endowment Contract (MEC)","C":"It qualifies for additional tax benefits due to the lump-sum funding","D":"It must be held for 7 years before the tax status is determined"},"answer":"B","explanation":"A single-premium life insurance policy automatically fails the 7-pay test because the entire premium is paid upfront (exceeding what would be needed to pay up the policy in 7 level annual payments). Therefore, single-premium policies are always MECs from inception.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch3-023","section":"2 - Products & Risks","stem":"Which situation would be LEAST suitable for a variable annuity recommendation?","choices":{"A":"A 50-year-old who has maxed out their 401(k) and wants additional tax-deferred growth","B":"A 35-year-old with a long time horizon who wants market exposure with a death benefit","C":"A 65-year-old placing their IRA rollover into a variable annuity for additional tax deferral","D":"A 55-year-old seeking lifetime income options starting in 10 years"},"answer":"C","explanation":"Placing a variable annuity inside an IRA is generally unsuitable because the IRA already provides tax deferral. Adding a VA adds another layer of fees (M&E, admin fees) without any additional tax benefit. The other situations all have valid reasons for a VA recommendation.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch4-001","section":"3 - Trading, Accounts & Prohibited","stem":"In a Joint Tenants with Rights of Survivorship (JTWROS) account, what happens when one owner dies?","choices":{"A":"The deceased owner's share goes through probate to their heirs","B":"The account is frozen until a court order is obtained","C":"The surviving owner(s) automatically inherit the deceased's share","D":"The deceased's share is divided equally among all named beneficiaries"},"answer":"C","explanation":"In a JTWROS account, the surviving owner(s) automatically inherit the deceased owner's share by operation of law. This happens outside of probate and regardless of what the deceased's will says. This \"right of survivorship\" is the key feature that distinguishes JTWROS from Tenants in Common.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch4-002","section":"3 - Trading, Accounts & Prohibited","stem":"Which statement is TRUE about UGMA/UTMA custodial accounts?","choices":{"A":"The custodian can change the beneficiary at any time","B":"Gifts to the account are irrevocable","C":"Multiple custodians can be named on a single account","D":"Assets remain under custodian control until the minor turns 30"},"answer":"B","explanation":"Gifts to UGMA/UTMA accounts are irrevocable - once made, they cannot be taken back. The beneficiary cannot be changed, only one custodian can be named per account, and assets must transfer to the minor at the age of majority (typically 18-25 depending on state and account type).","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch4-003","section":"4 - Regulatory Framework","stem":"Two business partners open a joint brokerage account. Partner A contributes $70,000 and Partner B contributes $30,000. They want ownership to reflect their contributions. Which account type is most appropriate?","choices":{"A":"Joint Tenants with Rights of Survivorship (JTWROS)","B":"Tenants in Common (TIC)","C":"Community Property","D":"Tenancy by the Entirety"},"answer":"B","explanation":"Tenants in Common (TIC) allows for unequal ownership based on each party's contribution. Partner A would own 70% and Partner B would own 30%. JTWROS requires equal ownership regardless of contribution. Community Property and Tenancy by the Entirety are only available to married couples.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch4-004","section":"2 - Products & Risks","stem":"What is the 2025 contribution limit for a 401(k) plan for an employee under age 50?","choices":{"A":"$7,000","B":"$16,500","C":"$23,500","D":"$70,000"},"answer":"C","explanation":"The 2025 401(k) contribution limit is $23,500 for employees under age 50. Those 50 and older can contribute an additional $7,500 catch-up contribution for a total of $31,000. Those ages 60-63 can contribute up to $11,250 in catch-up under SECURE 2.0.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch4-005","section":"3 - Trading, Accounts & Prohibited","stem":"Which retirement account does NOT require minimum distributions (RMDs) during the owner's lifetime?","choices":{"A":"Traditional IRA","B":"Roth IRA","C":"SEP IRA","D":"SIMPLE IRA"},"answer":"B","explanation":"Roth IRAs do NOT require minimum distributions during the owner's lifetime. This is a significant advantage of Roth accounts. Traditional IRAs, SEP IRAs, and SIMPLE IRAs all require RMDs beginning at age 73 (75 starting in 2033).","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch4-006","section":"3 - Trading, Accounts & Prohibited","stem":"A client receives a distribution from their 401(k) and wants to roll it over to an IRA. What is the deadline to complete an indirect (60-day) rollover?","choices":{"A":"30 days from receipt","B":"60 days from receipt","C":"90 days from receipt","D":"By December 31 of the same year"},"answer":"B","explanation":"For an indirect rollover, the funds must be redeposited into a qualified retirement account within 60 days of receipt. Missing this deadline results in the distribution being treated as taxable income (and potentially subject to the 10% early withdrawal penalty if under 59 1/2).","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch4-010","section":"3 - Trading, Accounts & Prohibited","stem":"Under the USA PATRIOT Act, which four pieces of information must be collected from customers opening accounts?","choices":{"A":"Name, Social Security Number, employer, and income","B":"Name, date of birth, address, and identification number","C":"Name, address, phone number, and email address","D":"Name, occupation, net worth, and investment objectives"},"answer":"B","explanation":"The CIP requirement under Section 326 of the USA PATRIOT Act requires firms to collect four specific pieces of information: (1) Name, (2) Date of Birth, (3) Address, and (4) Identification Number (SSN for U.S. persons or passport/government ID for non-U.S. persons).","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch4-011","section":"4 - Regulatory Framework","stem":"If a broker-dealer finds a customer's name on the OFAC SDN (Specially Designated Nationals) list, what must they do IMMEDIATELY?","choices":{"A":"File a Suspicious Activity Report within 30 days","B":"Close the account and refund any deposits","C":"Block the customer's assets and report to OFAC","D":"Notify the customer and request additional documentation"},"answer":"C","explanation":"An OFAC match requires IMMEDIATE blocking of assets. The firm must then report the match to OFAC within 10 business days. This is different from SAR filing, which has a 30-day deadline and does not require asset blocking. OFAC violations involve potential terrorists or sanctioned persons.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch4-012","section":"4 - Regulatory Framework","stem":"How long must a broker-dealer retain CIP records after an account is closed?","choices":{"A":"3 years","B":"5 years","C":"7 years","D":"10 years"},"answer":"B","explanation":"CIP records, including identifying information, verification documents, and descriptions of methods used to verify identity, must be retained for 5 years after the account is closed. This is a standard retention period for many financial records.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch4-013","section":"4 - Regulatory Framework","stem":"According to FINRA Rule 2090, how often must customer information be updated at a minimum?","choices":{"A":"Every 12 months","B":"Every 24 months","C":"Every 36 months","D":"Every 60 months"},"answer":"C","explanation":"FINRA Rule 2090 requires that customer information be updated at least every 36 months (3 years). However, firms should update more frequently when customers notify them of changes or when life events suggest circumstances have changed.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch4-014","section":"2 - Products & Risks","stem":"Which of the following is NOT typically part of a customer's investment profile under KYC requirements?","choices":{"A":"Annual income and net worth","B":"Investment objectives and time horizon","C":"Credit score and debt-to-income ratio","D":"Risk tolerance and investment experience"},"answer":"C","explanation":"While credit scores may be relevant for margin accounts, they are not typically part of the standard KYC investment profile. The investment profile includes age, annual income, net worth, tax status, investment objectives, experience, time horizon, risk tolerance, and liquidity needs.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch4-015","section":"4 - Regulatory Framework","stem":"Under FINRA Rule 4512, what is the purpose of obtaining a trusted contact person?","choices":{"A":"To authorize trading on behalf of the customer","B":"To receive duplicate statements and confirmations","C":"To contact if there are concerns about financial exploitation or the customer's health","D":"To verify the customer's identity under CIP requirements"},"answer":"C","explanation":"The trusted contact person is NOT an authorized trader. The purpose is to provide firms with someone to contact if there are concerns about the customer's account activity, possible financial exploitation, or health status. This is especially important for protecting senior investors.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch4-016","section":"4 - Regulatory Framework","stem":"Under Regulation S-P, when must a broker-dealer provide the initial privacy notice to a customer?","choices":{"A":"Within 30 days of account opening","B":"At the time of establishing the customer relationship","C":"With the first account statement","D":"Within 90 days of the first transaction"},"answer":"B","explanation":"Under Regulation S-P, the initial privacy notice must be provided at the time of establishing the customer relationship (account opening). This notice explains how the firm collects, uses, and protects customer information, and informs customers of their opt-out rights.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch4-017","section":"4 - Regulatory Framework","stem":"When must a prospectus be delivered to a customer purchasing mutual fund shares?","choices":{"A":"Within 3 business days after the sale","B":"At or before the sale","C":"With the first quarterly statement","D":"Within 30 days of settlement"},"answer":"B","explanation":"A prospectus must be delivered at or before the sale of mutual fund shares. A summary prospectus is acceptable for mutual funds, with the full statutory prospectus available upon request or online.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch4-018","section":"3 - Trading, Accounts & Prohibited","stem":"How frequently must account statements be sent to customers?","choices":{"A":"Monthly for all accounts","B":"At least quarterly","C":"Annually","D":"Only when there is activity"},"answer":"B","explanation":"Account statements must be sent at least quarterly, regardless of whether there was activity in the account. Some accounts, such as those holding penny stocks, require more frequent (monthly) statements.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch4-019","section":"2 - Products & Risks","stem":"A customer tells their representative: \"Buy some technology stocks when you think it's a good time.\" This instruction gives the representative:","choices":{"A":"No discretion - this is a normal order","B":"Time and price discretion only - no special authorization needed","C":"Full discretion - written authorization required","D":"Limited discretion - verbal authorization is sufficient"},"answer":"C","explanation":"This instruction gives the representative discretion over WHICH securities to buy and HOW MANY - this is full discretion requiring written authorization. The customer didn't specify the security or quantity. If the customer had said \"Buy 100 shares of XYZ when you think it's a good time,\" that would be only time/price discretion, which doesn't require special authorization.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch4-020","section":"4 - Regulatory Framework","stem":"Before opening a brokerage account for an employee of another FINRA member firm, what must be obtained?","choices":{"A":"A waiver from the SEC","B":"Written consent from the employee's employer firm","C":"Approval from FINRA's arbitration department","D":"A letter from the employee's compliance officer"},"answer":"B","explanation":"Under FINRA Rule 3210, before opening an account for a person associated with another FINRA member firm, you must obtain written consent from their employer. Additionally, duplicate confirmations and statements must be sent to the employer firm upon request.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch4-021","section":"4 - Regulatory Framework","stem":"Under FINRA Rule 2165, how long can a firm place a temporary hold on a suspicious disbursement from a senior investor's account?","choices":{"A":"Up to 10 business days","B":"Up to 25 business days, extendable by 30 more days","C":"Up to 60 calendar days","D":"Indefinitely until the matter is resolved"},"answer":"B","explanation":"FINRA Rule 2165 allows firms to place a temporary hold on disbursements for up to 25 business days if there is reasonable belief of financial exploitation. This can be extended by an additional 30 business days if the firm has reported the matter to a state regulator or agency.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch5-001","section":"4 - Regulatory Framework","stem":"Which component of FINRA Rule 2111 requires that a recommendation be suitable for at least SOME investors?","choices":{"A":"Customer-specific suitability","B":"Quantitative suitability","C":"Reasonable-basis suitability","D":"Regulatory suitability"},"answer":"C","explanation":"Reasonable-basis suitability requires that the representative understand the product well enough to determine it is suitable for at least some investors. This is different from customer-specific suitability, which requires the recommendation to be suitable for the particular customer.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch5-002","section":"4 - Regulatory Framework","stem":"Under Regulation Best Interest, which of the following is one of the four component obligations?","choices":{"A":"Profitability obligation","B":"Care obligation","C":"Suitability obligation","D":"Fiduciary obligation"},"answer":"B","explanation":"Regulation Best Interest has four component obligations: Disclosure, Care, Conflict of Interest, and Compliance. The Care Obligation requires broker-dealers to exercise reasonable diligence, care, and skill when making recommendations.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch5-003","section":"3 - Trading, Accounts & Prohibited","stem":"A representative makes several suitable individual recommendations, but when viewed together over time, the trading generates excessive costs for the customer. Which suitability component is violated?","choices":{"A":"Reasonable-basis suitability","B":"Customer-specific suitability","C":"Quantitative suitability","D":"Disclosure obligation"},"answer":"C","explanation":"Quantitative suitability addresses situations where individual recommendations may be suitable in isolation, but the series of transactions becomes excessive when viewed together. Factors include turnover rate, cost-equity ratio, and in-and-out trading patterns.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch5-004","section":"2 - Products & Risks","stem":"A 70-year-old retiree needs investments that provide regular income while preserving principal. Which investment objective is MOST appropriate?","choices":{"A":"Growth","B":"Speculation","C":"Income with capital preservation","D":"Aggressive growth"},"answer":"C","explanation":"Income with capital preservation is most appropriate for a retiree who needs regular income from investments while protecting their principal. This is the most conservative income objective, balancing the need for cash flow with safety of principal.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch5-005","section":"2 - Products & Risks","stem":"Which investment objective has the HIGHEST risk and return potential?","choices":{"A":"Capital preservation","B":"Growth and income","C":"Income","D":"Speculation"},"answer":"D","explanation":"Speculation has the highest risk and return potential. Speculative investors seek maximum gains and are willing to accept the possibility of significant losses. This objective is only suitable for sophisticated, aggressive investors who can afford substantial losses.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch5-006","section":"4 - Regulatory Framework","stem":"A high-income investor in the 37% tax bracket seeks income from a taxable brokerage account. Which fund type would be MOST tax-efficient?","choices":{"A":"Corporate bond fund","B":"Municipal bond fund","C":"High-yield bond fund","D":"Treasury bond fund"},"answer":"B","explanation":"Municipal bond funds provide tax-exempt income at the federal level, making them most suitable for high-income investors in taxable accounts. A 4% tax-free yield is equivalent to a much higher taxable yield for someone in the 37% bracket. Note: Muni bonds provide no benefit in tax-deferred accounts like IRAs.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch5-007","section":"3 - Trading, Accounts & Prohibited","stem":"A customer has high financial capacity to absorb losses but emotionally cannot tolerate seeing account values decline. How should the representative assess their risk tolerance?","choices":{"A":"High risk tolerance based on financial capacity","B":"Moderate risk tolerance as a compromise","C":"Low risk tolerance based on emotional attitude","D":"No risk tolerance assessment is needed"},"answer":"C","explanation":"Risk tolerance has two components: financial capacity and emotional attitude. When they differ, the representative should use the LOWER of the two. Even if a customer can financially afford losses, if they cannot emotionally handle volatility, recommendations should reflect their conservative emotional risk tolerance.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch5-008","section":"3 - Trading, Accounts & Prohibited","stem":"A 25-year-old investor is saving for retirement in 40 years. Which factor MOST supports recommending growth-oriented investments?","choices":{"A":"Their current high income","B":"Their long time horizon","C":"Their lack of investment experience","D":"Their need for current income"},"answer":"B","explanation":"A long time horizon (40 years until retirement) is the key factor supporting growth-oriented investments. With decades until they need the money, this investor has ample time to recover from market downturns, making them suitable for more volatile growth investments.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch5-009","section":"2 - Products & Risks","stem":"An aggressive investor plans to buy a house in 8 months and is saving for the down payment. What investments are MOST suitable for these funds?","choices":{"A":"Aggressive growth funds matching their risk tolerance","B":"Growth and income balanced funds","C":"Money market or short-term bond funds","D":"International equity funds"},"answer":"C","explanation":"Despite the investor's aggressive risk tolerance, the SHORT TIME HORIZON (8 months) requires conservative investments. Money needed soon should be in safe, liquid investments regardless of overall risk tolerance. The investor cannot afford to lose their down payment money.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch5-010","section":"3 - Trading, Accounts & Prohibited","stem":"A customer in the 35% tax bracket seeks income from a taxable account. They already have adequate bond exposure. Which recommendation is MOST suitable?","choices":{"A":"Corporate bond fund for higher yield","B":"Municipal bond fund for tax-exempt income","C":"Money market fund for safety","D":"Growth fund for capital appreciation"},"answer":"B","explanation":"For a high-tax-bracket investor seeking income in a taxable account, a municipal bond fund is most suitable. The tax-exempt income from municipal bonds is more valuable to high-income investors. A 3.5% tax-free yield is equivalent to about 5.4% taxable yield for someone in the 35% bracket.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch5-011","section":"3 - Trading, Accounts & Prohibited","stem":"A customer wants to purchase a variable annuity inside their IRA. What concern should the representative raise?","choices":{"A":"IRAs cannot hold variable annuities","B":"The IRA already provides tax deferral, so the VA adds fees without additional tax benefit","C":"Variable annuities have higher returns than IRAs","D":"The customer must be over age 59 1/2 to hold a VA in an IRA"},"answer":"B","explanation":"Placing a variable annuity inside an IRA is generally unsuitable because the IRA already provides tax deferral. Adding a VA adds another layer of fees (M&E, admin fees) without providing any additional tax benefit. The tax deferral feature of the VA is redundant inside an already tax-deferred IRA.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch5-012","section":"2 - Products & Risks","stem":"Before making an investment recommendation, which step should be completed FIRST?","choices":{"A":"Selecting the most profitable product for the firm","B":"Gathering customer information including financial situation, objectives, and risk tolerance","C":"Obtaining customer agreement to the recommendation","D":"Filing the necessary paperwork with FINRA"},"answer":"B","explanation":"The first step in making a suitable recommendation is gathering customer information. You cannot determine what is suitable for a customer without first understanding their financial situation, investment objectives, risk tolerance, time horizon, and other relevant factors.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch5-013","section":"3 - Trading, Accounts & Prohibited","stem":"A 28-year-old in a 22% tax bracket expects to be in a higher bracket when they retire. Which retirement account recommendation is MOST suitable?","choices":{"A":"Traditional IRA for the current tax deduction","B":"Roth IRA for tax-free withdrawals in retirement","C":"Non-deductible Traditional IRA","D":"Variable annuity for tax deferral"},"answer":"B","explanation":"A Roth IRA is most suitable for a young investor in a lower tax bracket who expects to be in a higher bracket in retirement. They pay taxes now at the lower rate (22%) and withdraw tax-free in retirement when they would otherwise be in a higher bracket.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch5-014","section":"3 - Trading, Accounts & Prohibited","stem":"A customer is rolling over their 401(k) to an IRA. Which rollover method should be recommended to avoid mandatory withholding?","choices":{"A":"Indirect rollover with 60-day deposit","B":"Direct trustee-to-trustee rollover","C":"Partial rollover with remainder cashed out","D":"Convert to Roth and pay taxes"},"answer":"B","explanation":"A direct trustee-to-trustee rollover is the best method because funds move directly between custodians without any withholding. Indirect rollovers result in mandatory 20% federal tax withholding and must be completed within 60 days, creating unnecessary risk and complications.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch5-015","section":"3 - Trading, Accounts & Prohibited","stem":"Which risk specifically describes the danger of poor investment returns early in retirement depleting the portfolio faster?","choices":{"A":"Inflation risk","B":"Longevity risk","C":"Sequence of returns risk","D":"Interest rate risk"},"answer":"C","explanation":"Sequence of returns risk is the specific risk that poor returns early in retirement disproportionately harm the portfolio. Because retirees are withdrawing funds, a declining portfolio early on has less time and fewer assets to recover when markets improve.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch5-019","section":"3 - Trading, Accounts & Prohibited","stem":"A representative recommends numerous trades in a customer's account, generating significant commissions but providing little benefit to the customer. This practice is called:","choices":{"A":"Breakpoint selling","B":"Churning","C":"Front-running","D":"Switching"},"answer":"B","explanation":"Churning is excessive trading in a customer's account primarily to generate commissions for the representative, without regard to the customer's investment objectives. This violates the quantitative suitability component of FINRA Rule 2111.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch5-020","section":"2 - Products & Risks","stem":"A customer wants to invest $49,500 in Class A mutual fund shares. The breakpoint for a reduced sales charge is $50,000. What should the representative do?","choices":{"A":"Process the order as requested without comment","B":"Inform the customer about the breakpoint and the benefit of investing $50,000","C":"Automatically increase the investment to $50,000","D":"Recommend Class B shares instead to avoid the issue"},"answer":"B","explanation":"The representative must inform the customer about the breakpoint opportunity. A $49,500 investment just below a $50,000 breakpoint is a red flag for breakpoint selling. The customer should be made aware that investing slightly more would result in a reduced sales charge.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch5-021","section":"2 - Products & Risks","stem":"Which of the following is a red flag for an unsuitable variable annuity recommendation?","choices":{"A":"Customer has maxed out their 401(k) and IRA contributions","B":"Customer has a 15-year time horizon before retirement","C":"Customer wants to place the variable annuity inside their existing IRA","D":"Customer wants guaranteed lifetime income options"},"answer":"C","explanation":"Placing a variable annuity inside an IRA is a classic red flag because the IRA already provides tax deferral. Adding a VA adds another layer of fees without additional tax benefit, making it generally unsuitable. The other options are legitimate reasons to consider a VA.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch6-001","section":"3 - Trading, Accounts & Prohibited","stem":"Under SEC Rule 22c-1, a customer places a mutual fund purchase order at 3:30 PM ET. Which NAV will be used to price the transaction?","choices":{"A":"The NAV at 3:30 PM when the order was placed","B":"The NAV calculated at 4:00 PM the same day","C":"The previous day's closing NAV","D":"The NAV at the time of settlement"},"answer":"B","explanation":"Under forward pricing (Rule 22c-1), all orders receive the NEXT calculated NAV. Since the order was placed before the 4:00 PM ET cut-off, it will receive that day's NAV, which is calculated after market close (typically around 4:00 PM ET).","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch6-002","section":"2 - Products & Risks","stem":"By law, within how many days must a mutual fund company pay redemption proceeds to a shareholder?","choices":{"A":"3 calendar days","B":"5 business days","C":"7 calendar days","D":"10 business days"},"answer":"C","explanation":"Mutual funds must pay redemption proceeds within 7 calendar days of receiving a redemption request in good order. This can only be delayed in extraordinary circumstances such as when the NYSE is closed for reasons other than weekends or holidays, or during SEC-declared emergencies.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch6-003","section":"1 - Capital Markets","stem":"A customer exchanges shares from one mutual fund to another within the same fund family. How is this exchange treated for tax purposes?","choices":{"A":"Tax-free because it's within the same fund family","B":"Tax-deferred until the new fund is sold","C":"As a taxable event - a sale of the original fund and purchase of the new fund","D":"Only taxable if the exchange results in a gain"},"answer":"C","explanation":"Exchanges between mutual funds are taxable events, even within the same fund family. The exchange is treated as a sale of the original fund (potentially triggering capital gains or losses) and a purchase of the new fund (establishing a new cost basis).","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch6-005","section":"1 - Capital Markets","stem":"In a 1035 exchange from one variable annuity to another, which of the following is required for the exchange to be tax-free?","choices":{"A":"The new annuity must have lower fees than the old one","B":"The customer must be over age 59½","C":"The funds must transfer directly between insurance companies","D":"The old annuity must be outside its surrender period"},"answer":"C","explanation":"For a 1035 exchange to qualify as tax-free, funds must transfer directly between insurance companies. The owner cannot take constructive receipt of the funds. The exchange is valid regardless of fees, age, or surrender period (though surrender charges may still apply to the old contract).","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch6-007","section":"2 - Products & Risks","stem":"Under SEC Rule 10b-10, when must trade confirmations be sent to customers?","choices":{"A":"Within 24 hours of the trade","B":"At or before completion (settlement) of the transaction","C":"Within 3 business days of the trade","D":"With the next monthly statement"},"answer":"B","explanation":"SEC Rule 10b-10 requires that trade confirmations be sent to customers at or before the completion of the transaction, meaning at or before settlement date. With T+1 settlement, this means confirmations must be delivered within one business day after the trade.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch6-008","section":"4 - Regulatory Framework","stem":"On a trade confirmation, what must be disclosed when a broker-dealer acts as AGENT for the customer?","choices":{"A":"The firm's profit margin","B":"The commission charged","C":"The firm's inventory position","D":"The market maker's spread"},"answer":"B","explanation":"When a broker-dealer acts as agent (executing trades on behalf of the customer), the commission amount must be disclosed on the confirmation. When acting as principal (trading from the firm's inventory), different disclosure rules apply for mark-ups and mark-downs.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch6-009","section":"2 - Products & Risks","stem":"A customer notices an error on their trade confirmation. What is the recommended course of action?","choices":{"A":"Wait for the next statement to see if it's corrected","B":"Contact the firm immediately and document the concern in writing","C":"File a complaint with FINRA first","D":"Cancel the trade through the transfer agent"},"answer":"B","explanation":"Customers should report any discrepancies on trade confirmations immediately and put their concerns in writing. As SIPC notes, failure to complain in writing may compromise eligibility for investor protection. Prompt notification allows errors to be corrected quickly.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch6-010","section":"4 - Regulatory Framework","stem":"Under FINRA Rule 2231, what is the minimum frequency for sending account statements to customers?","choices":{"A":"Monthly","B":"Quarterly","C":"Semi-annually","D":"Annually"},"answer":"B","explanation":"FINRA Rule 2231 requires that account statements be sent to customers at least quarterly. However, accounts holding penny stocks must receive monthly statements. Many firms choose to send monthly statements to all customers even though quarterly is the minimum requirement.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch6-011","section":"4 - Regulatory Framework","stem":"Which statement must be included on every customer account statement according to FINRA rules?","choices":{"A":"A disclaimer that past performance does not guarantee future results","B":"A notice advising the customer to report promptly any inaccuracy or discrepancy","C":"A warning about the risks of investing in securities","D":"A list of the firm's fees and commissions"},"answer":"B","explanation":"FINRA Rule 2231 requires that each account statement include a notice advising the customer to promptly report any inaccuracy or discrepancy in their account to their brokerage firm. This encourages customers to review statements and report errors quickly.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch6-012","section":"3 - Trading, Accounts & Prohibited","stem":"Under what circumstances can a firm deliver account statements electronically?","choices":{"A":"Anytime, without customer consent","B":"Only if the customer is under age 65","C":"If the customer consents and can access and retain the documents","D":"Only for accounts with values over $100,000"},"answer":"C","explanation":"Firms may deliver statements electronically if the customer consents to electronic delivery, has the ability to access the documents, can retain copies for their records, and can revoke consent at any time. The firm must comply with SEC standards for electronic delivery.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch6-013","section":"4 - Regulatory Framework","stem":"Under SEC Rule 17a-4, how long must customer account records be retained?","choices":{"A":"3 years after the last transaction","B":"6 years after the account is closed","C":"7 years from account opening","D":"10 years regardless of account status"},"answer":"B","explanation":"SEC Rule 17a-4 requires that customer account records be retained for 6 years after the account is closed. During the first 2 years of this period, the records must be readily accessible for regulatory examination.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch6-014","section":"2 - Products & Risks","stem":"What is the retention requirement for general correspondence with customers under SEC Rule 17a-4?","choices":{"A":"1 year","B":"3 years","C":"6 years","D":"10 years"},"answer":"B","explanation":"General correspondence with customers must be retained for 3 years under SEC Rule 17a-4, with the first 2 years in an easily accessible location. This includes emails, letters, and other written communications.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch6-015","section":"4 - Regulatory Framework","stem":"A broker-dealer employee conducts business communications through personal text messages that are not captured by firm systems. What regulatory concern does this raise?","choices":{"A":"Privacy violation under Regulation S-P","B":"Recordkeeping violation under Rules 17a-3/17a-4","C":"Suitability violation under Rule 2111","D":"Front-running violation"},"answer":"B","explanation":"Using personal devices for business communications that are not captured by firm systems is a recordkeeping violation under SEC Rules 17a-3 and 17a-4. All business communications must be preserved, and \"off-channel\" communications have resulted in over $2 billion in fines in recent years.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch6-016","section":"3 - Trading, Accounts & Prohibited","stem":"A representative enters an order to buy 1,000 shares of XYZ but accidentally purchases 1,000 shares of XYX. This firm error is discovered the next day. What should happen regarding the customer's position?","choices":{"A":"The customer keeps the XYX shares since the trade was executed","B":"The customer receives XYZ shares at the price they would have received if the order was correct","C":"The customer must accept the XYX shares but gets a discount","D":"The trade is canceled and the customer receives nothing"},"answer":"B","explanation":"When a firm makes an error, the customer should be made whole - receiving what they would have received if the order was executed correctly. The firm should provide XYZ shares at the price that was available when the order should have been executed, and the firm bears any loss from correcting the error.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch6-017","section":"4 - Regulatory Framework","stem":"Who bears the financial cost of a trade error caused by the broker-dealer firm?","choices":{"A":"The customer, as they authorized the trade","B":"The representative who made the error","C":"The firm bears the cost","D":"The cost is split between the firm and customer"},"answer":"C","explanation":"When a trade error is caused by the firm (including its representatives), the firm bears the financial cost of correcting the error. The customer should be made whole and receive the position/price they would have received if the trade had been executed correctly.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-ch6-018","section":"2 - Products & Risks","stem":"Upon discovering a trade error, what is the representative's FIRST required action?","choices":{"A":"Correct the error before anyone notices","B":"Notify the customer immediately","C":"Report the error to a supervisor","D":"Document the error in the error log"},"answer":"C","explanation":"The first action when discovering a trade error should be to report it to a supervisor. This allows proper supervisory oversight of the correction process and ensures the error is handled according to firm procedures. Attempting to correct errors without supervisory knowledge can lead to additional problems.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-prac-005","section":"2 - Products & Risks","stem":"Which statement about preferred stock is TRUE?","choices":{"A":"It represents a debt obligation of the issuing company","B":"It provides guaranteed protection against inflation","C":"It is an equity security with fixed dividend payments","D":"It has priority over common stock in voting rights"},"answer":"C","explanation":"Preferred stock is an EQUITY security (not debt) that typically pays fixed dividends. It does NOT guarantee inflation protection - the fixed dividend may lose purchasing power over time. Preferred shareholders usually have no voting rights.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-prac-006","section":"2 - Products & Risks","stem":"An economy has experienced six consecutive quarters of declining GDP. This economic condition is classified as a:","choices":{"A":"Recession","B":"Depression","C":"Stagflation","D":"Contraction"},"answer":"B","explanation":"A depression is characterized by a prolonged economic downturn, typically defined as six or more quarters of declining GDP. A recession is a shorter decline of at least two consecutive quarters of negative GDP growth.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-prac-007","section":"2 - Products & Risks","stem":"An investor holding Treasury STRIPS must report income taxes on:","choices":{"A":"Only when the bond matures","B":"The annual accretion of the discount, even though no cash is received","C":"Only if the bond is sold before maturity","D":"Interest payments received semi-annually"},"answer":"B","explanation":"Treasury STRIPS (zero-coupon bonds) generate \"phantom income\" - the investor must pay taxes each year on the imputed interest (accretion of discount) even though no cash interest is received until maturity.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-prac-014","section":"4 - Regulatory Framework","stem":"A corporate executive shares material nonpublic information with a friend, who then trades on that information. Under insider trading laws:","choices":{"A":"Only the executive (tipper) is liable","B":"Only the friend (tippee) is liable","C":"Both the tipper and tippee may be liable","D":"Neither is liable if no profit was made"},"answer":"C","explanation":"Under insider trading laws, BOTH the tipper (who shared the information) AND the tippee (who traded on it) can be held liable. Liability exists regardless of whether the tipper personally profited from the disclosure.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-prac-020","section":"2 - Products & Risks","stem":"Company executives are selling shares they personally own to the public through a registered offering. This is called a:","choices":{"A":"Primary offering","B":"Secondary offering","C":"Private placement","D":"Rights offering"},"answer":"B","explanation":"When existing shareholders (like executives or insiders) sell their shares to the public, it is a secondary offering. The company receives no proceeds. In a primary offering, the company issues NEW shares and receives the proceeds.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-prac-022","section":"4 - Regulatory Framework","stem":"Under Regulation D Rule 506(b), what is the maximum number of non-accredited investors who may participate in a private placement?","choices":{"A":"0 - only accredited investors allowed","B":"35","C":"100","D":"Unlimited"},"answer":"B","explanation":"Regulation D Rule 506(b) allows up to 35 non-accredited investors (who must be sophisticated), plus unlimited accredited investors. Rule 506(c) allows only accredited investors but permits general solicitation.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-prac-025","section":"2 - Products & Risks","stem":"An investor concerned about reinvestment risk should consider which type of bond?","choices":{"A":"Callable corporate bonds","B":"High-coupon municipal bonds","C":"Zero-coupon Treasury bonds","D":"Floating-rate bonds"},"answer":"C","explanation":"Zero-coupon bonds eliminate reinvestment risk because there are no periodic coupon payments to reinvest. The investor receives only the face value at maturity. Bonds with coupons expose investors to the risk of reinvesting at lower rates.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-prac-029","section":"2 - Products & Risks","stem":"Money market mutual funds invest primarily in:","choices":{"A":"Long-term corporate bonds","B":"Small-cap growth stocks","C":"Short-term, high-quality debt instruments","D":"Real estate investment trusts"},"answer":"C","explanation":"Money market funds invest in short-term (maturity under 13 months, weighted average under 60 days), high-quality debt instruments such as Treasury bills, commercial paper, and CDs. This maintains stable NAV and high liquidity.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-prac-032","section":"2 - Products & Risks","stem":"A TIPS bond has a 2% coupon rate and an inflation-adjusted principal of $1,050. What is the annual interest payment?","choices":{"A":"$20","B":"$21","C":"$50","D":"$1,050"},"answer":"B","explanation":"TIPS interest is calculated on the inflation-adjusted principal. Interest = $1,050 x 2% = $21. The coupon rate stays fixed, but the principal adjusts with inflation, increasing the dollar amount of interest payments.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-prac-033","section":"4 - Regulatory Framework","stem":"Which of the following securities is NOT exempt from registration under the Securities Act of 1933?","choices":{"A":"U.S. Treasury bonds","B":"Municipal securities","C":"Collateral trust certificates","D":"Bank certificates of deposit"},"answer":"C","explanation":"Collateral trust certificates are corporate debt securities backed by other securities as collateral - they must be registered under the Securities Act of 1933. Government securities, municipal securities, and bank CDs are exempt from registration.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-prac-035","section":"2 - Products & Risks","stem":"When analyzing a general obligation (GO) municipal bond, an investor would NOT typically review:","choices":{"A":"The issuer's debt-to-assessed valuation ratio","B":"A feasibility study for the project","C":"The community's tax collection rate","D":"The issuer's overall tax base"},"answer":"B","explanation":"GO bonds are backed by the full faith and credit (taxing power) of the issuer, not a specific project. Feasibility studies are used for REVENUE bonds, which depend on project income. GO analysis focuses on tax base, collection rates, and debt ratios.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-prac-036","section":"2 - Products & Risks","stem":"When a market maker sells securities from its own inventory to a customer, the firm earns compensation through a:","choices":{"A":"Commission","B":"Markup","C":"Advisory fee","D":"12b-1 fee"},"answer":"B","explanation":"When acting as a dealer (principal), market makers earn markups when selling to customers and markdowns when buying from customers. Commissions are charged when acting as agent (broker) on behalf of customers.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-prac-039","section":"2 - Products & Risks","stem":"The minimum credit rating for a bond to be classified as investment grade is:","choices":{"A":"A","B":"BBB (Baa)","C":"BB (Ba)","D":"B"},"answer":"B","explanation":"Investment grade bonds are rated BBB (or Baa by Moody's) and above. Bonds rated BB/Ba and below are considered speculative or \"high-yield\" (junk bonds). Many institutional investors are restricted to investment-grade securities.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-prac-043","section":"4 - Regulatory Framework","stem":"Under Regulation A+ Tier 1, what is the maximum amount a company can raise in a 12-month period?","choices":{"A":"$5 million","B":"$20 million","C":"$50 million","D":"$75 million"},"answer":"B","explanation":"Regulation A+ Tier 1 allows companies to raise up to $20 million in a 12-month period with simplified SEC review. Tier 2 allows up to $75 million but requires more ongoing reporting. Both allow general solicitation.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-vl-002","section":"2 - Products & Risks","stem":"Which document MUST be delivered to a prospective variable life insurance purchaser before or at the time of sale?","choices":{"A":"Annual report","B":"Prospectus","C":"Statement of additional information","D":"Form 1099"},"answer":"B","explanation":"Variable life insurance is considered a security because of the investment component in separate accounts. Under SEC regulations, a prospectus must be delivered before or at the time of sale. The prospectus describes the policy features, investment options, fees, and risks.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s6-vl-004","section":"2 - Products & Risks","stem":"Which risk does the policyholder assume in a variable life insurance policy?","choices":{"A":"Mortality risk","B":"Investment risk","C":"Regulatory risk","D":"Insurance company default risk"},"answer":"B","explanation":"In variable life insurance, the policyholder assumes the investment risk because cash values fluctuate based on the performance of the separate account subaccounts. Unlike whole life insurance where the insurer guarantees a minimum return, variable life policy values can increase or decrease with market performance.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s65p2-001","section":"2 - Products & Risks","stem":"A no-load mutual fund does NOT charge which of the following fees?","choices":{"A":"Management fees","B":"Sales charges (loads)","C":"Administrative expenses","D":"12b-1 fees under 0.25%"},"answer":"B","explanation":"A no-load fund does not charge sales charges (front-end or back-end loads). However, all mutual funds, including no-load funds, still charge management fees and administrative expenses. They may also charge 12b-1 fees up to 0.25% and still be considered no-load.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s65p2-002","section":"2 - Products & Risks","stem":"An executive who holds restricted securities must file which form with the SEC before selling shares under Rule 144?","choices":{"A":"Form 4","B":"Form 144","C":"Form 10-K","D":"Form S-1"},"answer":"B","explanation":"Form 144 is filed with the SEC to provide notice of the proposed sale of restricted or control securities under Rule 144. This form must be filed if the sale exceeds 5,000 shares or $50,000 in any three-month period.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s65p2-004","section":"4 - Regulatory Framework","stem":"When a broker-dealer acts as a broker (agent) in a securities transaction, the firm earns:","choices":{"A":"A markup","B":"A markdown","C":"A commission","D":"A spread"},"answer":"C","explanation":"When acting as a broker (agent), the firm facilitates the transaction between buyer and seller without taking ownership of the securities. The compensation is a commission charged to the customer.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s65p2-005","section":"2 - Products & Risks","stem":"A call option with a strike price of $60 when the underlying stock is trading at $55 is:","choices":{"A":"In the money","B":"At the money","C":"Out of the money","D":"Break-even"},"answer":"C","explanation":"A call option is out of the money when the strike price is above the current market price. With a $60 strike and $55 market price, the call holder would not exercise because they could buy the stock cheaper in the market.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s65p2-006","section":"2 - Products & Risks","stem":"Which characteristic distinguishes publicly traded REITs from non-traded REITs?","choices":{"A":"Tax treatment of dividends","B":"Liquidity through exchange trading","C":"Requirement to distribute 90% of income","D":"Investment in real estate assets"},"answer":"B","explanation":"Publicly traded (listed) REITs trade on stock exchanges, providing investors with liquidity and the ability to buy or sell shares readily. Non-traded REITs lack this liquidity and may have limited redemption options.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s65p2-007","section":"2 - Products & Risks","stem":"A 457 deferred compensation plan is available to employees of:","choices":{"A":"Private corporations","B":"State and local governments and certain tax-exempt organizations","C":"Federal government agencies only","D":"Self-employed individuals"},"answer":"B","explanation":"457 plans are deferred compensation arrangements available to employees of state and local governments and certain tax-exempt organizations. They allow pre-tax contributions and tax-deferred growth similar to 401(k) plans.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s65p2-008","section":"2 - Products & Risks","stem":"A high-yield bond fund would be MOST appropriate for an investor seeking:","choices":{"A":"Capital preservation with minimal risk","B":"Higher income with acceptance of greater credit risk","C":"Tax-exempt interest income","D":"Short-term liquidity needs"},"answer":"B","explanation":"High-yield (junk) bond funds invest in below-investment-grade bonds rated BB or lower. They offer higher yields to compensate for the greater credit risk and are suitable for aggressive investors willing to accept default risk for enhanced income.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s65p2-010","section":"2 - Products & Risks","stem":"Which of the following is NOT classified as a precious metal for investment purposes?","choices":{"A":"Gold","B":"Silver","C":"Platinum","D":"Steel"},"answer":"D","explanation":"Steel is an industrial metal alloy, not a precious metal. Precious metals include gold, silver, platinum, and palladium, which are valued for their rarity, industrial uses, and role as stores of value.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s65p2-011","section":"2 - Products & Risks","stem":"A conservative investor seeking current income with minimal interest rate risk should consider:","choices":{"A":"Long-term corporate bond fund","B":"Short-term government bond fund","C":"High-yield bond fund","D":"Zero-coupon bond fund"},"answer":"B","explanation":"Short-term government bond funds have minimal interest rate risk (low duration) and high credit quality. They provide current income with lower volatility, making them suitable for conservative investors.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s65p2-012","section":"2 - Products & Risks","stem":"The PRIMARY factor causing fluctuations in the market prices of outstanding bonds is:","choices":{"A":"The issuer's earnings reports","B":"Changes in prevailing interest rates","C":"The bond's maturity date","D":"Stock market performance"},"answer":"B","explanation":"Changes in prevailing interest rates are the primary driver of bond price fluctuations. When rates rise, existing bond prices fall (and vice versa) because newly issued bonds offer different yields than outstanding bonds.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s65p2-015","section":"3 - Trading, Accounts & Prohibited","stem":"Assets in a UGMA/UTMA custodial account transfer to the minor beneficiary at:","choices":{"A":"Age 16","B":"Age of majority (typically 18 or 21 depending on state)","C":"Age 25","D":"When the custodian decides"},"answer":"B","explanation":"Custodial account assets automatically transfer to the beneficiary at the age of majority, which varies by state (typically 18 or 21). The custodian has no discretion to delay or prevent this transfer.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s65p2-016","section":"2 - Products & Risks","stem":"A convertible bond has a conversion ratio of 25 shares. If the stock is trading at $38, what is the parity price of the bond?","choices":{"A":"$900","B":"$950","C":"$1,000","D":"$1,050"},"answer":"B","explanation":"Parity price (conversion value) = Conversion ratio x Stock price = 25 shares x $38 = $950. This represents the value of the bond if converted into stock immediately.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s65p2-017","section":"4 - Regulatory Framework","stem":"A broker-dealer that executes proprietary trades before filling customer orders in the same security is engaged in:","choices":{"A":"Churning","B":"Front-running (trading ahead)","C":"Painting the tape","D":"Matched orders"},"answer":"B","explanation":"Front-running (trading ahead) is a prohibited practice where a firm trades for its own account ahead of customer orders to take advantage of the price movement the customer order will create. This violates the duty to put customer interests first.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s65p2-018","section":"2 - Products & Risks","stem":"Under the Securities Act of 1933, willful violations may result in criminal penalties including imprisonment of up to:","choices":{"A":"1 year","B":"3 years","C":"5 years","D":"10 years"},"answer":"C","explanation":"Willful violations of the Securities Act of 1933 may result in fines up to $10,000 and/or imprisonment up to 5 years per violation. The statute of limitations for criminal prosecution is 3 years.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s65p2-019","section":"2 - Products & Risks","stem":"An aggressive growth portfolio would MOST likely have the highest allocation to:","choices":{"A":"Money market instruments","B":"Investment-grade bonds","C":"Small-cap growth stocks","D":"Treasury securities"},"answer":"C","explanation":"Aggressive growth portfolios prioritize capital appreciation over income and safety. Small-cap growth stocks offer the highest growth potential (and highest risk), making them the primary holding in aggressive portfolios.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s65p2-020","section":"3 - Trading, Accounts & Prohibited","stem":"Under federal tax rules, 529 plan account owners may change their investment options:","choices":{"A":"At any time without restriction","B":"Twice per calendar year","C":"Once per calendar year (or upon beneficiary change)","D":"Only when the beneficiary turns 18"},"answer":"C","explanation":"Federal tax law permits 529 plan investment changes twice per calendar year (increased from once). Additionally, investment changes are allowed when changing the designated beneficiary.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s65p2-022","section":"2 - Products & Risks","stem":"A put option with a strike price of $45 when the stock trades at $50 is:","choices":{"A":"In the money by $5","B":"Out of the money by $5","C":"At the money","D":"In the money by $45"},"answer":"B","explanation":"A put is out of the money when the strike price is below the market price. With a $45 strike and $50 market price, the put holder would not exercise because they could sell the stock for more in the market ($50 > $45).","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s65p2-023","section":"2 - Products & Risks","stem":"Dollar cost averaging is BEST suited for an investor who:","choices":{"A":"Wants to time market peaks and valleys","B":"Has a lump sum to invest immediately","C":"Is concerned about investing at the wrong time","D":"Needs maximum short-term returns"},"answer":"C","explanation":"Dollar cost averaging involves investing fixed amounts at regular intervals regardless of market conditions. This strategy reduces the risk of investing a large sum at an inopportune time (market peak) and is ideal for investors concerned about market timing.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s65p2-024","section":"2 - Products & Risks","stem":"A mutual fund has total assets of $500 million, liabilities of $10 million, and 20 million shares outstanding. What is the NAV per share?","choices":{"A":"$24.00","B":"$24.50","C":"$25.00","D":"$25.50"},"answer":"B","explanation":"NAV = (Total Assets - Liabilities) / Shares Outstanding = ($500M - $10M) / 20M = $490M / 20M = $24.50 per share.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s65p2-026","section":"2 - Products & Risks","stem":"Using the Rule of 72, approximately how long will it take for an investment to double at 6% annual return?","choices":{"A":"6 years","B":"8 years","C":"10 years","D":"12 years"},"answer":"D","explanation":"The Rule of 72 estimates doubling time: 72 / Interest Rate = Years to Double. At 6%: 72 / 6 = 12 years to double the investment.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s65p2-027","section":"4 - Regulatory Framework","stem":"Under Regulation D Rule 506(b), a private placement may be sold to a maximum of how many non-accredited investors?","choices":{"A":"25","B":"35","C":"50","D":"Unlimited"},"answer":"B","explanation":"Regulation D Rule 506(b) allows an unlimited number of accredited investors but limits non-accredited purchasers to 35. Non-accredited investors must be \"sophisticated\" and receive specific disclosure documents.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s65p2-029","section":"2 - Products & Risks","stem":"The Investment Company Act of 1940 classifies investment companies into three categories. Which is NOT one of them?","choices":{"A":"Management companies","B":"Unit investment trusts (UITs)","C":"Face-amount certificate companies","D":"Exchange-traded funds (ETFs)"},"answer":"D","explanation":"The 1940 Act defines three types of investment companies: management companies (open-end and closed-end funds), unit investment trusts (UITs), and face-amount certificate companies. ETFs are typically structured as either open-end funds or UITs.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s65p2-031","section":"2 - Products & Risks","stem":"A technical analyst who follows short interest theory would interpret very high short interest as:","choices":{"A":"Bearish, indicating more selling pressure","B":"Bullish, as shorts must eventually buy to cover","C":"Neutral, with no predictive value","D":"Indicating the stock should be avoided"},"answer":"B","explanation":"Short interest theory is a contrarian indicator. High short interest is bullish because short sellers must eventually buy shares to cover their positions (short squeeze potential), creating buying pressure that could drive prices up.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s65p2-032","section":"2 - Products & Risks","stem":"An investor in the 37% federal tax bracket seeking tax-advantaged income should consider:","choices":{"A":"Corporate bonds","B":"Treasury bonds","C":"Municipal bonds","D":"High-yield bonds"},"answer":"C","explanation":"Municipal bonds pay interest that is exempt from federal income tax (and often state tax if issued in the investor's state). High-bracket investors benefit most from this tax exemption.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s65p2-033","section":"2 - Products & Risks","stem":"A bond with a 5% coupon trading at 95 has a current yield of:","choices":{"A":"4.75%","B":"5.00%","C":"5.26%","D":"5.50%"},"answer":"C","explanation":"Current Yield = Annual Interest / Market Price = $50 / $950 = 0.0526 = 5.26%. When a bond trades at a discount, current yield exceeds the coupon rate.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s65p2-034","section":"3 - Trading, Accounts & Prohibited","stem":"Contributions to a Coverdell Education Savings Account are:","choices":{"A":"Tax-deductible at the federal level","B":"Tax-deductible at the state level only","C":"Not tax-deductible, but earnings grow tax-free","D":"Deductible up to $2,000 per year"},"answer":"C","explanation":"Coverdell ESA contributions are made with after-tax dollars (not tax-deductible). However, earnings grow tax-free, and withdrawals for qualified education expenses are tax-free.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s65p2-037","section":"3 - Trading, Accounts & Prohibited","stem":"An order ticket for a market order would NOT include:","choices":{"A":"The security to be bought or sold","B":"The number of shares","C":"A specific limit price","D":"Whether the order is a buy or sell"},"answer":"C","explanation":"Market orders execute at the best available price, so there is no specific limit price on the order ticket. Limit orders, stop orders, and stop-limit orders include a specified price.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s65p2-040","section":"2 - Products & Risks","stem":"Treasury bills are considered zero-coupon securities because they:","choices":{"A":"Pay interest monthly","B":"Are issued at a discount and mature at par","C":"Have variable interest rates","D":"Pay interest only at maturity"},"answer":"B","explanation":"T-bills are issued at a discount to face value and mature at par. The difference between purchase price and par value represents the investor's return. They do not make periodic interest payments.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s65p2-041","section":"3 - Trading, Accounts & Prohibited","stem":"Municipal bonds are generally NOT recommended for placement in retirement accounts because:","choices":{"A":"They are too risky for retirement portfolios","B":"Their tax-exempt status provides no additional benefit in tax-deferred accounts","C":"They are prohibited by IRS regulations","D":"They have lower yields than corporate bonds"},"answer":"B","explanation":"Municipal bond interest is already federal tax-exempt. Placing them in a tax-deferred account (IRA, 401k) wastes this benefit since all distributions are taxed as ordinary income anyway. It's double inefficient.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s65p2-043","section":"2 - Products & Risks","stem":"An investor purchasing a thinly-traded OTC stock faces the greatest risk of:","choices":{"A":"Inflation risk","B":"Liquidity risk","C":"Currency risk","D":"Reinvestment risk"},"answer":"B","explanation":"Thinly-traded (low volume) OTC stocks have significant liquidity risk - the inability to buy or sell quickly without substantially affecting the price. Wide bid-ask spreads and difficulty exiting positions are common.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s65p2-044","section":"3 - Trading, Accounts & Prohibited","stem":"A limit order guarantees:","choices":{"A":"Execution of the trade","B":"The specified price or better if executed","C":"Immediate execution at any price","D":"Priority over all other orders"},"answer":"B","explanation":"A limit order guarantees the specified price or better IF the order is executed. However, unlike market orders, limit orders do not guarantee execution - the market may never reach the limit price.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s65p2-045","section":"3 - Trading, Accounts & Prohibited","stem":"Once a gift is made to a UGMA/UTMA custodial account, the donor:","choices":{"A":"Can reclaim the gift at any time","B":"Cannot take back the gift; it is irrevocable","C":"Can redirect the gift to another beneficiary","D":"Must wait until the minor turns 18 to reclaim it"},"answer":"B","explanation":"Gifts to UGMA/UTMA accounts are irrevocable. Once contributed, the assets belong to the minor beneficiary. The custodian manages the account but cannot return assets to the donor or redirect them to another person.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s65p3-017","section":"3 - Trading, Accounts & Prohibited","stem":"A customer places a sell stop order at $45. At what price will this order be triggered?","choices":{"A":"Only at exactly $45","B":"At $45 or higher","C":"At $45 or below","D":"At any price different from $45"},"answer":"C","explanation":"A sell stop order is triggered when the market price reaches or falls below the stop price. Once triggered at $45 or below, the order becomes a market order and is executed at the next available price.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s65p3-038","section":"2 - Products & Risks","stem":"The rate at which the Federal Reserve charges member banks for short-term loans is called the:","choices":{"A":"Prime rate","B":"Federal funds rate","C":"Discount rate","D":"LIBOR rate"},"answer":"C","explanation":"The discount rate is the interest rate the Federal Reserve charges member banks for short-term loans made through the discount window. This is different from the federal funds rate, which is the rate banks charge each other for overnight loans.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s66-pv29","section":"2 - Products & Risks","stem":"A high-net-worth client in the highest tax bracket seeks income with preferential tax treatment. Which investment would provide the MOST tax-advantaged income?","choices":{"A":"Corporate bond fund","B":"Money market fund","C":"High-yield bond fund","D":"Municipal bond fund"},"answer":"D","explanation":"Municipal bond funds provide income that is exempt from federal income tax. For high-bracket investors, this tax exemption makes municipal bonds particularly attractive as the after-tax yield may exceed that of taxable alternatives.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s66-pv30","section":"2 - Products & Risks","stem":"Which type of investment income is exempt from federal income taxation?","choices":{"A":"Treasury bond interest","B":"Corporate bond interest","C":"Preferred stock dividends","D":"General obligation municipal bond interest"},"answer":"D","explanation":"Interest from municipal bonds (both general obligation and revenue bonds) is exempt from federal income tax. Treasury interest is exempt from state/local tax but federally taxable. Corporate bonds and preferred dividends are fully taxable.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s66-pv31","section":"3 - Trading, Accounts & Prohibited","stem":"In a variable annuity, if the assumed interest rate (AIR) is 5% and the separate account earns 7% during a payment period, the next payment will:","choices":{"A":"Increase because actual return exceeded AIR","B":"Decrease because AIR was set too low","C":"Stay the same until annual recalculation","D":"Be adjusted only if requested by the annuitant"},"answer":"A","explanation":"In variable annuities, payments increase when the separate account performance exceeds the AIR and decrease when performance is below the AIR. Since 7% actual return exceeds the 5% AIR, the next payment will increase.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s66-pv32","section":"3 - Trading, Accounts & Prohibited","stem":"Under ERISA, a qualified retirement plan may require employees to meet which maximum eligibility requirements before participating?","choices":{"A":"Age 18 and 500 hours of service","B":"Age 25 and 2000 hours of service","C":"Age 21 and 6 months of service","D":"Age 21 and 1 year of service (1,000 hours)"},"answer":"D","explanation":"ERISA permits plans to require employees to reach age 21 and complete 1 year of service (at least 1,000 hours) before becoming eligible. Plans cannot impose stricter requirements than these maximums.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s66-pv36","section":"3 - Trading, Accounts & Prohibited","stem":"Which statement about Coverdell Education Savings Accounts (ESAs) is TRUE?","choices":{"A":"Contributions are tax-deductible at the federal level","B":"There is no income limit for contributors","C":"High-income earners may be phased out from contributing","D":"Funds can only be used for college expenses"},"answer":"C","explanation":"Coverdell ESA contributions are subject to income phaseouts. For single filers, the phaseout begins at $95,000 MAGI; for joint filers at $190,000. High-income earners may be ineligible to contribute directly.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s66-pv37","section":"2 - Products & Risks","stem":"Form CRS (Client Relationship Summary) is designed to provide retail investors with:","choices":{"A":"Detailed fee schedules and expense ratios","B":"A comprehensive list of disciplinary history","C":"Annual performance reports","D":"A brief summary of services, fees, conflicts, and disciplinary information"},"answer":"D","explanation":"Form CRS is a brief relationship summary (maximum 4 pages for dual registrants) that provides retail investors with key information about the nature of the relationship, services offered, fees, conflicts of interest, and disciplinary history in plain language.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s66-pv38","section":"3 - Trading, Accounts & Prohibited","stem":"Assuming equal account values and annuitant age, which variable annuity payout option would provide the HIGHEST monthly payment?","choices":{"A":"Life annuity (straight life)","B":"Life with 10-year period certain","C":"Life with 20-year period certain","D":"Joint and survivor 100%"},"answer":"A","explanation":"A straight life annuity provides the highest payment because it has no guarantees beyond the annuitant's life. Period certain options and survivor benefits reduce payments because the insurer assumes greater risk of paying longer.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s66-pv40","section":"2 - Products & Risks","stem":"An investor concerned about a sustained increase in the Consumer Price Index (CPI) is most worried about:","choices":{"A":"Business risk","B":"Purchasing power risk (inflation risk)","C":"Liquidity risk","D":"Credit risk"},"answer":"B","explanation":"The CPI measures inflation. Rising CPI indicates declining purchasing power of future cash flows. This purchasing power risk (inflation risk) is a systematic risk affecting all investments, particularly fixed-income securities.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s66-pv41","section":"4 - Regulatory Framework","stem":"An agent wishes to open a joint account with a family member who is not in the same household. Which of the following is required?","choices":{"A":"Approval from the state administrator only","B":"Written authorization from the family member only","C":"Verbal approval from the broker-dealer's compliance department","D":"Written authorization from the family member and prior written approval from the broker-dealer"},"answer":"D","explanation":"Opening a joint account with any person requires both written authorization from the other party and prior written approval from the employing broker-dealer. This applies even to family members not in the same household.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s66-pv42","section":"4 - Regulatory Framework","stem":"A company offers securities to 30 sophisticated investors without general solicitation or advertising. This offering would MOST likely:","choices":{"A":"Require full SEC registration","B":"Be prohibited under the Securities Act of 1933","C":"Qualify for a private placement exemption under Regulation D","D":"Require state registration in all 50 states"},"answer":"C","explanation":"This offering meets the criteria for a Regulation D private placement exemption: limited number of purchasers (under 35 non-accredited), sophisticated investors, and no general solicitation. The offering would be exempt from SEC registration.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s66-pv44","section":"2 - Products & Risks","stem":"A 30-year-old client with a high risk tolerance and long time horizon seeks maximum growth. Which recommendation would be LEAST suitable?","choices":{"A":"Small-cap growth fund","B":"Emerging markets equity fund","C":"Aggressive growth portfolio","D":"Conservative income portfolio of bonds and preferred stocks"},"answer":"D","explanation":"A conservative income portfolio focused on bonds and preferred stocks would be least suitable for a young, aggressive investor seeking maximum growth. Such portfolios prioritize income and capital preservation over growth potential.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s66-pv45","section":"2 - Products & Risks","stem":"An investor redeems 1,000 shares of a mutual fund at a NAV of $25.00. If the fund has a 1.5% redemption fee, what is the net proceeds?","choices":{"A":"$24,625","B":"$25,000","C":"$25,375","D":"$26,500"},"answer":"A","explanation":"Gross redemption = 1,000 shares x $25.00 = $25,000. Redemption fee = $25,000 x 1.5% = $375. Net proceeds = $25,000 - $375 = $24,625.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s66-pv46","section":"4 - Regulatory Framework","stem":"Securities acquired through a Regulation D private placement are classified as:","choices":{"A":"Registered securities","B":"Listed securities","C":"Restricted securities","D":"Control securities"},"answer":"C","explanation":"Securities purchased in private placements under Regulation D are restricted securities. They cannot be freely resold without registration or an available exemption (such as Rule 144 after holding period requirements are met).","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s66-pv49","section":"2 - Products & Risks","stem":"A client who believes in active management and market inefficiencies would MOST likely prefer which investment vehicle?","choices":{"A":"S&P 500 index fund","B":"Total market ETF","C":"Actively managed mutual fund","D":"Target-date index fund"},"answer":"C","explanation":"Investors who believe in active management and market inefficiencies prefer actively managed funds where portfolio managers attempt to outperform the market through security selection. Index-based products assume markets are efficient.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-001","section":"2 - Products & Risks","stem":"A registered representative (RR) wants to participate in a private securities transaction. Which of the following actions must the RR take?","choices":{"A":"Request a meeting with his supervisor","B":"Call his supervisor and inform her","C":"Send written notice to his supervisor outlining the activity and compensation structure","D":"Initiate the paperwork required by the policies of the firm once the activity has begun"},"answer":"C","explanation":"Under FINRA Rule 3280 (Private Securities Transactions), also known as \"selling away,\" an RR must provide WRITTEN notice to the member firm BEFORE participating in any private securities transaction. The notice must describe the proposed transaction and the RR's role, including any compensation to be received.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-001a","section":"4 - Regulatory Framework","stem":"Which of the following would be considered \"selling away\" in violation of FINRA rules?","choices":{"A":"An RR selling securities through their firm's normal channels","B":"An RR participating in a private securities transaction without notifying their firm in writing","C":"An RR recommending a mutual fund from their firm's approved list","D":"An RR executing trades on behalf of clients during market hours"},"answer":"B","explanation":"\"Selling away\" refers to an RR participating in private securities transactions outside their firm without proper written notification. This violates FINRA Rule 3280, which requires prior written notice to the member firm.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-002","section":"1 - Capital Markets","stem":"Under Rule 144A, an issuer of restricted stock is permitted to sell to which investors?","choices":{"A":"Financial institutions","B":"Accredited investors","C":"Qualified institutional buyers (QIBs)","D":"Nonaccredited investors who have previously purchased restricted stock"},"answer":"C","explanation":"Rule 144A provides a safe harbor exemption from registration for sales of restricted securities to Qualified Institutional Buyers (QIBs). A QIB is typically an institution that owns and invests at least $100 million in securities.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-002a","section":"2 - Products & Risks","stem":"To qualify as a Qualified Institutional Buyer (QIB) under Rule 144A, an institution must generally own and invest at least:","choices":{"A":"$5 million in securities","B":"$25 million in securities","C":"$100 million in securities","D":"$500 million in securities"},"answer":"C","explanation":"A Qualified Institutional Buyer (QIB) must own and invest on a discretionary basis at least $100 million in securities of unaffiliated issuers. This threshold ensures only sophisticated institutional investors participate in Rule 144A transactions.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-003","section":"2 - Products & Risks","stem":"Under statutory voting, a common stockholder has as many votes for each vacancy as:","choices":{"A":"Positions vacant on the board","B":"Directors present at the meeting","C":"Shares owned by the stockholder","D":"Proxies available for voting"},"answer":"C","explanation":"Under statutory (regular) voting, shareholders receive one vote per share owned for EACH director position. If you own 100 shares and there are 3 positions, you can cast up to 100 votes for each of the 3 positions (but cannot give more than 100 votes to any single candidate).","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-003a","section":"2 - Products & Risks","stem":"Which voting method allows a shareholder to allocate all their votes to a single board candidate?","choices":{"A":"Statutory voting","B":"Cumulative voting","C":"Proxy voting","D":"Preferential voting"},"answer":"B","explanation":"Cumulative voting allows shareholders to multiply their shares by the number of positions being elected and allocate all votes to one candidate. This helps minority shareholders gain board representation.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-004","section":"2 - Products & Risks","stem":"Municipal bond dollar prices and accrued interest computation is on what calendar basis?","choices":{"A":"30/360","B":"30/365","C":"Actual/360","D":"Actual/365"},"answer":"A","explanation":"Municipal bonds use the 30/360 day count convention, meaning each month is treated as having 30 days and each year as having 360 days. This simplifies accrued interest calculations.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-004a","section":"2 - Products & Risks","stem":"Which of the following securities uses the actual/actual day count convention for calculating accrued interest?","choices":{"A":"Municipal bonds","B":"Corporate bonds","C":"Treasury notes","D":"Commercial paper"},"answer":"C","explanation":"U.S. Treasury securities use the actual/actual day count convention, counting the actual number of days in each month and year. This differs from municipal and corporate bonds which use 30/360.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-005","section":"4 - Regulatory Framework","stem":"Under SEC Regulation S-P (Consumer Privacy), what must a firm include in privacy notices?","choices":{"A":"The address of the firm's website","B":"The fee to opt out","C":"The deadline to opt out","D":"The policies to protect security of nonpublic information"},"answer":"D","explanation":"Regulation S-P requires firms to provide clear disclosure of their policies and procedures for protecting the confidentiality and security of consumers' nonpublic personal information.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-005a","section":"4 - Regulatory Framework","stem":"How often must broker-dealers provide privacy notices to customers under Regulation S-P?","choices":{"A":"Monthly","B":"Quarterly","C":"Annually","D":"Only at account opening"},"answer":"C","explanation":"Regulation S-P requires broker-dealers to provide an annual privacy notice to customers, informing them of the firm's privacy policies and their right to opt out of information sharing with nonaffiliated third parties.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-006","section":"4 - Regulatory Framework","stem":"When a broker-dealer charges a commission, it has acted as:","choices":{"A":"An agent","B":"A principal","C":"An underwriter","D":"A market maker"},"answer":"A","explanation":"When a broker-dealer charges a commission, it is acting as an AGENT, facilitating a transaction between buyer and seller without taking ownership of the securities. Agents earn commissions.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-006a","section":"4 - Regulatory Framework","stem":"When a broker-dealer sells securities from its own inventory and charges a markup, it is acting as:","choices":{"A":"An agent","B":"A principal","C":"A fiduciary","D":"A custodian"},"answer":"B","explanation":"When a broker-dealer trades from its own inventory, it acts as a PRINCIPAL (dealer). In this capacity, it charges a markup (on sales) or markdown (on purchases) rather than a commission.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-007","section":"2 - Products & Risks","stem":"Call protection is most valuable when bond prices are:","choices":{"A":"Rising","B":"Falling","C":"Stable","D":"Fluctuating"},"answer":"A","explanation":"Call protection is most valuable when prices are rising (interest rates falling) because issuers are most likely to call bonds to refinance at lower rates. Call protection prevents this, allowing investors to keep their higher-yielding bonds.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-007a","section":"1 - Capital Markets","stem":"An issuer is MOST likely to call its outstanding bonds when:","choices":{"A":"Interest rates have risen significantly","B":"Interest rates have fallen significantly","C":"The issuer's credit rating has been downgraded","D":"The bond is trading at a discount"},"answer":"B","explanation":"Issuers call bonds when interest rates fall significantly because they can refinance the debt at lower rates, reducing their interest expense. This is similar to a homeowner refinancing a mortgage when rates drop.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-008","section":"2 - Products & Risks","stem":"To offer shareholders a privilege to obtain shares at a fixed price, a corporation issues:","choices":{"A":"Puts","B":"Rights","C":"Futures","D":"Preferred stock"},"answer":"B","explanation":"Rights (also called preemptive rights or subscription rights) give existing shareholders the privilege to purchase additional shares at a fixed subscription price, typically below market value, to maintain their proportionate ownership.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-008a","section":"2 - Products & Risks","stem":"What is the typical duration of stock rights before they expire?","choices":{"A":"30 to 45 days","B":"6 months to 1 year","C":"2 to 5 years","D":"10 years or longer"},"answer":"A","explanation":"Stock rights typically have a short lifespan of 30 to 45 days. Shareholders must exercise or sell their rights during this window or they will expire worthless.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-009","section":"2 - Products & Risks","stem":"Company ABC announces a 20% stock dividend. If a customer holds 1,000 shares at $50.00, what is the new price and number of shares?","choices":{"A":"800 shares at $62.50","B":"1,000 shares at $41.67","C":"1,200 shares at $41.67","D":"1,200 shares at $50.00"},"answer":"C","explanation":"A 20% stock dividend means the shareholder receives 20% more shares: 1,000 x 1.20 = 1,200 shares. The total value stays the same ($50,000), so the new price per share is $50,000 / 1,200 = $41.67.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-009a","section":"2 - Products & Risks","stem":"An investor owns 500 shares of XYZ stock at $80 per share. After a 2-for-1 stock split, the investor will have:","choices":{"A":"250 shares at $160","B":"500 shares at $40","C":"1,000 shares at $40","D":"1,000 shares at $80"},"answer":"C","explanation":"In a 2-for-1 split, shares double and price halves. 500 shares become 1,000 shares, and the price drops from $80 to $40. Total value remains $40,000.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-010","section":"2 - Products & Risks","stem":"When a firm receives cash in excess of $10,000 from one customer in one day, what must be filed?","choices":{"A":"A Currency Transaction Report (CTR)","B":"A Suspicious Activity Report (SAR) with the SEC","C":"A cash transfer receipt","D":"A five-day hold notice"},"answer":"A","explanation":"Under the Bank Secrecy Act, a Currency Transaction Report (CTR) must be filed with FinCEN within 15 days when a firm receives cash exceeding $10,000 in a single day from one customer. This is an anti-money laundering requirement.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-010a","section":"4 - Regulatory Framework","stem":"A Suspicious Activity Report (SAR) should be filed when:","choices":{"A":"A customer deposits more than $10,000 in cash","B":"A firm suspects money laundering or other illegal activity","C":"A customer opens a new margin account","D":"A customer makes their first securities purchase"},"answer":"B","explanation":"A SAR must be filed when a firm suspects money laundering, terrorist financing, or other illegal activity. Unlike CTRs, SARs require a judgment that activity is suspicious, not just a dollar threshold.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-011","section":"2 - Products & Risks","stem":"A decline in GDP must last at least how many quarters to be considered a recession?","choices":{"A":"1 quarter","B":"2 quarters","C":"3 quarters","D":"4 quarters"},"answer":"B","explanation":"A recession is commonly defined as two consecutive quarters of negative GDP growth. This rule of thumb is widely used, although the official determination by the NBER considers additional factors.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-011a","section":"2 - Products & Risks","stem":"Which of the following is a leading economic indicator?","choices":{"A":"GDP","B":"Unemployment rate","C":"Building permits","D":"Corporate profits"},"answer":"C","explanation":"Building permits are a leading economic indicator because they predict future construction activity. Leading indicators move BEFORE the economy changes direction.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-012","section":"2 - Products & Risks","stem":"Which statement is true about annuity contracts?","choices":{"A":"Payouts of nonqualified annuity are all tax-free","B":"The kind of annuity selected partly determines the payment amounts","C":"Age and sex of annuitant do not affect payment amounts","D":"Payment amounts are determined solely by the insurance company's investment returns"},"answer":"B","explanation":"The type of annuity selected (life only, life with period certain, joint and survivor, etc.) significantly affects payment amounts. A life-only annuity pays more per period than one with guarantees because the insurer takes on less risk.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-012a","section":"2 - Products & Risks","stem":"Which annuity payout option provides the HIGHEST periodic payment?","choices":{"A":"Life annuity with 20-year period certain","B":"Life-only annuity","C":"Joint and survivor annuity","D":"Life annuity with refund"},"answer":"B","explanation":"A life-only (straight life) annuity provides the highest periodic payment because payments stop at death with no beneficiary payments. The insurer assumes no extra risk of paying beyond the annuitant's life.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-013","section":"2 - Products & Risks","stem":"During low inflation and recession, the Federal Reserve is expected to:","choices":{"A":"Decrease taxes","B":"Raise the federal funds rate","C":"Buy bonds in the open market","D":"Require banks to increase reserves"},"answer":"C","explanation":"During recession with low inflation, the Fed implements expansionary monetary policy by buying bonds in the open market. This injects money into the economy, lowering interest rates and stimulating borrowing and spending.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-013a","section":"2 - Products & Risks","stem":"To combat rising inflation, the Federal Reserve would most likely:","choices":{"A":"Lower the discount rate","B":"Sell securities in open market operations","C":"Decrease the federal funds rate target","D":"Lower reserve requirements for banks"},"answer":"B","explanation":"To fight inflation, the Fed implements contractionary policy by selling securities. This removes money from circulation, raising interest rates and slowing economic activity.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-014","section":"2 - Products & Risks","stem":"Which investments are traded according to average life rather than maturity dates?","choices":{"A":"Corporate bonds","B":"Government bonds","C":"Asset-backed securities","D":"Fixed-rate capital securities"},"answer":"C","explanation":"Asset-backed securities (ABS), including mortgage-backed securities, are quoted based on average life rather than stated maturity because the underlying loans can be prepaid at any time, making the actual cash flow timing uncertain.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-014a","section":"2 - Products & Risks","stem":"Prepayment risk is MOST associated with which type of security?","choices":{"A":"Treasury bills","B":"Corporate debentures","C":"Mortgage-backed securities","D":"Municipal general obligation bonds"},"answer":"C","explanation":"Mortgage-backed securities (MBS) have significant prepayment risk because homeowners can pay off mortgages early, especially when interest rates fall. This forces investors to reinvest at lower rates.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-015","section":"4 - Regulatory Framework","stem":"Which Form U4 reportable event results in statutory disqualification?","choices":{"A":"A personal bankruptcy filing","B":"A written customer complaint alleging misappropriation","C":"A felony theft charge","D":"A felony conviction for DUI"},"answer":"C","explanation":"A felony CHARGE (not just conviction) involving theft, dishonesty, or securities-related misconduct can result in statutory disqualification. Theft is a crime involving dishonesty and moral turpitude.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-015a","section":"4 - Regulatory Framework","stem":"Which of the following must be disclosed on Form U4?","choices":{"A":"A traffic violation resulting in a fine","B":"An investment-related customer complaint settled for $25,000","C":"A misdemeanor for jaywalking","D":"A verbal warning from a supervisor"},"answer":"B","explanation":"An investment-related customer-initiated complaint, arbitration, or civil litigation alleging sales-practice violations that is settled for $15,000 or more must be disclosed on Form U4 (threshold raised from $10,000 to $15,000, effective May 18, 2009). A $25,000 settlement exceeds that threshold and is reportable.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-016","section":"2 - Products & Risks","stem":"All of the following risks apply to both foreign and domestic debt EXCEPT:","choices":{"A":"Political risk","B":"Exchange rate risk","C":"Repayment (credit) risk","D":"Interest rate risk"},"answer":"B","explanation":"Exchange rate (currency) risk is unique to foreign investments. Domestic debt is denominated in the home currency, so there's no exchange rate risk. Foreign debt involves converting payments between currencies.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-016a","section":"2 - Products & Risks","stem":"Currency risk is a concern for investors holding:","choices":{"A":"U.S. Treasury bonds","B":"Domestic corporate bonds","C":"American Depositary Receipts (ADRs)","D":"Municipal bonds"},"answer":"C","explanation":"ADRs represent foreign stocks and involve currency risk because the underlying shares are denominated in a foreign currency. Changes in exchange rates affect ADR values.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-017","section":"3 - Trading, Accounts & Prohibited","stem":"Upon expiration, in-the-money S&P 100 Index call options are settled by:","choices":{"A":"Cash","B":"S&P 100 Index stocks","C":"S&P 100 ETF shares","D":"Same number of put options"},"answer":"A","explanation":"Index options are cash-settled because delivering all the underlying stocks would be impractical. The holder receives the cash difference between the index level and the strike price.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-017a","section":"2 - Products & Risks","stem":"Which options are typically settled by physical delivery of the underlying security?","choices":{"A":"S&P 500 Index options","B":"VIX options","C":"Equity options on individual stocks","D":"Currency index options"},"answer":"C","explanation":"Equity options on individual stocks are settled by physical delivery - the buyer receives (calls) or delivers (puts) 100 shares of the underlying stock. Index options use cash settlement.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-018","section":"2 - Products & Risks","stem":"XYZ 5.50s 2030 last traded at 102. This bond is selling at:","choices":{"A":"Par","B":"A premium","C":"A discount","D":"Asset value"},"answer":"B","explanation":"A price of 102 means 102% of par value ($1,020 for a $1,000 bond). Since this exceeds par (100), the bond is trading at a PREMIUM. This occurs when the coupon rate exceeds current market rates.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-018a","section":"2 - Products & Risks","stem":"A bond with a 4% coupon is trading at 95. This bond is selling at:","choices":{"A":"Par","B":"A premium","C":"A discount","D":"Net asset value"},"answer":"C","explanation":"A price of 95 means 95% of par value ($950 for a $1,000 bond). Since this is below par (100), the bond trades at a DISCOUNT. This occurs when market rates exceed the coupon rate.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-019","section":"3 - Trading, Accounts & Prohibited","stem":"When recommending a 529 education savings plan, what should be explained to the customer?","choices":{"A":"Potential deductibility from state taxes","B":"Potential deductibility from federal taxes","C":"Income eligibility restrictions","D":"Rights of beneficiary at age of majority"},"answer":"A","explanation":"529 plan contributions may be deductible for STATE income tax purposes in many states. There is no federal tax deduction for 529 contributions, but qualified withdrawals are tax-free.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-019a","section":"3 - Trading, Accounts & Prohibited","stem":"Which of the following is TRUE about 529 education savings plans?","choices":{"A":"Contributions are tax-deductible at the federal level","B":"There are income limits for contributors","C":"Qualified withdrawals for education are tax-free","D":"The beneficiary controls the account at age 18"},"answer":"C","explanation":"Qualified distributions from 529 plans for education expenses (tuition, room, board, books) are completely tax-free at the federal level and usually at the state level.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-020","section":"2 - Products & Risks","stem":"An advantage of index funds is:","choices":{"A":"Protection of principal in bearish markets","B":"High portfolio turnover","C":"Higher management fees due to active management","D":"Lower management fees due to passive management"},"answer":"D","explanation":"Index funds use passive management, simply tracking an index rather than actively selecting securities. This results in lower management fees (expense ratios) compared to actively managed funds.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-020a","section":"2 - Products & Risks","stem":"Which characteristic is typically associated with actively managed mutual funds compared to index funds?","choices":{"A":"Lower expense ratios","B":"Higher expense ratios","C":"Lower portfolio turnover","D":"Guaranteed outperformance of the benchmark"},"answer":"B","explanation":"Actively managed funds have higher expense ratios because they employ portfolio managers and analysts to research and select securities. Index funds simply track an index with minimal management.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-021","section":"3 - Trading, Accounts & Prohibited","stem":"An initial purchase of $3,000 of stock in a margin account requires a cash deposit of:","choices":{"A":"$750","B":"$1,500","C":"$2,000","D":"$3,000"},"answer":"C","explanation":"Regulation T requires 50% initial margin, but FINRA also requires a minimum of $2,000 (or the full purchase price if less than $2,000). For a $3,000 purchase, 50% = $1,500, but the $2,000 minimum applies, so $2,000 is required.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-021a","section":"4 - Regulatory Framework","stem":"Regulation T requires what percentage for the initial purchase of marginable securities?","choices":{"A":"25%","B":"50%","C":"75%","D":"100%"},"answer":"B","explanation":"Regulation T, set by the Federal Reserve, requires an initial margin of 50% for the purchase of marginable securities. The customer must deposit at least half the purchase price.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-022","section":"2 - Products & Risks","stem":"Which security has a stated maturity, floating interest rate, and an option for the investor to put it back daily or weekly?","choices":{"A":"Equity put option","B":"Perpetual preferred stock","C":"Variable rate demand note (VRDN)","D":"Tax-deferred variable annuity"},"answer":"C","explanation":"Variable Rate Demand Notes (VRDNs) are municipal securities with floating rates that reset frequently and include a put feature allowing investors to tender (put back) the notes daily or weekly at par.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-022a","section":"2 - Products & Risks","stem":"What type of municipal security is commonly held by money market funds due to its liquidity features?","choices":{"A":"General obligation bonds","B":"Revenue bonds","C":"Variable rate demand notes (VRDNs)","D":"Industrial development bonds"},"answer":"C","explanation":"VRDNs are popular in municipal money market funds because their put feature provides daily/weekly liquidity, and floating rates mean minimal interest rate risk. They effectively trade like short-term instruments.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-023a","section":"3 - Trading, Accounts & Prohibited","stem":"Regular way settlement for corporate securities is:","choices":{"A":"Same day","B":"T+1","C":"T+2","D":"T+3"},"answer":"B","explanation":"As of May 28, 2024, regular way settlement for corporate securities (stocks and bonds) is T+1 (one business day after the trade date). The SEC shortened the cycle from T+2 to T+1 under amended Rule 15c6-1.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-024","section":"2 - Products & Risks","stem":"The redemption value of open-end investment company shares is based on:","choices":{"A":"Previous offering price","B":"Previous closing NAV","C":"NAV computed after the order is received (forward pricing)","D":"Offering price computed after the order is received"},"answer":"C","explanation":"Open-end funds use forward pricing - shares are redeemed at the NAV calculated at the close of business AFTER the order is received. This ensures all investors receive the same price on a given day.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-024a","section":"3 - Trading, Accounts & Prohibited","stem":"An investor places a mutual fund purchase order at 2:00 PM Eastern. At what price will the purchase be executed?","choices":{"A":"The previous day's closing NAV","B":"The NAV at 2:00 PM when the order was placed","C":"The NAV calculated at 4:00 PM that day","D":"The NAV at market open the next day"},"answer":"C","explanation":"Under forward pricing rules, mutual fund orders placed before 4:00 PM Eastern are executed at that day's closing NAV (calculated at 4:00 PM). Orders after 4:00 PM get the next day's NAV.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-025","section":"2 - Products & Risks","stem":"When selling base currency for counter currency, what determines the amount received?","choices":{"A":"The spot exchange rate","B":"The counter currency's inflation rate","C":"The trade balance","D":"The credit rating of counter currency's government"},"answer":"A","explanation":"The spot exchange rate determines the immediate conversion rate between currencies. It represents the current market price for exchanging one currency for another.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra-025a","section":"2 - Products & Risks","stem":"Which of the following would cause the U.S. dollar to strengthen against foreign currencies?","choices":{"A":"Decreasing U.S. interest rates","B":"Increasing U.S. interest rates","C":"Increasing U.S. trade deficits","D":"Decreasing demand for U.S. goods abroad"},"answer":"B","explanation":"Higher U.S. interest rates attract foreign investment seeking better returns. This increases demand for dollars, strengthening the currency. Capital flows toward higher yields.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-001","section":"2 - Products & Risks","stem":"A municipal finance professional contributed $200 to a mayor's campaign 13 months ago. To support the mayor further without impacting the firm's ability to do business with the municipality, the MFP can contribute up to:","choices":{"A":"$50","B":"$100","C":"$150","D":"$250"},"answer":"D","explanation":"Under MSRB Rule G-37, municipal finance professionals may contribute up to $250 per election to officials for whom they are entitled to vote without triggering the two-year ban on municipal securities business. Since this is a de minimis contribution and the MFP can vote for the mayor, the $250 limit applies.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-002","section":"4 - Regulatory Framework","stem":"Under MSRB Rule G-37, a municipal finance professional who contributes more than $250 to an official of a municipality will trigger a ban on municipal securities business with that municipality for:","choices":{"A":"6 months","B":"1 year","C":"2 years","D":"5 years"},"answer":"C","explanation":"MSRB Rule G-37 imposes a two-year ban on municipal securities business with a municipality if an MFP contributes more than $250 to an official of that municipality. This \"pay-to-play\" rule is designed to prevent quid pro quo arrangements in municipal finance.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-003","section":"4 - Regulatory Framework","stem":"Which of the following is a required component of a broker-dealer's Anti-Money Laundering (AML) program?","choices":{"A":"Designating an AML compliance officer","B":"Filing the AML program with FINRA","C":"Conducting criminal background checks on all employees","D":"Identifying employees responsible for CTRs to regulators"},"answer":"A","explanation":"Under the Bank Secrecy Act and USA PATRIOT Act, every broker-dealer must have an AML program that includes: (1) internal policies and procedures, (2) designation of a compliance officer, (3) ongoing employee training, and (4) independent testing of the program. The program does not need to be filed with FINRA.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-004","section":"4 - Regulatory Framework","stem":"A broker-dealer's AML program must include all of the following EXCEPT:","choices":{"A":"Written internal policies and procedures","B":"A designated AML compliance officer","C":"Independent testing of the AML program","D":"Monthly reports to FinCEN"},"answer":"D","explanation":"An AML program must include written policies/procedures, a designated compliance officer, ongoing training, and independent testing. There is no requirement for monthly reports to FinCEN, though Suspicious Activity Reports (SARs) must be filed when suspicious activity is detected.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-005","section":"2 - Products & Risks","stem":"What is the effect of a forward stock split on an investor's holdings?","choices":{"A":"Price per share increases","B":"Price per share decreases","C":"Each stockholder's proportionate ownership decreases","D":"Each stockholder's proportionate ownership increases"},"answer":"B","explanation":"In a forward stock split, the number of shares increases and the price per share decreases proportionally. For example, in a 2-for-1 split, an investor with 100 shares at $50 would have 200 shares at $25. The total value and proportionate ownership remain the same.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-006","section":"2 - Products & Risks","stem":"After a 3-for-1 stock split, an investor who owned 100 shares at $90 per share will have:","choices":{"A":"300 shares at $90 per share","B":"300 shares at $30 per share","C":"100 shares at $30 per share","D":"33 shares at $270 per share"},"answer":"B","explanation":"In a 3-for-1 stock split, the number of shares triples and the price is divided by 3. The investor would have 300 shares (100 x 3) at $30 per share ($90 / 3). The total value remains $9,000 before and after the split.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-007","section":"4 - Regulatory Framework","stem":"Under Regulation T, when is a 90-day freeze imposed on a customer's cash account?","choices":{"A":"When the customer buys and sells the same stock on the same day in a margin account","B":"When the customer buys the same stock in different accounts on the same day","C":"When family members buy the same stock on the same day","D":"When the customer sells securities in a cash account before paying for them in full"},"answer":"D","explanation":"Freeriding occurs when a customer buys securities in a cash account, sells them before paying for them, and uses the sale proceeds to pay for the original purchase. This violates Regulation T and results in a 90-day freeze requiring the customer to have cash in the account before placing trades.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-008","section":"3 - Trading, Accounts & Prohibited","stem":"A customer buys $10,000 of stock in a cash account on Monday, sells it on Wednesday for $11,000, and uses the proceeds to pay for the original purchase. This practice is known as:","choices":{"A":"Day trading","B":"Freeriding","C":"Churning","D":"Front running"},"answer":"B","explanation":"This is freeriding - buying securities in a cash account and selling them before paying for them in full, using the sale proceeds to cover the purchase. Freeriding violates Regulation T and results in a 90-day freeze on the account, requiring funds to be deposited before placing future trades.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-009","section":"2 - Products & Risks","stem":"An associated person who is NOT a registered representative may perform which of the following activities?","choices":{"A":"Accept an unsolicited customer order","B":"Provide account opening forms to a new customer","C":"Discuss the features of an investment product","D":"Prequalify customers regarding investment objectives"},"answer":"B","explanation":"An unregistered associated person may perform only clerical functions such as providing account opening forms. Accepting orders, discussing investment products, and prequalifying customers are all activities that require registration as a representative.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-010","section":"4 - Regulatory Framework","stem":"Which of the following activities requires registration as a representative?","choices":{"A":"Distributing marketing materials approved by the firm","B":"Scheduling appointments for a registered representative","C":"Recommending securities to customers","D":"Processing customer address changes"},"answer":"C","explanation":"Making securities recommendations to customers is a registered representative function that requires passing appropriate qualification exams. Administrative tasks like distributing approved materials, scheduling appointments, and processing address changes are clerical functions that do not require registration.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-011","section":"1 - Capital Markets","stem":"Which of the following investment products would be most adversely impacted if the issuer's credit rating is downgraded?","choices":{"A":"Mutual funds","B":"Unit Investment Trusts (UITs)","C":"Exchange-Traded Funds (ETFs)","D":"Exchange-Traded Notes (ETNs)"},"answer":"D","explanation":"ETNs are unsecured debt obligations of the issuer, meaning investors are exposed to the issuer's credit risk. If the issuer's credit rating is downgraded, the value of the ETN will likely decline. Mutual funds, UITs, and ETFs hold baskets of securities and are not directly impacted by the credit rating of the fund company.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-012","section":"2 - Products & Risks","stem":"What is the primary difference between an ETF and an ETN?","choices":{"A":"ETFs trade on exchanges while ETNs do not","B":"ETNs are unsecured debt of the issuer while ETFs hold actual securities","C":"ETFs have maturity dates while ETNs do not","D":"ETNs pay dividends while ETFs do not"},"answer":"B","explanation":"The key difference is that ETNs are unsecured debt obligations of the issuing bank, exposing investors to credit risk. ETFs actually hold a portfolio of underlying securities. Both trade on exchanges. ETNs have maturity dates while ETFs do not.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-013","section":"1 - Capital Markets","stem":"An exchange member that provides liquidity by continuously buying and selling securities at quoted prices is known as:","choices":{"A":"A broker","B":"An underwriter","C":"A market maker","D":"A transfer agent"},"answer":"C","explanation":"Market makers provide liquidity by standing ready to buy and sell securities at publicly quoted bid and ask prices. They profit from the spread between these prices. Brokers execute trades for customers, underwriters sell new issues, and transfer agents maintain ownership records.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-014","section":"2 - Products & Risks","stem":"How do market makers earn their profit?","choices":{"A":"By charging commissions on customer trades","B":"By earning the spread between bid and ask prices","C":"By receiving fees from exchanges for providing liquidity","D":"By earning interest on customer cash balances"},"answer":"B","explanation":"Market makers profit from the bid-ask spread - buying at the bid price and selling at the higher ask price. They do not charge commissions (that's how brokers earn money). While some exchanges offer rebates for providing liquidity, the primary profit source is the spread.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-015","section":"2 - Products & Risks","stem":"No-load mutual funds may have lower expense ratios because:","choices":{"A":"No-load funds do not charge any 12b-1 fees","B":"No-load funds cannot charge 12b-1 fees greater than 0.25%","C":"Sales charges are included in expense ratios","D":"No-load funds always have lower management fees"},"answer":"B","explanation":"To be classified as a no-load fund, 12b-1 fees cannot exceed 0.25% (25 basis points). Funds with higher 12b-1 fees must be classified as load funds. No-load funds can still charge 12b-1 fees, just not more than 25 bps. Sales charges are not part of expense ratios.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-016","section":"2 - Products & Risks","stem":"What is the maximum 12b-1 fee a mutual fund can charge and still be classified as \"no-load\"?","choices":{"A":"0.00%","B":"0.25%","C":"0.50%","D":"1.00%"},"answer":"B","explanation":"Under SEC rules, a fund may be called \"no-load\" only if it has no front-end or back-end sales charges and its 12b-1 fee does not exceed 0.25% (25 basis points). A fund with higher 12b-1 fees cannot market itself as no-load.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-017","section":"4 - Regulatory Framework","stem":"Which of the following actions violates FINRA rules regarding private securities transactions (selling away)?","choices":{"A":"Recommending another broker-dealer's services to a customer","B":"Sharing commissions with another registered representative at the same firm","C":"Advising customers to purchase just below a breakpoint discount level","D":"Engaging in private securities transactions without the firm's written consent"},"answer":"D","explanation":"Selling away occurs when a registered representative engages in securities transactions outside the scope of their employment without written approval from their firm. This violates FINRA Rule 3280. Representatives must notify their firm and receive written permission before engaging in any private securities transactions.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-018","section":"4 - Regulatory Framework","stem":"A registered representative wants to sell promissory notes issued by a family member's business to clients. Under FINRA rules, the representative must:","choices":{"A":"Proceed since family transactions are exempt","B":"Provide written notice to and receive written approval from their firm","C":"File a Form U4 amendment with FINRA","D":"Register as an investment adviser"},"answer":"B","explanation":"Private securities transactions (selling away) require written notice to the member firm. If the representative will receive compensation, the firm must approve the transaction in writing and supervise it as if done through the firm. This applies regardless of family relationships.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-020","section":"2 - Products & Risks","stem":"Which of the following is NOT a money market instrument?","choices":{"A":"Treasury bills","B":"Commercial paper","C":"Treasury bonds","D":"Banker's acceptances"},"answer":"C","explanation":"Treasury bonds have maturities of 20-30 years, making them long-term instruments rather than money market instruments. Money market instruments mature in one year or less and include T-bills (up to 52 weeks), commercial paper (up to 270 days), and banker's acceptances (up to 180 days).","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-021","section":"2 - Products & Risks","stem":"A letter of intent for mutual fund purchases to receive breakpoint discounts is valid for a maximum of:","choices":{"A":"3 months","B":"6 months","C":"13 months","D":"24 months"},"answer":"C","explanation":"A letter of intent (LOI) allows an investor to receive breakpoint discounts on mutual fund purchases over a 13-month period. The investor signs the LOI agreeing to invest a specified amount, and all purchases within 13 months count toward the breakpoint. The LOI can be backdated 90 days.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-022","section":"2 - Products & Risks","stem":"An investor signs a letter of intent (LOI) to invest $50,000 in a mutual fund. After 10 months, the investor has invested only $30,000. What happens?","choices":{"A":"The LOI is automatically extended for another 13 months","B":"The investor must immediately invest the remaining $20,000","C":"The investor loses the breakpoint discount and pays a higher sales charge on shares already purchased","D":"Nothing happens - the LOI is non-binding"},"answer":"C","explanation":"A letter of intent is binding. If the investor fails to meet the commitment within 13 months, shares held in escrow are liquidated to pay the higher sales charge that should have been charged. The investor received a discount based on the expected $50,000 but only invested $30,000.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-023","section":"3 - Trading, Accounts & Prohibited","stem":"A customer buys 100 shares of ABC stock at $35 and also purchases 1 ABC Jan 35 put for $3. What is the customer's break-even point at expiration?","choices":{"A":"$3","B":"$32","C":"$35","D":"$38"},"answer":"D","explanation":"In a protective put (married put) position, the break-even is the stock purchase price plus the put premium paid. The customer paid $35 for the stock plus $3 for the put, so the stock must rise to $38 to break even. The put protects against losses below $35 but costs $3.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-024","section":"2 - Products & Risks","stem":"An investor owns 100 shares of XYZ at $50 and buys a put with a $50 strike price for $4. What is the maximum loss on this position?","choices":{"A":"$400","B":"$4,600","C":"$5,000","D":"Unlimited"},"answer":"A","explanation":"In a protective put, the maximum loss is limited to the premium paid for the put. The put guarantees the ability to sell at $50, so even if the stock goes to zero, the investor loses only the $4 premium ($400 total). This is the benefit of a protective put - it limits downside risk.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-025","section":"2 - Products & Risks","stem":"Interest on U.S. Treasury notes is paid:","choices":{"A":"Quarterly","B":"Semiannually","C":"Annually","D":"At maturity"},"answer":"B","explanation":"Treasury notes (and Treasury bonds) pay interest semiannually (every 6 months). Treasury bills do not pay periodic interest - they are sold at a discount and mature at face value. The semiannual payment is standard for most U.S. government and corporate bonds.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-026","section":"2 - Products & Risks","stem":"Which U.S. Treasury security does NOT pay periodic interest?","choices":{"A":"Treasury notes","B":"Treasury bonds","C":"Treasury bills","D":"TIPS (Treasury Inflation-Protected Securities)"},"answer":"C","explanation":"Treasury bills (T-bills) are sold at a discount to face value and do not pay periodic interest. The investor's return is the difference between the discounted purchase price and the face value at maturity. T-notes, T-bonds, and TIPS all pay semiannual interest.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-027","section":"2 - Products & Risks","stem":"A portfolio consists of 30% Energy stocks, 30% Health Care stocks, 30% S&P 500 ETF, and 10% Money Market. What type of risk is most inherent in this portfolio?","choices":{"A":"Credit risk","B":"Liquidity risk","C":"Political risk","D":"Nonsystematic risk"},"answer":"D","explanation":"This portfolio has significant sector concentration (60% in just two sectors), which exposes it to nonsystematic (unsystematic) risk. Nonsystematic risk is company-specific or sector-specific risk that can be reduced through diversification. A well-diversified portfolio across many sectors would have less nonsystematic risk.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-028","section":"2 - Products & Risks","stem":"Which type of risk can be reduced through portfolio diversification?","choices":{"A":"Market risk","B":"Systematic risk","C":"Unsystematic risk","D":"Interest rate risk"},"answer":"C","explanation":"Unsystematic risk (also called nonsystematic or diversifiable risk) is specific to individual companies or sectors and can be reduced through diversification. Systematic risk (market risk, interest rate risk) affects the entire market and cannot be diversified away.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-029","section":"4 - Regulatory Framework","stem":"Under FINRA rules, a registered representative must provide written notification to their firm for which of the following activities?","choices":{"A":"Volunteering as a soccer coach","B":"Winning $10,000 gambling","C":"Driving part-time for a rideshare company","D":"Selling the firm's proprietary products"},"answer":"C","explanation":"FINRA Rule 3270 requires registered representatives to provide written notice of any outside business activity for which they receive compensation. Driving for a rideshare company is compensated outside employment requiring notification. Volunteer work without compensation does not require notification.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-030","section":"4 - Regulatory Framework","stem":"A registered representative wants to work part-time as a real estate agent on weekends. What must the representative do under FINRA rules?","choices":{"A":"Nothing - real estate is exempt from outside business activity rules","B":"Provide written notice to the member firm prior to engaging in the activity","C":"Resign from the broker-dealer before starting","D":"File a Form U5 with FINRA"},"answer":"B","explanation":"Working as a real estate agent is an outside business activity requiring prior written notice to the member firm under FINRA Rule 3270. The firm may approve, disapprove, or place conditions on the activity. There is no exemption for real estate or any other profession.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-031","section":"3 - Trading, Accounts & Prohibited","stem":"At issuance, which of the following securities normally has the longest time to expiration?","choices":{"A":"Rights","B":"Options","C":"Warrants","D":"Repurchase agreements"},"answer":"C","explanation":"Warrants typically have the longest expiration periods, often 5-10 years or even perpetual. Rights usually expire in 30-45 days. Exchange-traded options have expirations from 1 week to 3 years, with most being less than 1 year. Repurchase agreements are typically very short-term (overnight to a few weeks).","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-032","section":"2 - Products & Risks","stem":"Stock rights issued by a corporation typically expire within:","choices":{"A":"30-45 days","B":"6 months","C":"1-2 years","D":"5-10 years"},"answer":"A","explanation":"Stock rights (preemptive rights) typically have short expiration periods of 30-45 days. They allow existing shareholders to purchase new shares in proportion to their holdings before the public offering. Due to their short life, rights must be exercised or sold quickly.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-033","section":"4 - Regulatory Framework","stem":"Which of the following communications would be considered misleading under FINRA rules?","choices":{"A":"Historical illustrations based on actual past performance","B":"Product comparisons that highlight material differences","C":"A research report with a buy recommendation based on fundamental analysis","D":"Using 10-year performance history to predict future results"},"answer":"D","explanation":"Using past performance to predict future results is misleading because past performance is not indicative of future results. FINRA prohibits communications that imply future performance can be predicted from historical data. Factual historical illustrations, product comparisons, and research recommendations based on analysis are permitted.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-034","section":"4 - Regulatory Framework","stem":"A broker-dealer's advertisement states: \"Our fund has returned 12% annually for the past 5 years and will continue this performance.\" This advertisement is:","choices":{"A":"Permitted because it is based on actual performance","B":"Permitted if approved by a principal","C":"Prohibited because it guarantees future performance","D":"Prohibited unless filed with FINRA"},"answer":"C","explanation":"Stating that past performance \"will continue\" is a guarantee of future performance, which is prohibited. Communications must not predict or imply that past performance will continue. While the historical 12% return is factual, promising its continuation is misleading and violates FINRA rules.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-035","section":"2 - Products & Risks","stem":"A company announces a tender offer to purchase a maximum of 1 million shares at $10 per share, with no minimum. If 900,000 shares are tendered and an investor tenders 1,000 shares, how many shares will be purchased from the investor?","choices":{"A":"0","B":"100","C":"900","D":"1,000"},"answer":"D","explanation":"Since only 900,000 shares were tendered (less than the 1 million share maximum), all tendered shares will be purchased. The investor's 1,000 shares will be fully purchased at $10 per share. If more than 1 million shares had been tendered, shares would be purchased on a pro-rata basis.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-036","section":"2 - Products & Risks","stem":"A company makes a tender offer for 500,000 shares at $25. If 750,000 shares are tendered, how will the company handle the over-subscription?","choices":{"A":"Purchase all 750,000 shares","B":"Purchase shares on a first-come, first-served basis","C":"Purchase shares on a pro-rata basis from all tendering shareholders","D":"Cancel the tender offer entirely"},"answer":"C","explanation":"When a tender offer is oversubscribed, shares are purchased on a pro-rata basis from all shareholders who tendered. In this case, 500,000/750,000 = 66.7% of each shareholder's tendered shares would be purchased. This ensures fair treatment of all tendering shareholders.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-037","section":"2 - Products & Risks","stem":"What is the primary purpose of the syndicate desk in an equity offering?","choices":{"A":"To determine the list of selling shareholders","B":"To build the order book and allocate stock","C":"To solicit interest from potential investors","D":"To chaperone management during the road show"},"answer":"B","explanation":"The syndicate desk is responsible for building the book of orders (book building) and allocating shares to investors in a new equity offering. Soliciting interest is done by the sales force during the road show. The syndicate desk manages the overall demand and determines allocations.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-038","section":"3 - Trading, Accounts & Prohibited","stem":"During an IPO, the process of collecting investor orders to determine demand and pricing is called:","choices":{"A":"Market making","B":"Stabilization","C":"Book building","D":"Underwriting"},"answer":"C","explanation":"Book building is the process where underwriters collect indications of interest and orders from institutional investors to gauge demand and help set the offering price. This is managed by the syndicate desk. It helps determine both the offering price and how shares will be allocated.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-039","section":"2 - Products & Risks","stem":"A firm agrees to repurchase securities from customers at no less than the original purchase price. Such agreements are:","choices":{"A":"Prohibited as fraudulent and manipulative","B":"Permissible if the securities are held in escrow","C":"Prohibited unless funds are set aside in reserve","D":"Permissible if customers can also sell to the market"},"answer":"A","explanation":"Agreements to repurchase securities at no less than the original price are prohibited as they constitute a guarantee against loss, which is fraudulent and manipulative. Such guarantees artificially induce customers to purchase securities by eliminating risk, which distorts the market.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-040","section":"2 - Products & Risks","stem":"A registered representative tells a customer, \"If the stock goes down, I'll personally make up the difference.\" This statement is:","choices":{"A":"Permitted as good customer service","B":"Permitted if documented in writing","C":"Prohibited as sharing in customer losses","D":"Prohibited unless approved by the firm"},"answer":"C","explanation":"Guaranteeing customers against loss or promising to make up losses is strictly prohibited under FINRA rules. This includes sharing in customer losses. Such promises are fraudulent and manipulative, distorting the customer's perception of investment risk.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-041","section":"2 - Products & Risks","stem":"What is the greatest investment risk associated with variable life insurance?","choices":{"A":"Credit risk","B":"Market risk","C":"Inflation risk","D":"Interest rate risk"},"answer":"B","explanation":"Variable life insurance invests the cash value in separate accounts (similar to mutual funds). The cash value and potentially the death benefit fluctuate based on investment performance. Market risk is the primary concern because poor investment performance can reduce the cash value and may require additional premium payments.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-042","section":"2 - Products & Risks","stem":"In a variable life insurance policy, the cash value is invested in:","choices":{"A":"The insurance company's general account","B":"Separate accounts chosen by the policyholder","C":"U.S. Treasury securities only","D":"Fixed-rate savings accounts"},"answer":"B","explanation":"Variable life insurance cash values are invested in separate accounts (subaccounts) selected by the policyholder, similar to mutual fund options. This differs from whole life insurance, where cash values are invested in the insurer's general account. The separate accounts bear investment risk.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-043","section":"4 - Regulatory Framework","stem":"Under which circumstance may an employee trade securities without violating insider trading laws?","choices":{"A":"An independent analyst explains why earnings could be lower than expected","B":"A neighbor who works in government shares information about a contract award","C":"A spouse shares an overheard conversation about a potential acquisition","D":"A coworker shares inside information about a pending class action lawsuit"},"answer":"A","explanation":"An analyst's opinion based on publicly available information and professional judgment is not inside information. Trading based on analyst research is legal. The other scenarios involve material nonpublic information received from insiders or through misappropriation, which would violate insider trading laws.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-044","section":"2 - Products & Risks","stem":"Material nonpublic information includes all of the following EXCEPT:","choices":{"A":"Upcoming earnings announcements","B":"Pending merger negotiations","C":"Published analyst recommendations","D":"Undisclosed regulatory investigations"},"answer":"C","explanation":"Published analyst recommendations are public information, not material nonpublic information. Analysts base recommendations on public data and professional judgment. Upcoming earnings, pending mergers, and undisclosed investigations are material nonpublic information that insiders cannot trade on.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-045","section":"2 - Products & Risks","stem":"A market maker posts a quote of 10.00 - 10.10 [25x10]. What is the market maker willing to do?","choices":{"A":"Sell 1,000 shares at $10.00 and buy 2,500 shares at $10.10","B":"Buy 2,500 shares at $10.00 and sell 1,000 shares at $10.10","C":"Sell 100 shares at $10.00 and buy 250 shares at $10.10","D":"Buy 250 shares at $10.00 and sell 100 shares at $10.10"},"answer":"B","explanation":"In a market maker quote, the first number is the bid (price to buy), the second is the ask (price to sell). The bracketed numbers indicate size in round lots (100 shares). So 25x10 means 25 round lots (2,500 shares) on the bid at $10.00 and 10 round lots (1,000 shares) on the ask at $10.10.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-046","section":"2 - Products & Risks","stem":"If a stock is quoted at 45.50 - 45.75, the bid-ask spread is:","choices":{"A":"$0.10","B":"$0.25","C":"$0.50","D":"$45.625"},"answer":"B","explanation":"The bid-ask spread is the difference between the ask price (what you pay to buy) and the bid price (what you receive when selling). In this case, $45.75 - $45.50 = $0.25. The spread represents the market maker's profit on a round-trip transaction.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-047","section":"3 - Trading, Accounts & Prohibited","stem":"A savings account at a bank is guaranteed by:","choices":{"A":"FDIC","B":"SIPC","C":"Federal Reserve","D":"Department of Treasury"},"answer":"A","explanation":"The Federal Deposit Insurance Corporation (FDIC) insures bank deposits including savings accounts, checking accounts, CDs, and money market deposit accounts up to $250,000 per depositor, per bank. SIPC protects securities at broker-dealers, not bank deposits.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-048","section":"2 - Products & Risks","stem":"What is the current FDIC insurance coverage limit per depositor, per bank?","choices":{"A":"$100,000","B":"$250,000","C":"$500,000","D":"$1,000,000"},"answer":"B","explanation":"The FDIC insures deposits up to $250,000 per depositor, per insured bank, per ownership category. This limit was permanently increased from $100,000 in 2010. Joint accounts and retirement accounts may provide additional coverage under different ownership categories.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-049","section":"4 - Regulatory Framework","stem":"A registered representative placing a mutual fund advertisement must receive written approval from:","choices":{"A":"FINRA","B":"Each state's securities administrator","C":"A registered principal of the representative's firm","D":"The SEC regional office"},"answer":"C","explanation":"Under FINRA rules, all retail communications (including advertisements) must be approved by a registered principal of the member firm before use. This is an internal firm review, not a regulatory filing. Some communications may require filing with FINRA, but the approval comes from the firm's principal.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra2-050","section":"4 - Regulatory Framework","stem":"Who is responsible for approving a member firm's retail communications before they are used?","choices":{"A":"The registered representative who created them","B":"A registered principal of the firm","C":"FINRA's advertising department","D":"The compliance department of the SEC"},"answer":"B","explanation":"A registered principal (supervisor with appropriate licenses) must approve retail communications before first use. While FINRA requires certain communications to be filed, the approval responsibility lies with the firm's principal. This ensures the firm is supervising its representatives' communications.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-001","section":"2 - Products & Risks","stem":"Which product owner is MOST exposed to inflationary risk?","choices":{"A":"Utility stocks","B":"Treasury bills","C":"Treasury bonds","D":"Blue chip industrials"},"answer":"C","explanation":"Treasury bonds (long-term fixed income securities) are most exposed to inflation risk because their fixed payments lose purchasing power over time as prices rise. Short-term instruments like T-bills are less affected because they mature quickly and can be reinvested at higher rates. Stocks, including utilities and blue chips, can potentially raise prices to offset inflation.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-002","section":"2 - Products & Risks","stem":"An investor concerned about inflation would be LEAST likely to invest in which of the following?","choices":{"A":"Real estate investment trusts (REITs)","B":"Common stocks","C":"30-year Treasury bonds","D":"Treasury Inflation-Protected Securities (TIPS)"},"answer":"C","explanation":"Long-term fixed-rate bonds like 30-year Treasury bonds offer no protection against inflation. REITs and common stocks can increase in value with inflation, and TIPS are specifically designed to protect against inflation by adjusting principal with the CPI.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-004","section":"3 - Trading, Accounts & Prohibited","stem":"Which of the following is TRUE about a custodial account under UTMA?","choices":{"A":"The custodian may take loans from the account","B":"The account may have multiple custodians","C":"The assets belong irrevocably to the minor","D":"Distributions must be equal among siblings"},"answer":"C","explanation":"Under UTMA, once assets are transferred to the minor, the gift is irrevocable and the assets belong to the minor. There can only be one custodian, the custodian cannot borrow from the account, and each UTMA account is for one minor only with no requirement for equal distributions among siblings.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-005","section":"4 - Regulatory Framework","stem":"A broker-dealer may accept payment for a new issue from a new customer when:","choices":{"A":"the registration statement becomes effective","B":"the red herring is delivered","C":"the preliminary prospectus is amended","D":"during the cooling-off period"},"answer":"A","explanation":"Broker-dealers cannot accept payment for new issues until the SEC declares the registration statement effective. During the cooling-off period, indications of interest may be collected but no sales or payment can occur. The red herring (preliminary prospectus) is used to gauge interest but does not authorize sales.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-006","section":"4 - Regulatory Framework","stem":"During the cooling-off period for a new issue, a broker-dealer may do all of the following EXCEPT:","choices":{"A":"distribute the preliminary prospectus","B":"take indications of interest","C":"accept payment for the securities","D":"hold due diligence meetings"},"answer":"C","explanation":"During the cooling-off period (while SEC reviews the registration statement), broker-dealers may distribute the red herring prospectus, collect non-binding indications of interest, and hold due diligence meetings. However, they cannot accept money or make binding sales until the registration becomes effective.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-007","section":"4 - Regulatory Framework","stem":"Under FINRA rules, noncash compensation for variable contracts includes all of the following EXCEPT:","choices":{"A":"gifts","B":"meals","C":"lodging","D":"commissions"},"answer":"D","explanation":"Commissions are considered cash compensation, not noncash compensation. Noncash compensation includes gifts, meals, lodging, and entertainment. FINRA has strict rules limiting noncash compensation to prevent conflicts of interest in recommending variable products.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-008","section":"4 - Regulatory Framework","stem":"FINRA limits noncash compensation for the sale of variable contracts primarily to prevent:","choices":{"A":"excessive trading","B":"conflicts of interest","C":"insider trading","D":"market manipulation"},"answer":"B","explanation":"FINRA limits noncash compensation (such as gifts, trips, and entertainment) to prevent conflicts of interest that could lead representatives to recommend products based on incentives rather than customer suitability. Limits typically restrict gifts to $100 per person per year.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-009","section":"2 - Products & Risks","stem":"In the OTC market, the term \"spread\" refers to the difference between:","choices":{"A":"bid and asked prices","B":"offered and asked prices","C":"indicated and firm prices","D":"opening and closing prices"},"answer":"A","explanation":"In the OTC market, the spread is the difference between the bid price (what the dealer will pay to buy) and the asked price (what the dealer will sell for). This spread represents the dealer's profit margin on transactions. A narrower spread indicates a more liquid market.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-010","section":"2 - Products & Risks","stem":"A market maker quotes a stock at 25.00 - 25.10. What is the spread?","choices":{"A":"$0.05","B":"$0.10","C":"$25.00","D":"$25.10"},"answer":"B","explanation":"The spread is the difference between the ask price ($25.10) and the bid price ($25.00), which equals $0.10. The bid is what the market maker pays to buy, and the ask is what they charge to sell. The spread is their compensation for making a market.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-011","section":"3 - Trading, Accounts & Prohibited","stem":"Roth 401(k) and Roth IRA share which feature?","choices":{"A":"Contributions are made pretax","B":"Neither has maximum contribution limits","C":"Neither is subject to early distribution penalties","D":"Qualified distributions are excluded from federal income tax"},"answer":"D","explanation":"Both Roth 401(k) and Roth IRA accounts feature tax-free qualified distributions. Contributions are made with after-tax dollars, both have contribution limits, and both are subject to early withdrawal penalties on earnings before age 59-1/2 unless an exception applies.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-012","section":"3 - Trading, Accounts & Prohibited","stem":"Which statement about Roth IRAs is TRUE?","choices":{"A":"Contributions are tax-deductible","B":"Required minimum distributions must begin at age 73","C":"Earnings grow tax-free","D":"Only self-employed individuals can contribute"},"answer":"C","explanation":"Roth IRA earnings grow tax-free, and qualified distributions are not taxable. Contributions are made with after-tax dollars (not deductible), Roth IRAs have no required minimum distributions during the owner's lifetime, and anyone with earned income below the income limits can contribute.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-013","section":"2 - Products & Risks","stem":"FinCEN safeguards the financial system by enforcing:","choices":{"A":"SEC regulations","B":"the Bank Secrecy Act","C":"the Securities Act of 1933","D":"the Investment Company Act of 1940"},"answer":"B","explanation":"FinCEN (Financial Crimes Enforcement Network) is a bureau of the U.S. Treasury that enforces the Bank Secrecy Act (BSA). The BSA requires financial institutions to assist government agencies in detecting and preventing money laundering and terrorist financing through reporting requirements.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-014","section":"2 - Products & Risks","stem":"Under the Bank Secrecy Act, a Currency Transaction Report (CTR) must be filed for cash transactions exceeding:","choices":{"A":"$3,000","B":"$5,000","C":"$10,000","D":"$15,000"},"answer":"C","explanation":"The Bank Secrecy Act requires financial institutions to file a Currency Transaction Report (CTR) for any cash transaction exceeding $10,000. Suspicious Activity Reports (SARs) may be filed for suspicious transactions of $5,000 or more, but CTRs specifically apply to cash over $10,000.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-015","section":"2 - Products & Risks","stem":"A transaction where an option writer covers a position by purchasing an option is:","choices":{"A":"a closing sale","B":"a closing purchase","C":"an opening sale","D":"an opening purchase"},"answer":"B","explanation":"When an option writer (seller) wants to close their position, they must buy back the same option. This is called a closing purchase. An opening sale creates a short option position, while a closing purchase eliminates it. Buyers use closing sales to exit long positions.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-016","section":"2 - Products & Risks","stem":"An investor who is long a call option can close the position by executing a:","choices":{"A":"closing purchase","B":"closing sale","C":"opening purchase","D":"opening sale"},"answer":"B","explanation":"An investor who bought (is long) a call option closes the position by selling the same option, which is a closing sale. Opening transactions establish new positions, while closing transactions eliminate existing ones. Long positions are closed with sales; short positions are closed with purchases.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-017","section":"2 - Products & Risks","stem":"What are the possible outcomes for the writer of a covered call?","choices":{"A":"Profit limited and loss limited","B":"Profit limited and loss unlimited","C":"Profit unlimited and loss limited","D":"Profit unlimited and loss unlimited"},"answer":"A","explanation":"A covered call writer owns the underlying stock and sells a call. Profit is limited to the premium received plus any gain up to the strike price. Loss is limited because they own the stock (it can only go to zero), and the premium received provides some downside protection. Compare to naked calls which have unlimited loss potential.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-018","section":"2 - Products & Risks","stem":"An investor writes a covered call primarily to:","choices":{"A":"speculate on price increases","B":"generate additional income on existing stock holdings","C":"protect against unlimited downside risk","D":"avoid paying dividends"},"answer":"B","explanation":"Investors write covered calls primarily to generate additional income (the premium) from stocks they already own and are willing to sell at the strike price. This strategy is conservative and used for income enhancement, not speculation. It provides limited downside protection but caps upside potential.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-019","section":"4 - Regulatory Framework","stem":"In a stock split, who maintains the record of shareholders eligible for additional shares?","choices":{"A":"DTC","B":"Issuer","C":"Custodian","D":"Transfer agent"},"answer":"D","explanation":"The transfer agent maintains the official list of a company's shareholders and their holdings. When a stock split occurs, the transfer agent identifies eligible shareholders and arranges for distribution of additional shares. The issuer declares the split, DTC settles trades, and custodians hold securities.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-020","section":"2 - Products & Risks","stem":"Which entity is responsible for issuing and canceling stock certificates?","choices":{"A":"Registrar","B":"Transfer agent","C":"Clearing corporation","D":"Securities depository"},"answer":"B","explanation":"The transfer agent issues new stock certificates and cancels old ones when ownership changes. They maintain the official shareholder register for the issuing company. The registrar verifies that outstanding shares match authorized shares, clearing corporations settle trades, and depositories hold securities.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-021","section":"4 - Regulatory Framework","stem":"All of the following are considered insider information EXCEPT:","choices":{"A":"pending acquisitions","B":"declared stock dividends","C":"top management changes","D":"imminent financial liquidity problems"},"answer":"B","explanation":"Once a dividend is declared (publicly announced by the board of directors), it is public information, not insider information. Insider information is material nonpublic information such as undisclosed mergers, undisclosed management changes, or financial problems not yet revealed to the public.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-022","section":"2 - Products & Risks","stem":"Trading on material nonpublic information violates which securities law?","choices":{"A":"Securities Act of 1933","B":"Securities Exchange Act of 1934","C":"Investment Company Act of 1940","D":"Investment Advisers Act of 1940"},"answer":"B","explanation":"Insider trading violates the Securities Exchange Act of 1934, specifically Rule 10b-5, which prohibits fraud in connection with the purchase or sale of securities. This includes trading while in possession of material nonpublic information or tipping others to trade on such information.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-023","section":"2 - Products & Risks","stem":"Stability in debt portfolio value is greatest when:","choices":{"A":"interest rates are rising","B":"interest rates are falling","C":"maturities are long","D":"maturities are short"},"answer":"D","explanation":"Short-term bonds have less price sensitivity to interest rate changes than long-term bonds. A portfolio of short-maturity bonds will experience smaller price fluctuations as rates change, providing greater stability. Long-term bonds are more volatile because their prices move more dramatically with rate changes.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-024","section":"2 - Products & Risks","stem":"Which bond would experience the LEAST price volatility?","choices":{"A":"30-year Treasury bond","B":"10-year corporate bond","C":"5-year municipal bond","D":"1-year Treasury bill"},"answer":"D","explanation":"A 1-year Treasury bill has the shortest maturity and therefore the lowest duration and price sensitivity. Longer-term bonds experience greater price swings when interest rates change. The T-bill's short maturity means its price is relatively stable regardless of rate movements.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-025","section":"4 - Regulatory Framework","stem":"Under the Securities Act of 1933, registration is required for:","choices":{"A":"Eurodollar bonds","B":"Municipal securities","C":"American Depositary Receipts (ADRs)","D":"Securities issued by the federal government"},"answer":"C","explanation":"ADRs must be registered under the Securities Act of 1933 because they are issued by U.S. banks representing foreign securities. Municipal securities and U.S. government securities are exempt from registration. Eurodollar bonds issued outside the U.S. may not require SEC registration.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-026","section":"4 - Regulatory Framework","stem":"Which of the following securities is EXEMPT from registration under the Securities Act of 1933?","choices":{"A":"Corporate bonds","B":"ADRs","C":"Municipal bonds","D":"IPO shares"},"answer":"C","explanation":"Municipal bonds are exempt from registration under the Securities Act of 1933. Other exempt securities include U.S. government securities, bank securities, and commercial paper with maturities under 270 days. Corporate bonds, ADRs, and IPO shares all require registration.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-027","section":"2 - Products & Risks","stem":"What is the cost basis of an inherited mutual fund?","choices":{"A":"NAV on the date the owner dies","B":"NAV 30 days after death","C":"Same cost basis as the deceased","D":"Deceased cost basis plus capital gains distributions"},"answer":"A","explanation":"Inherited securities receive a \"stepped-up\" cost basis equal to the fair market value (NAV for mutual funds) on the date of the original owner's death. This eliminates any unrealized gains that occurred during the decedent's lifetime, potentially saving the heir significant capital gains taxes.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-028","section":"2 - Products & Risks","stem":"An investor inherits stock purchased by the decedent for $10,000. At the date of death, the stock is worth $50,000. What is the heir's cost basis?","choices":{"A":"$10,000","B":"$30,000","C":"$50,000","D":"$60,000"},"answer":"C","explanation":"The heir receives a stepped-up cost basis equal to the fair market value at the date of death ($50,000). If the heir later sells for $55,000, the taxable gain is only $5,000, not $45,000. This is a significant tax benefit of inherited assets versus gifted assets, which use carryover basis.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-029","section":"2 - Products & Risks","stem":"Which creditor has first claim priority in a Chapter 11 bankruptcy proceeding?","choices":{"A":"Equity holders","B":"Secured debt holders","C":"Unsecured debt holders","D":"Preferred stockholders"},"answer":"B","explanation":"Secured debt holders have the highest priority in bankruptcy because their claims are backed by specific collateral. The liquidation priority order is: secured creditors, unsecured creditors (including bondholders), preferred stockholders, and finally common stockholders. Common and preferred stock are last because they represent ownership, not debt.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-030","section":"2 - Products & Risks","stem":"In a corporate liquidation, common stockholders:","choices":{"A":"receive payment before preferred stockholders","B":"receive payment before bondholders","C":"are paid last after all other claims","D":"have priority over unsecured creditors"},"answer":"C","explanation":"Common stockholders are at the bottom of the priority list in liquidation. They receive any remaining assets only after all creditors (secured and unsecured) and preferred stockholders have been paid. This reflects the higher risk of equity ownership compared to debt.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-031","section":"4 - Regulatory Framework","stem":"Blue-sky laws are regulated by:","choices":{"A":"SEC","B":"MSRB","C":"FINRA","D":"State securities regulators"},"answer":"D","explanation":"Blue-sky laws are state securities laws enforced by state securities administrators. Each state has its own securities regulations that may require registration of securities, broker-dealers, and investment advisers within that state. The SEC enforces federal securities laws, while FINRA regulates broker-dealers at the national level.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-032","section":"2 - Products & Risks","stem":"The Uniform Securities Act is a model law created by:","choices":{"A":"SEC","B":"NASAA","C":"FINRA","D":"U.S. Congress"},"answer":"B","explanation":"NASAA (North American Securities Administrators Association) created the Uniform Securities Act as a model law that states can adopt to bring consistency to state securities regulation. Individual states may adopt it in whole or in part. NASAA coordinates among state regulators but does not enforce rules directly.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-033","section":"2 - Products & Risks","stem":"What is the essential difference between a primary and secondary distribution?","choices":{"A":"Primary only involves equity; secondary involves equity and debt","B":"Primary only exceeds a specified dollar amount","C":"Primary is at fixed POP; secondary is at market price","D":"Primary involves newly issued shares by the issuer; secondary involves already issued shares"},"answer":"D","explanation":"In a primary distribution, the issuing company sells new shares and receives the proceeds for corporate purposes. In a secondary distribution, existing shareholders sell their already-issued shares, and the issuer receives nothing. Both can involve equity or debt, and pricing varies based on the type of offering.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-034","section":"1 - Capital Markets","stem":"When a company conducts an IPO, this is an example of a:","choices":{"A":"secondary market transaction","B":"primary distribution","C":"secondary distribution","D":"fourth market transaction"},"answer":"B","explanation":"An IPO (Initial Public Offering) is a primary distribution where the company issues new shares to the public for the first time and receives the proceeds. After the IPO, trading among investors occurs in the secondary market. A secondary distribution involves selling existing shares, not new issuance.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-035","section":"3 - Trading, Accounts & Prohibited","stem":"A customer with a cash balance and long positions, but no transactions in 18 months, must receive account statements how often?","choices":{"A":"Monthly","B":"Quarterly","C":"Semiannually","D":"Annually"},"answer":"B","explanation":"For inactive accounts with positions but no activity, broker-dealers must send statements at least quarterly. Active accounts with transactions during the month require monthly statements. The quarterly minimum ensures customers can monitor their holdings and detect any unauthorized activity.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-036","section":"3 - Trading, Accounts & Prohibited","stem":"A customer account with monthly trading activity must receive statements:","choices":{"A":"weekly","B":"monthly","C":"quarterly","D":"upon request only"},"answer":"B","explanation":"Accounts with activity during the month must receive monthly statements. This includes any purchase, sale, interest or dividend credit, or other transaction. The statement must show all positions, transactions, and any changes to the account during the statement period.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-037","section":"2 - Products & Risks","stem":"An investor owns 100 shares at $50. After a 1-for-2 reverse split, the position will be:","choices":{"A":"50 shares at $25","B":"50 shares at $100","C":"200 shares at $25","D":"200 shares at $100"},"answer":"B","explanation":"In a 1-for-2 reverse split, shareholders receive 1 new share for every 2 old shares, reducing the number of shares by half. The price doubles to maintain the same total value: 100 shares becomes 50 shares, and $50 per share becomes $100 per share. Total value remains $5,000.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-038","section":"2 - Products & Risks","stem":"A company announces a 2-for-1 stock split. An investor holding 200 shares at $80 will have:","choices":{"A":"100 shares at $160","B":"200 shares at $80","C":"400 shares at $40","D":"400 shares at $80"},"answer":"C","explanation":"In a 2-for-1 forward split, shareholders receive 2 new shares for each share owned, doubling the share count. The price is halved to maintain the same total value: 200 shares becomes 400 shares, $80 becomes $40. Total value remains $16,000 (200 x $80 = 400 x $40).","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-039","section":"2 - Products & Risks","stem":"The call provision of a bond stipulates:","choices":{"A":"Maturity date","B":"Call date and call price","C":"Original issue discount","D":"Coupon rate and call date"},"answer":"B","explanation":"A call provision specifies when the issuer can call (redeem) the bond before maturity (the call date) and at what price (the call price, typically at a premium to par). This protects issuers if interest rates decline, allowing them to refinance at lower rates. Investors face reinvestment risk.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-040","section":"1 - Capital Markets","stem":"Which type of bond provision benefits the ISSUER if interest rates decline?","choices":{"A":"Put provision","B":"Call provision","C":"Conversion provision","D":"Sinking fund provision"},"answer":"B","explanation":"A call provision benefits the issuer when rates decline because they can call the existing high-coupon bonds and reissue new bonds at lower rates, reducing interest costs. Put provisions benefit bondholders. Conversion provisions benefit bondholders when stock prices rise.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-041","section":"2 - Products & Risks","stem":"A married couple with income over $300,000 for the prior two years and the current year is:","choices":{"A":"a qualified investor","B":"an accredited investor","C":"an institutional investor","D":"a qualified institutional buyer (QIB)"},"answer":"B","explanation":"A married couple with joint income exceeding $300,000 for the past two years, with reasonable expectation of the same for the current year, meets the accredited investor definition under Regulation D. Accredited investors can participate in private placements. QIBs require $100 million in securities owned.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-042","section":"4 - Regulatory Framework","stem":"Under Regulation D, an accredited investor includes an individual with a net worth exceeding:","choices":{"A":"$500,000 including primary residence","B":"$1 million including primary residence","C":"$1 million excluding primary residence","D":"$2 million excluding primary residence"},"answer":"C","explanation":"An individual qualifies as an accredited investor with net worth exceeding $1 million, excluding the value of their primary residence. This change was made by Dodd-Frank to prevent over-reliance on home equity. The income test is $200,000 individual or $300,000 joint for the past two years.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-043","section":"2 - Products & Risks","stem":"Which of the following is TRUE about treasury stock?","choices":{"A":"It has voting rights","B":"It receives dividends","C":"It is issued stock subsequently reacquired by the corporation","D":"It is authorized stock not yet issued held in treasury"},"answer":"C","explanation":"Treasury stock is previously issued stock that the company has reacquired through buybacks. Treasury shares do not vote, do not receive dividends, and are not counted as outstanding shares for per-share calculations. They can be reissued, retired, or used for employee compensation plans.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-044","section":"2 - Products & Risks","stem":"A company with 10 million shares issued and 1 million shares held as treasury stock has how many outstanding shares?","choices":{"A":"9 million","B":"10 million","C":"11 million","D":"1 million"},"answer":"A","explanation":"Outstanding shares equal issued shares minus treasury shares. With 10 million issued and 1 million held as treasury stock, there are 9 million outstanding shares. Outstanding shares are those held by investors and are used to calculate earnings per share and other per-share metrics.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-045","section":"1 - Capital Markets","stem":"Direct participation programs (DPPs) provide investors with:","choices":{"A":"liquidity and transparency","B":"exposure to non-correlated assets","C":"market-related correlations with higher returns","D":"direct purchases of stock from public companies"},"answer":"B","explanation":"DPPs provide exposure to alternative assets like oil and gas, real estate, and equipment leasing that may not correlate with stock and bond markets. This diversification benefit is valuable. However, DPPs are illiquid (not traded on exchanges) and lack the transparency of public securities.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-046","section":"1 - Capital Markets","stem":"Which is a characteristic of Direct Participation Programs (DPPs)?","choices":{"A":"High liquidity","B":"Tax benefits pass directly to investors","C":"Traded on national exchanges","D":"Guaranteed returns"},"answer":"B","explanation":"DPPs are structured as limited partnerships where tax benefits (deductions, credits) pass through directly to investors' personal tax returns. DPPs are illiquid with no active secondary market, are not traded on exchanges, and offer no guaranteed returns. They are suitable for sophisticated, high-net-worth investors.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-047","section":"2 - Products & Risks","stem":"Which statement is TRUE about all U.S. government agency issues?","choices":{"A":"They are exempt from federal taxes","B":"They are exempt from registration under the Securities Act of 1933","C":"They are issued in bearer form only","D":"They are general obligations of the federal government"},"answer":"B","explanation":"All U.S. government and government agency securities are exempt from registration under the Securities Act of 1933. However, tax treatment varies: Treasury securities are exempt from state tax, while most agency securities are fully taxable. Most agency securities are not backed by the full faith and credit of the U.S. government.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-048","section":"2 - Products & Risks","stem":"Interest on U.S. Treasury securities is:","choices":{"A":"exempt from all taxes","B":"subject to federal tax but exempt from state and local taxes","C":"subject to state tax but exempt from federal tax","D":"subject to both federal and state taxes"},"answer":"B","explanation":"U.S. Treasury securities interest is subject to federal income tax but exempt from state and local income taxes. This makes Treasuries particularly attractive to investors in high-tax states. Municipal bond interest, by contrast, is exempt from federal tax.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-049","section":"3 - Trading, Accounts & Prohibited","stem":"Which statement is TRUE about a tenants in common account?","choices":{"A":"Owners must equally share the assets","B":"Ownership of a decedent's assets is governed by will or state law","C":"Tenants in common is only for two individuals","D":"Tenants in common is only for married couples or family members"},"answer":"B","explanation":"In a tenants in common (TIC) account, there is no right of survivorship. When one owner dies, their share passes according to their will or state intestacy laws, not automatically to surviving owners. Ownership percentages can be unequal, any number of owners is allowed, and they need not be related.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-finra3-050","section":"3 - Trading, Accounts & Prohibited","stem":"Which type of joint account features the right of survivorship?","choices":{"A":"Tenants in common","B":"Joint tenants with right of survivorship","C":"Tenancy by the entirety","D":"Both B and C"},"answer":"D","explanation":"Both Joint Tenants with Right of Survivorship (JTWROS) and Tenancy by the Entirety feature the right of survivorship, where the surviving owner(s) automatically inherit the deceased owner's share. Tenancy by the entirety is available only to married couples. Tenants in common has no survivorship rights.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-001","section":"2 - Products & Risks","stem":"A corporation issues callable bonds with a first call date of January 1, 2030. If the bonds were issued on January 1, 2025, how many years of call protection do bondholders have?","choices":{"A":"3 years","B":"5 years","C":"7 years","D":"10 years"},"answer":"B","explanation":"Call protection is the period during which the issuer cannot call (redeem) the bonds. It is calculated from the issue date to the first call date. From January 1, 2025 to January 1, 2030 is 5 years of call protection.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-002","section":"2 - Products & Risks","stem":"Which date is MOST important for determining how long bondholders are protected from early redemption on a callable bond?","choices":{"A":"The maturity date","B":"The first call date","C":"The dated date","D":"The settlement date"},"answer":"B","explanation":"The first call date determines when the issuer can first exercise its right to redeem the bonds early. The period from issuance until the first call date is the call protection period, during which bondholders are protected from early redemption.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-003","section":"2 - Products & Risks","stem":"A 6% preferred stock has a par value of $100. What is the annual dividend an investor would expect to receive per share?","choices":{"A":"$0.60","B":"$6.00","C":"$60.00","D":"$100.00"},"answer":"B","explanation":"Preferred stock dividends are calculated as a percentage of par value. With a $100 par value and 6% dividend rate: $100 x 6% = $6.00 annual dividend per share.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-004","section":"2 - Products & Risks","stem":"An investor seeking steady income with less volatility than common stock would MOST likely invest in:","choices":{"A":"Growth stocks","B":"Preferred stock","C":"Stock options","D":"Stock warrants"},"answer":"B","explanation":"Preferred stock pays fixed dividends (typically at a stated rate on $100 par value), making it attractive for income-focused investors. It has less price volatility than common stock because its value is based primarily on dividend payments.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-005","section":"2 - Products & Risks","stem":"Who determines the ex-dividend date for a mutual fund distribution?","choices":{"A":"The SEC","B":"FINRA","C":"The fund's Board of Directors","D":"The stock exchange where the fund trades"},"answer":"C","explanation":"For mutual funds, the Board of Directors sets the ex-dividend date as part of its dividend declaration. This is different from exchange-traded stocks, where the exchange determines the ex-date based on settlement rules.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-006","section":"1 - Capital Markets","stem":"The ex-dividend date for a mutual fund differs from that of exchange-traded stocks because:","choices":{"A":"Mutual funds never pay dividends","B":"The mutual fund's Board of Directors determines the ex-date","C":"FINRA sets the ex-date for all investment companies","D":"Mutual funds trade at NAV, so ex-dates do not apply"},"answer":"B","explanation":"Unlike exchange-traded securities where the ex-date is determined by exchange rules (typically one business day before record date), mutual fund ex-dates are set by the fund's Board of Directors as part of the dividend declaration.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-007","section":"3 - Trading, Accounts & Prohibited","stem":"A customer instructs their representative to buy 500 shares of XYZ stock \"when the time is right.\" What authorization does the representative need to execute this order?","choices":{"A":"Written power of attorney","B":"Verbal authorization only - no POA needed","C":"Discretionary account agreement","D":"Third-party trading authorization"},"answer":"B","explanation":"Time and price discretion (also called \"not held\" orders) only require verbal authorization. A power of attorney is not required because the customer has specified the asset and amount. The representative only has discretion over timing and price.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-008","section":"3 - Trading, Accounts & Prohibited","stem":"Which of the following orders would NOT require a written power of attorney?","choices":{"A":"\"Buy some blue-chip stocks for my account\"","B":"\"Sell 100 shares of ABC whenever you think the price is good\"","C":"\"Invest $10,000 in something suitable for me\"","D":"\"Trade my account as you see fit\""},"answer":"B","explanation":"When a customer specifies the security (ABC) and quantity (100 shares) but gives the representative discretion only over time and/or price, this is time and price discretion, which requires only verbal authorization - no written POA needed.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-009","section":"3 - Trading, Accounts & Prohibited","stem":"What is the minimum maintenance margin requirement for a long stock position held in a margin account?","choices":{"A":"20%","B":"25%","C":"30%","D":"50%"},"answer":"B","explanation":"The minimum maintenance margin for long stock positions is 25% of the current market value. If equity falls below this level, a maintenance call is issued requiring the customer to deposit additional funds.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-010","section":"2 - Products & Risks","stem":"A short seller must maintain a minimum equity of what percentage of the short market value?","choices":{"A":"25%","B":"30%","C":"50%","D":"100%"},"answer":"B","explanation":"Short positions require a 30% minimum maintenance margin because of their unlimited risk potential. This is higher than the 25% requirement for long positions.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-011","section":"3 - Trading, Accounts & Prohibited","stem":"In a cash account, securities must be fully paid for by:","choices":{"A":"The trade date","B":"T+1 (trade date plus one business day)","C":"Settlement date (T+1 for most securities)","D":"Within 30 days of purchase"},"answer":"C","explanation":"In a cash account, customers must pay for securities in full by the settlement date. For most securities, settlement occurs on T+1 (one business day after trade date).","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-012","section":"3 - Trading, Accounts & Prohibited","stem":"What distinguishes a cash account from a margin account?","choices":{"A":"Cash accounts allow unlimited trading","B":"Cash accounts require full payment for all securities by settlement","C":"Cash accounts permit short selling","D":"Cash accounts have lower maintenance requirements"},"answer":"B","explanation":"The fundamental distinction is that cash accounts require customers to pay 100% of the purchase price by settlement date. No credit is extended, unlike margin accounts where customers can borrow a portion of the purchase price.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-013","section":"2 - Products & Risks","stem":"An investor who expects the market to rise significantly would MOST likely:","choices":{"A":"Buy put options","B":"Sell call options","C":"Buy call options","D":"Sell stock short"},"answer":"C","explanation":"Buying call options is a bullish strategy. As the underlying stock price rises, the value of call options increases, allowing the holder to profit from the upward movement with limited risk (maximum loss is the premium paid).","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-014","section":"2 - Products & Risks","stem":"If the stock market experiences a sudden rally, which position would MOST likely increase in value?","choices":{"A":"Long put options","B":"Short stock positions","C":"Long call options","D":"Short call options"},"answer":"C","explanation":"Long call options increase in value when the underlying stock rises. A market rally would cause call premiums to increase due to higher intrinsic value and potentially higher implied volatility.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-015","section":"2 - Products & Risks","stem":"For federal income tax purposes, dividend income is reported based on which date?","choices":{"A":"Declaration date","B":"Ex-dividend date","C":"Record date","D":"Payable date"},"answer":"D","explanation":"For tax reporting purposes, dividend income is recognized in the year it is received, which is determined by the payable date (the date the dividend is actually paid to shareholders).","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-016","section":"2 - Products & Risks","stem":"A dividend declared in December 2024 with a payable date of January 15, 2025 would be taxable in:","choices":{"A":"Tax year 2024","B":"Tax year 2025","C":"Either year, at the investor's choice","D":"Split between both tax years"},"answer":"B","explanation":"Dividends are taxable in the year they are actually paid (payable date). Since the payable date is January 15, 2025, the dividend income is reported on the 2025 tax return, regardless of when it was declared.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-017","section":"2 - Products & Risks","stem":"For a bond trading at a premium, which of the following lists the yields from LOWEST to HIGHEST?","choices":{"A":"Coupon rate, current yield, YTM, YTC","B":"YTC, YTM, current yield, coupon rate","C":"Current yield, YTM, YTC, coupon rate","D":"YTM, YTC, current yield, coupon rate"},"answer":"B","explanation":"For premium bonds, yields from lowest to highest are: YTC < YTM < Current Yield < Coupon Rate. The investor paid more than par, so all calculated yields are lower than the stated coupon rate.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-018","section":"2 - Products & Risks","stem":"A bond with a 6% coupon trading at 105 would have which yield as the LOWEST?","choices":{"A":"Coupon rate (6%)","B":"Current yield","C":"Yield to maturity","D":"Yield to call"},"answer":"D","explanation":"When a bond trades at a premium (105 = $1,050 for a $1,000 par bond), yield to call is the lowest yield because the investor loses the premium faster if called early. The order for premium bonds: YTC < YTM < CY < Coupon.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-019","section":"1 - Capital Markets","stem":"In a best efforts underwriting, what happens to securities that remain unsold?","choices":{"A":"The underwriter must purchase them at a discount","B":"They are returned to the issuer who retains them","C":"They are distributed pro-rata to syndicate members","D":"They are sold at auction to institutional investors"},"answer":"B","explanation":"In a best efforts underwriting, the underwriter agrees only to make its best effort to sell the securities. Any unsold securities are returned to the issuer, who keeps (retains) them. The underwriter takes no risk of ownership.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-020","section":"1 - Capital Markets","stem":"Which type of underwriting arrangement places no risk on the underwriter for unsold securities?","choices":{"A":"Firm commitment","B":"Best efforts","C":"Standby underwriting","D":"All-or-none"},"answer":"B","explanation":"In a best efforts underwriting, the underwriter acts as an agent and bears no risk for unsold securities. Any unsold shares are simply returned to the issuer. The underwriter only commits to trying its best to sell the offering.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-021","section":"4 - Regulatory Framework","stem":"Under insider trading laws, if a corporate officer shares material nonpublic information with a friend who then trades on it, who can be held liable?","choices":{"A":"Only the corporate officer (tipper)","B":"Only the friend who traded (tippee)","C":"Both the tipper and the tippee","D":"Neither, if no money was exchanged for the tip"},"answer":"C","explanation":"Both the tipper (person who provides inside information) and the tippee (person who receives and trades on it) can be held liable for insider trading violations. The tipper breaches a duty of trust, and the tippee knowingly benefits from that breach.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-022","section":"2 - Products & Risks","stem":"A person who receives material nonpublic information and trades on it is known as a:","choices":{"A":"Market maker","B":"Tipper","C":"Tippee","D":"Underwriter"},"answer":"C","explanation":"A tippee is someone who receives material nonpublic information from an insider (the tipper) and then trades on that information. Under securities laws, tippees can be held liable for insider trading alongside the tipper who provided the information.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-023","section":"2 - Products & Risks","stem":"An investor who is bearish on a stock they own would MOST likely:","choices":{"A":"Buy additional shares","B":"Buy call options","C":"Write (sell) covered calls","D":"Buy put options on a different stock"},"answer":"C","explanation":"Writing covered calls is appropriate for a mildly bearish or neutral outlook. The investor earns premium income while expecting the stock price to stay flat or decline slightly. If the stock falls, they keep the premium and offset some losses.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-024","section":"2 - Products & Risks","stem":"Which options position profits when the underlying stock price DECLINES?","choices":{"A":"Long call","B":"Short call","C":"Long stock","D":"Short put"},"answer":"B","explanation":"A short call (selling a call) profits when the stock price stays the same or declines. The call seller keeps the premium received if the option expires worthless (when the stock price is at or below the strike price at expiration).","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-025","section":"4 - Regulatory Framework","stem":"Municipal securities are exempt from registration requirements under which federal law?","choices":{"A":"Investment Company Act of 1940","B":"Securities Act of 1933","C":"Securities Exchange Act of 1934","D":"Investment Advisers Act of 1940"},"answer":"B","explanation":"Municipal bonds are exempt securities under the Securities Act of 1933, meaning they do not need to be registered with the SEC before being offered to the public. This exemption applies because municipal issuers (state and local governments) are presumed to act in the public interest.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-026","section":"4 - Regulatory Framework","stem":"Which of the following securities does NOT require registration with the SEC under the Securities Act of 1933?","choices":{"A":"Common stock of a Fortune 500 company","B":"Corporate bonds issued by Apple Inc.","C":"General obligation bonds issued by the City of Chicago","D":"Shares of a mutual fund"},"answer":"C","explanation":"Municipal bonds (including general obligation bonds issued by cities) are exempt from SEC registration under the Securities Act of 1933. This exemption exists because state and local governments are presumed to be acting in the public interest.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-027","section":"2 - Products & Risks","stem":"Which type of limited partnership investment allows investors to claim depletion deductions?","choices":{"A":"Real estate limited partnerships","B":"Equipment leasing partnerships","C":"Oil and gas partnerships","D":"Hedge fund limited partnerships"},"answer":"C","explanation":"Depletion is a tax deduction unique to natural resources, such as oil, gas, and minerals. Oil and gas limited partnerships pass through depletion deductions to investors. Real estate uses depreciation, not depletion.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-028","section":"2 - Products & Risks","stem":"An investor in a real estate limited partnership can take advantage of which tax benefit?","choices":{"A":"Depletion allowance","B":"Depreciation deductions","C":"Intangible drilling costs","D":"Percentage depletion"},"answer":"B","explanation":"Real estate limited partnerships allow investors to claim depreciation deductions on buildings and improvements. Depletion and intangible drilling costs are specific to oil and gas investments, not real estate.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-029","section":"2 - Products & Risks","stem":"A hostile takeover attempt typically begins with which of the following?","choices":{"A":"A friendly merger proposal","B":"A tender offer to shareholders","C":"An SEC registration statement","D":"A vote by the target company's board"},"answer":"B","explanation":"A hostile takeover typically begins with a tender offer, which is a public offer to purchase shares directly from the target company's shareholders at a premium price. This bypasses the board of directors who may oppose the acquisition.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-030","section":"2 - Products & Risks","stem":"When acquiring company ABC makes an offer to purchase shares directly from XYZ Corporation's shareholders without XYZ board approval, this is called:","choices":{"A":"A merger","B":"A leveraged buyout","C":"A tender offer","D":"A rights offering"},"answer":"C","explanation":"A tender offer is a public bid to purchase shares directly from shareholders, typically at a premium to the current market price. When made without target board approval, it is often part of a hostile takeover attempt.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-031","section":"2 - Products & Risks","stem":"For a bond purchased above par value, which yield will be the HIGHEST?","choices":{"A":"Yield to call","B":"Yield to maturity","C":"Current yield","D":"Nominal (coupon) yield"},"answer":"D","explanation":"For a premium bond, the nominal (coupon) yield is the highest because it is based on par value, not the higher purchase price. The order from highest to lowest is: Coupon > Current Yield > YTM > YTC.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-032","section":"2 - Products & Risks","stem":"An investor purchases a 5% coupon bond at 110. Which statement about the bond's yields is TRUE?","choices":{"A":"Current yield is higher than the coupon rate","B":"Yield to maturity is higher than yield to call","C":"Coupon rate is the highest yield","D":"Yield to call is higher than current yield"},"answer":"C","explanation":"For a premium bond (purchased at 110 = $1,100 for $1,000 par), the coupon rate (5%) is the highest yield. Since the investor paid more than par, all other yields (current yield, YTM, YTC) will be lower than the stated coupon rate.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-033","section":"3 - Trading, Accounts & Prohibited","stem":"A 45-year-old who becomes permanently disabled withdraws funds from their traditional IRA. What are the tax consequences?","choices":{"A":"No taxes or penalties","B":"Ordinary income tax plus 10% penalty","C":"Ordinary income tax only, no 10% penalty","D":"10% penalty only, no ordinary income tax"},"answer":"C","explanation":"Traditional IRA withdrawals due to disability are exempt from the 10% early withdrawal penalty. However, the distribution is still taxable as ordinary income since the contributions were made with pre-tax dollars.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-034","section":"3 - Trading, Accounts & Prohibited","stem":"Which of the following traditional IRA distributions would be subject to the 10% early withdrawal penalty?","choices":{"A":"Disability distribution at age 40","B":"Regular distribution at age 60","C":"Withdrawal for vacation expenses at age 45","D":"Distribution after death to a beneficiary"},"answer":"C","explanation":"A withdrawal for personal expenses like vacation at age 45 would be subject to both ordinary income tax and the 10% early withdrawal penalty. Exceptions include disability, death, and distributions after age 59 1/2.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-035","section":"2 - Products & Risks","stem":"What is the maximum maturity for a banker's acceptance?","choices":{"A":"90 days","B":"180 days","C":"270 days","D":"1 year"},"answer":"C","explanation":"Banker's acceptances typically have a maximum maturity of 270 days (9 months). They are short-term money market instruments used to finance international trade, guaranteed by the accepting bank.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-036","section":"2 - Products & Risks","stem":"Which money market instrument is used to facilitate international trade and has a maximum maturity of 270 days?","choices":{"A":"Treasury bills","B":"Banker's acceptances","C":"Negotiable CDs","D":"Repurchase agreements"},"answer":"B","explanation":"Banker's acceptances are time drafts guaranteed by a bank, primarily used in international trade. They have a maximum maturity of 270 days and are traded at a discount in the money market.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-037","section":"4 - Regulatory Framework","stem":"Which of the following would be classified as institutional communications under FINRA rules?","choices":{"A":"A brochure mailed to 100 retail customers","B":"A research report sent to a pension fund with $75 million in assets","C":"An email to a customer with $50,000 in their account","D":"A television advertisement"},"answer":"B","explanation":"Institutional communications are directed exclusively to institutional investors, which include entities with at least $50 million in assets. A pension fund with $75 million qualifies. These communications have fewer approval requirements than retail communications.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-038","section":"4 - Regulatory Framework","stem":"To qualify as an institutional investor for purposes of institutional communications, an entity must generally have:","choices":{"A":"At least $1 million in annual revenue","B":"At least $10 million in assets","C":"At least $50 million in assets","D":"At least $100 million in assets"},"answer":"C","explanation":"Under FINRA rules, an institutional investor is defined as an entity with at least $50 million in total assets. This includes banks, insurance companies, investment companies, pension funds, and similar large organizations.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-039","section":"3 - Trading, Accounts & Prohibited","stem":"What is the maximum annual contribution to a Coverdell Education Savings Account (ESA)?","choices":{"A":"$500","B":"$2,000","C":"$5,500","D":"$18,500"},"answer":"B","explanation":"The maximum annual contribution to a Coverdell ESA is $2,000 per beneficiary. Contributions are not tax-deductible, but earnings grow tax-free when used for qualified education expenses.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-040","section":"3 - Trading, Accounts & Prohibited","stem":"A grandparent wants to contribute to a Coverdell ESA for their grandchild. Which of the following is TRUE?","choices":{"A":"Maximum contribution is $10,000 per year","B":"Maximum contribution is $2,000 per year per beneficiary","C":"Contributions are tax-deductible","D":"Only parents can contribute to a Coverdell ESA"},"answer":"B","explanation":"The annual contribution limit for a Coverdell ESA is $2,000 per beneficiary from all sources combined. Any person (parents, grandparents, friends, or even the beneficiary) can contribute, subject to income limits.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-041","section":"2 - Products & Risks","stem":"An offering memorandum is MOST commonly associated with:","choices":{"A":"A registered public offering","B":"A Regulation D private placement","C":"An exchange-traded fund","D":"A municipal bond offering"},"answer":"B","explanation":"An offering memorandum (also called private placement memorandum) is the disclosure document used in Regulation D private placements. Since these offerings are exempt from SEC registration, no prospectus is required, but the offering memorandum provides essential information to investors.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-042","section":"4 - Regulatory Framework","stem":"Which document would an investor receive when purchasing securities in a Regulation D private placement?","choices":{"A":"Prospectus","B":"Official statement","C":"Offering memorandum","D":"Annual report"},"answer":"C","explanation":"Investors in Regulation D private placements receive an offering memorandum (private placement memorandum) that describes the offering terms, risks, and other material information. This is used instead of a prospectus because the offering is exempt from registration.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-043","section":"2 - Products & Risks","stem":"Which term is NOT synonymous with the coupon rate on a bond?","choices":{"A":"Stated rate","B":"Nominal yield","C":"Yield to maturity","D":"Interest rate printed on the bond"},"answer":"C","explanation":"Yield to maturity (YTM) is NOT synonymous with coupon rate. YTM accounts for the bond's current price, time to maturity, and reinvestment of interest. Coupon rate, stated rate, nominal yield, and the interest rate printed on the bond all refer to the same thing.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-044","section":"2 - Products & Risks","stem":"The nominal yield on a bond refers to:","choices":{"A":"The annual interest payment as a percentage of current market price","B":"The stated coupon rate as a percentage of par value","C":"The total return if held to maturity","D":"The return if the bond is called early"},"answer":"B","explanation":"Nominal yield (also called coupon rate or stated rate) is the annual interest payment as a percentage of the bond's par value. It remains fixed throughout the life of the bond, regardless of market price changes.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-045","section":"4 - Regulatory Framework","stem":"Which of the following practices is prohibited under securities regulations?","choices":{"A":"Recommending suitable investments to customers","B":"Guaranteeing to repurchase shares at purchase price","C":"Providing educational materials about investing","D":"Disclosing all material facts about a security"},"answer":"B","explanation":"Guaranteeing to repurchase shares at the purchase price (or any guaranteed price) is prohibited because it shields the investor from normal market risk. Such guarantees against loss are considered fraudulent practices under securities laws.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-046","section":"2 - Products & Risks","stem":"A registered representative promises a client \"I'll buy back your shares at $50 if the stock drops.\" This practice is:","choices":{"A":"Permitted as good customer service","B":"Prohibited as a guarantee against loss","C":"Allowed if the client signs a waiver","D":"Required for high-risk investments"},"answer":"B","explanation":"Guaranteeing to repurchase shares at a specific price is prohibited under FINRA rules. This constitutes a guarantee against loss, which is fraudulent because it eliminates the investment risk that investors should understand and accept.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-047","section":"4 - Regulatory Framework","stem":"Under MSRB rules, a Municipal Fund Securities Principal (MFP) is primarily responsible for:","choices":{"A":"Executing trades in municipal bonds","B":"Soliciting municipal issuers such as states and local governments","C":"Managing retail customer accounts","D":"Providing research on corporate bonds"},"answer":"B","explanation":"A Municipal Fund Securities Principal (MFP) is responsible for soliciting municipal issuers (states, cities, school districts) to establish 529 plans and other municipal fund securities programs. They work with issuers, not retail clients.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-048","section":"2 - Products & Risks","stem":"Which type of clients does a Municipal Fund Securities Principal (MFP) typically engage with?","choices":{"A":"Individual retail investors","B":"High-net-worth individuals","C":"Municipal issuers like states and cities","D":"Corporate pension funds"},"answer":"C","explanation":"MFPs work exclusively with municipal issuers - state and local governments that create 529 plans and similar municipal fund securities. They do not work directly with retail investors or corporate entities.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-049","section":"2 - Products & Risks","stem":"A life with period certain annuity guarantees payments for:","choices":{"A":"Only the annuitant's lifetime","B":"A fixed number of years only","C":"The longer of the annuitant's lifetime or a guaranteed period","D":"Two lifetimes (joint and survivor)"},"answer":"C","explanation":"A life with period certain annuity pays for the greater of the annuitant's lifetime or a specified minimum period (e.g., 10 or 20 years). If the annuitant dies before the period ends, a beneficiary receives payments for the remainder.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siep-050","section":"2 - Products & Risks","stem":"An annuitant elects a life with 20-year period certain annuity. If the annuitant dies after 8 years, what happens?","choices":{"A":"Payments stop immediately","B":"Beneficiary receives payments for the remaining 12 years","C":"Beneficiary receives a lump sum of 12 years' payments","D":"The annuity continues for 20 more years"},"answer":"B","explanation":"With a life with 20-year period certain annuity, payments are guaranteed for at least 20 years. If the annuitant dies after 8 years, the designated beneficiary receives payments for the remaining 12 years of the guaranteed period.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-001","section":"4 - Regulatory Framework","stem":"A registered representative terminates employment with their broker-dealer. Which form must be filed to formally end the registration?","choices":{"A":"Form U-4","B":"Form U-5","C":"Form BD","D":"Form ADV"},"answer":"B","explanation":"Form U-5 (Uniform Termination Notice for Securities Industry Registration) must be filed when a registered representative leaves a firm. Form U-4 is for initial registration, Form BD is for broker-dealer registration, and Form ADV is for investment advisers.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-002","section":"4 - Regulatory Framework","stem":"An individual passed the SIE exam but never associated with a broker-dealer. After how many years will the SIE exam results expire?","choices":{"A":"2 years","B":"3 years","C":"4 years","D":"6 years"},"answer":"C","explanation":"SIE exam results remain valid for 4 years from the passing date. If an individual does not become associated with a FINRA member firm within 4 years, they must retake the SIE. This is separate from the 2-year lapse period for top-off exams after leaving the industry.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-003","section":"2 - Products & Risks","stem":"An investor is short 100 shares of XYZ at $80 and purchases a protective call with a strike price of $85 for $3. What is the maximum potential gain on this position?","choices":{"A":"$7,700","B":"$8,000","C":"$8,200","D":"Unlimited"},"answer":"A","explanation":"When short stock with a long call, maximum gain occurs if stock goes to zero. Maximum gain = Sale price - Call premium = $80 - $3 = $77 per share = $7,700 total. The call limits losses if the stock rises but costs $3, reducing profit potential.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-004","section":"2 - Products & Risks","stem":"Why does an investor who is short stock purchase a call option?","choices":{"A":"To generate additional income","B":"To increase potential profits if the stock declines","C":"To limit the maximum loss if the stock price rises","D":"To leverage the short position"},"answer":"C","explanation":"A short seller faces unlimited loss potential if the stock rises. Buying a call option caps the maximum loss at the strike price minus the short sale price plus the premium paid. The call acts as insurance, guaranteeing the ability to buy shares at the strike price.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-005","section":"3 - Trading, Accounts & Prohibited","stem":"When opening a new customer account, which of the following is NOT required information?","choices":{"A":"Customer's name and address","B":"Tax identification number","C":"Medical history and health status","D":"Investment objectives"},"answer":"C","explanation":"Medical history and health status are not required for opening a securities account. Required information includes name, address, tax ID, employment status, investment objectives, risk tolerance, net worth, and annual income. Health information would violate privacy concerns.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-006","section":"3 - Trading, Accounts & Prohibited","stem":"A representative is gathering information for a new account application. Which question would be inappropriate to ask?","choices":{"A":"What is your annual income?","B":"Are you employed by a broker-dealer?","C":"Do you have any chronic health conditions?","D":"What is your investment time horizon?"},"answer":"C","explanation":"Asking about chronic health conditions is inappropriate and not required for account opening. Know Your Customer rules require financial information, employment, investment objectives, and risk tolerance - not medical information. Health-related questions could also raise discrimination concerns.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-007","section":"2 - Products & Risks","stem":"A Treasury note is quoted at 98-24. What is the price as a percentage of par value?","choices":{"A":"98.24%","B":"98.50%","C":"98.75%","D":"99.24%"},"answer":"C","explanation":"Treasury notes are quoted in 32nds. The quote 98-24 means 98 and 24/32 = 98 + 0.75 = 98.75% of par value. To convert: 24/32 = 0.75. For a $1,000 par bond, the price would be $987.50.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-008","section":"2 - Products & Risks","stem":"An investor purchases a Treasury bond quoted at 102-08. What dollar amount would the investor pay for $10,000 par value?","choices":{"A":"$10,208.00","B":"$10,225.00","C":"$10,250.00","D":"$10,280.00"},"answer":"C","explanation":"Treasury securities are quoted in 32nds. 102-08 = 102 and 8/32 = 102.25% of par. For $10,000 par value: $10,000 x 1.0225 = $10,225.00. The investor pays a premium of $225 above par value.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-009","section":"2 - Products & Risks","stem":"When making investment recommendations, which customer information is MOST critical for determining suitable investments?","choices":{"A":"Employer's name","B":"Risk tolerance","C":"Marital status","D":"Educational background"},"answer":"B","explanation":"Risk tolerance is the most critical factor in determining investment suitability. It indicates how much volatility and potential loss a customer can emotionally and financially handle. Recommendations must align with the customer's risk tolerance to be suitable.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-010","section":"2 - Products & Risks","stem":"A customer describes herself as very conservative and unable to tolerate any loss of principal. Which recommendation would be UNSUITABLE?","choices":{"A":"U.S. Treasury bills","B":"Certificates of deposit","C":"Money market funds","D":"Small-cap growth stocks"},"answer":"D","explanation":"Small-cap growth stocks are high-risk investments with significant volatility and potential for loss, completely unsuitable for a conservative investor who cannot tolerate principal loss. Treasury bills, CDs, and money market funds are appropriate for conservative investors.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-011","section":"2 - Products & Risks","stem":"A customer grants limited power of attorney to their financial advisor. What is the advisor authorized to do?","choices":{"A":"Withdraw funds from the account","B":"Execute trades in the account","C":"Change the account registration","D":"Borrow against the account"},"answer":"B","explanation":"A limited power of attorney authorizes the advisor to execute trades but NOT to withdraw funds or make changes to account registration. Only a full power of attorney would authorize fund withdrawals. Trading authority is the core function of both limited and full POA.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-012","section":"3 - Trading, Accounts & Prohibited","stem":"What is the key difference between full and limited power of attorney for securities accounts?","choices":{"A":"Only full POA allows trading","B":"Full POA allows fund withdrawals while limited POA does not","C":"Limited POA must be renewed annually","D":"Full POA requires court approval"},"answer":"B","explanation":"The key difference is that full power of attorney allows both trading AND withdrawing funds from the account, while limited power of attorney only authorizes trading. Both allow the agent to make investment decisions, but only full POA permits movement of money.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-013","section":"2 - Products & Risks","stem":"A municipality issues short-term debt to fund a new bridge project while waiting for a long-term bond offering. This type of security is called:","choices":{"A":"Revenue anticipation note (RAN)","B":"Tax anticipation note (TAN)","C":"Bond anticipation note (BAN)","D":"General obligation bond"},"answer":"C","explanation":"Bond Anticipation Notes (BANs) are short-term municipal securities issued to finance construction projects while the municipality awaits a long-term bond offering. BANs are repaid from the proceeds of the future long-term bond issue.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-014","section":"2 - Products & Risks","stem":"How are Bond Anticipation Notes (BANs) typically repaid?","choices":{"A":"From future tax collections","B":"From project revenue once operational","C":"From proceeds of a future long-term bond issue","D":"From federal grants"},"answer":"C","explanation":"BANs are repaid from the proceeds of the future long-term bond offering they anticipate. They provide interim financing for construction while the municipality prepares for a larger, permanent bond issue. TANs are repaid from taxes, and RANs from revenue.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-015","section":"1 - Capital Markets","stem":"In a firm commitment underwriting, the investment bank takes on which role?","choices":{"A":"Agent for the issuer","B":"Principal purchasing the securities","C":"Advisor with no financial risk","D":"Market maker after the offering"},"answer":"B","explanation":"In a firm commitment underwriting, the investment bank acts as a principal, purchasing the entire issue from the company at an agreed price and then reselling to investors. The underwriter bears the risk of unsold securities, unlike best efforts where they act as agent.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-016","section":"1 - Capital Markets","stem":"Which underwriting arrangement places the most financial risk on the investment bank?","choices":{"A":"Best efforts underwriting","B":"All-or-none underwriting","C":"Firm commitment underwriting","D":"Standby underwriting"},"answer":"C","explanation":"Firm commitment underwriting places the most risk on the investment bank because it purchases the entire issue upfront and assumes the risk of any unsold shares. In best efforts, the underwriter acts as agent and returns unsold shares to the issuer without financial loss.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-017","section":"4 - Regulatory Framework","stem":"Which regulatory body is responsible for enforcing the Uniform Securities Act?","choices":{"A":"Securities and Exchange Commission (SEC)","B":"State securities administrators","C":"FINRA","D":"Federal Reserve Board"},"answer":"B","explanation":"The Uniform Securities Act is state law, enforced by individual state securities administrators. The SEC enforces federal securities laws. Each state adopts its own version of the Uniform Securities Act, and state administrators oversee compliance within their jurisdiction.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-018","section":"2 - Products & Risks","stem":"The SEC has enforcement authority over all of the following EXCEPT:","choices":{"A":"Securities Act of 1933","B":"Securities Exchange Act of 1934","C":"Uniform Securities Act","D":"Investment Company Act of 1940"},"answer":"C","explanation":"The SEC enforces federal securities laws including the Securities Acts of 1933 and 1934, and the Investment Company Act of 1940. The Uniform Securities Act is state law, enforced by state securities administrators, not the SEC.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-019","section":"2 - Products & Risks","stem":"An investor owns 200 shares of ABC Corp at $90 per share. After a 2-for-1 forward split, the investor will have:","choices":{"A":"100 shares at $180","B":"200 shares at $90","C":"400 shares at $45","D":"400 shares at $90"},"answer":"C","explanation":"In a 2-for-1 forward split, shares double and price halves. The investor's 200 shares become 400 shares, and the $90 price becomes $45. Total value remains the same: 200 x $90 = $18,000 = 400 x $45 = $18,000.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-020","section":"2 - Products & Risks","stem":"A company announces a 4-for-1 stock split. Which statement is TRUE?","choices":{"A":"The share price will quadruple","B":"The number of outstanding shares will decrease by 75%","C":"Each shareholder's proportionate ownership will decrease","D":"The share price will decrease to one-fourth of its pre-split value"},"answer":"D","explanation":"In a 4-for-1 forward split, each share becomes 4 shares, and the price is divided by 4. Proportionate ownership remains exactly the same. The split increases shares outstanding 4x and reduces price to 1/4. Market capitalization is unchanged.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-021","section":"2 - Products & Risks","stem":"Stock rights are issued with intrinsic value. This means that at issuance:","choices":{"A":"The exercise price equals the current market price","B":"The exercise price is above the current market price","C":"The exercise price is below the current market price","D":"The rights have no value until expiration"},"answer":"C","explanation":"Rights are issued with intrinsic value because the subscription price (exercise price) is set below the current market price. This creates immediate value for shareholders, who can either exercise the rights to buy discounted shares or sell the rights in the market.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-022","section":"2 - Products & Risks","stem":"A shareholder receives preemptive rights but does not want to purchase additional shares. What options are available?","choices":{"A":"The rights must be exercised or they expire worthless","B":"The rights can be sold in the secondary market","C":"The rights must be returned to the company","D":"The rights automatically convert to common stock"},"answer":"B","explanation":"Rights are transferable and can be traded in the secondary market. If a shareholder does not want to exercise their rights, they can sell them to another investor who wants to purchase shares at the discounted subscription price. Rights not exercised or sold will expire worthless.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-023","section":"2 - Products & Risks","stem":"Which characteristic makes Treasury bills classified as money market instruments?","choices":{"A":"They are issued by the federal government","B":"They pay semiannual interest","C":"They have maturities of one year or less","D":"They are backed by the full faith and credit of the U.S."},"answer":"C","explanation":"Money market instruments are defined by their short-term maturities of one year or less. T-bills mature in 4, 8, 13, 26, or 52 weeks. While government backing is a feature, the defining characteristic for money market classification is the short maturity.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-024","section":"2 - Products & Risks","stem":"Which of the following is considered a capital market instrument rather than a money market instrument?","choices":{"A":"13-week Treasury bill","B":"270-day commercial paper","C":"5-year Treasury note","D":"90-day banker's acceptance"},"answer":"C","explanation":"A 5-year Treasury note is a capital market instrument because it has a maturity greater than one year. Money market instruments (T-bills, commercial paper, banker's acceptances) mature in one year or less. Capital market instruments provide long-term funding.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-025","section":"2 - Products & Risks","stem":"Which share class is most appropriate for an investor planning to invest $8,000 in a mutual fund and hold for 10 years?","choices":{"A":"Class A shares","B":"Class B shares","C":"Class C shares","D":"No-load shares"},"answer":"B","explanation":"Class B shares are designed for long-term investors with smaller purchases who cannot reach breakpoints. B shares have no front-end load, a declining CDSC that typically disappears after 6-8 years, and convert to A shares after the CDSC period. For $8,000 held 10 years, B shares are appropriate.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-026","section":"2 - Products & Risks","stem":"What happens to Class B mutual fund shares after the contingent deferred sales charge period ends?","choices":{"A":"They are automatically redeemed","B":"They convert to Class A shares","C":"The expense ratio increases","D":"They continue as Class B with higher 12b-1 fees"},"answer":"B","explanation":"Class B shares automatically convert to Class A shares after the CDSC period ends (typically 6-8 years). This conversion benefits investors because Class A shares have lower ongoing 12b-1 fees. Without conversion, long-term B share holders would pay higher expenses indefinitely.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-027","section":"2 - Products & Risks","stem":"A corporate bond is quoted at 93 1/4. What is the dollar price for a $1,000 par value bond?","choices":{"A":"$931.25","B":"$932.50","C":"$934.00","D":"$9,325.00"},"answer":"B","explanation":"Corporate bonds are quoted as a percentage of par value in fractions. 93 1/4 = 93.25% of par. For a $1,000 bond: $1,000 x 0.9325 = $932.50. The bond trades at a discount (below par) because 93.25% is less than 100%.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-028","section":"2 - Products & Risks","stem":"An investor purchases a corporate bond quoted at 104 3/8. How much will the investor pay?","choices":{"A":"$1,003.75","B":"$1,043.75","C":"$1,043.80","D":"$10,437.50"},"answer":"B","explanation":"Corporate bond pricing: 104 3/8 = 104.375% of par. For a $1,000 bond: $1,000 x 1.04375 = $1,043.75. The bond trades at a premium (above par). Remember: 3/8 = 0.375.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-029","section":"4 - Regulatory Framework","stem":"Under FINRA's IPO allocation rules, which individual would be PROHIBITED from purchasing shares in a hot IPO?","choices":{"A":"A customer with a $5 million account","B":"The spouse of a registered representative at the underwriting firm","C":"A customer who has never purchased an IPO before","D":"An institutional investor with no connection to the underwriter"},"answer":"B","explanation":"FINRA Rule 5130 prohibits immediate family members of broker-dealer employees from purchasing shares in a hot IPO (one that trades at a premium immediately). This prevents industry insiders and their families from receiving favorable allocations at the expense of regular investors.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-030","section":"1 - Capital Markets","stem":"A registered representative's adult child requests to purchase shares in a hot IPO. The representative should:","choices":{"A":"Allow the purchase since the child is not a minor","B":"Allow the purchase if the child has a separate account at another firm","C":"Deny the purchase as immediate family members are restricted","D":"Allow the purchase with principal approval"},"answer":"C","explanation":"Immediate family members of broker-dealer employees are restricted from purchasing hot IPOs under FINRA Rule 5130, regardless of age or whether they have accounts at other firms. The restriction exists to prevent industry insiders from gaining unfair access to profitable new issues.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-031","section":"4 - Regulatory Framework","stem":"Which type of market structure is characterized by a single seller and heavy government regulation?","choices":{"A":"Perfect competition","B":"Oligopoly","C":"Monopoly","D":"Monopsony"},"answer":"C","explanation":"A monopoly has a single seller controlling the entire market with no close substitutes. Because there is no competition, monopolies are heavily regulated to prevent abuse of market power. Utilities are classic examples of regulated monopolies.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-032","section":"4 - Regulatory Framework","stem":"Why are monopolies typically subject to government regulation?","choices":{"A":"To encourage new competitors to enter the market","B":"To prevent the monopolist from raising prices excessively","C":"To help the monopolist expand into new markets","D":"To eliminate the need for antitrust enforcement"},"answer":"B","explanation":"Monopolies are regulated because without competition, the single seller could charge excessive prices and reduce output. Regulation aims to protect consumers by controlling pricing, ensuring adequate service, and preventing abuse of market power. Utilities are examples of regulated monopolies.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-033","section":"2 - Products & Risks","stem":"Which variable annuity funding and payout combination is NOT available?","choices":{"A":"Single premium with immediate payout","B":"Periodic premiums with deferred payout","C":"Single premium with deferred payout","D":"All of the above combinations are available"},"answer":"D","explanation":"Variable annuities offer maximum flexibility. All combinations of funding (single premium or periodic) and payout timing (immediate or deferred) are available. Single Premium Immediate Annuities (SPIAs), Single Premium Deferred Annuities (SPDAs), and flexible premium deferred annuities are all common products.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-034","section":"2 - Products & Risks","stem":"An investor wants to make a single payment and begin receiving income immediately. Which annuity product would be appropriate?","choices":{"A":"Flexible premium deferred annuity","B":"Single premium immediate annuity (SPIA)","C":"Periodic premium deferred annuity","D":"Variable universal life insurance"},"answer":"B","explanation":"A Single Premium Immediate Annuity (SPIA) is designed for investors who want to make one lump-sum payment and begin receiving periodic income immediately. This is commonly used by retirees to convert assets into a guaranteed income stream.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-035","section":"2 - Products & Risks","stem":"NYSE-listed securities that trade over-the-counter are said to trade in the:","choices":{"A":"Primary market","B":"Second market","C":"Third market","D":"Fourth market"},"answer":"C","explanation":"The third market refers to exchange-listed securities that trade over-the-counter (OTC) rather than on the exchange. This allows trading outside of exchange hours and potentially better execution for large orders. The second market is simply the secondary market (exchanges).","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-036","section":"4 - Regulatory Framework","stem":"Which market involves institutional investors trading directly with each other without broker intermediaries?","choices":{"A":"Primary market","B":"Second market","C":"Third market","D":"Fourth market"},"answer":"D","explanation":"The fourth market consists of direct trading between institutional investors without broker intermediaries, often through electronic communication networks (ECNs). This provides cost savings and anonymity for large trades. Examples include Instinet and POSIT.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-037","section":"2 - Products & Risks","stem":"Which type of corporate bond is secured by a lien on company property?","choices":{"A":"Debenture","B":"Collateral trust bond","C":"Mortgage bond","D":"Equipment trust certificate"},"answer":"C","explanation":"Mortgage bonds are secured by a lien on real property (land, buildings). If the issuer defaults, bondholders can foreclose on the property. Collateral trust bonds are secured by securities, equipment trust certificates by equipment, and debentures are unsecured.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-038","section":"2 - Products & Risks","stem":"An investor concerned about default risk should prefer which type of corporate bond?","choices":{"A":"Subordinated debentures","B":"Income bonds","C":"Mortgage bonds","D":"Zero-coupon bonds"},"answer":"C","explanation":"Mortgage bonds offer the best protection against default risk because they are secured by real property. In a bankruptcy, mortgage bondholders have a priority claim on the collateral. Subordinated debentures are unsecured and rank below other debt. Income bonds only pay interest if earnings permit.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-039","section":"2 - Products & Risks","stem":"The federal government's decisions about taxation and spending represent:","choices":{"A":"Monetary policy","B":"Fiscal policy","C":"Credit policy","D":"Reserve requirements"},"answer":"B","explanation":"Fiscal policy involves government decisions about taxation and spending, implemented by Congress and the President. This is distinct from monetary policy, which is controlled by the Federal Reserve and involves managing money supply and interest rates.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-040","section":"2 - Products & Risks","stem":"Which entity does NOT have authority over monetary policy?","choices":{"A":"Federal Open Market Committee","B":"Board of Governors of the Federal Reserve","C":"U.S. Congress","D":"Federal Reserve Banks"},"answer":"C","explanation":"Congress does not control monetary policy; it controls fiscal policy through taxation and spending decisions. Monetary policy is the domain of the Federal Reserve System, including the FOMC, Board of Governors, and Federal Reserve Banks. The Fed operates independently of Congress.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-041","section":"4 - Regulatory Framework","stem":"When a registered representative voluntarily resigns from their broker-dealer, which form must the firm file?","choices":{"A":"Form U-4","B":"Form U-5","C":"Form U-6","D":"Form BD"},"answer":"B","explanation":"Form U-5 (Uniform Termination Notice) must be filed within 30 days when a registered representative leaves a firm, whether voluntarily or involuntarily. Form U-4 is for registration, Form BD is for broker-dealer registration. There is no Form U-6 in securities registration.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-042","section":"4 - Regulatory Framework","stem":"A broker-dealer must file Form U-5 within how many days of a representative's termination?","choices":{"A":"10 days","B":"15 days","C":"30 days","D":"60 days"},"answer":"C","explanation":"FINRA requires broker-dealers to file Form U-5 within 30 days of a registered representative's termination. This applies whether the departure is voluntary or involuntary. The form discloses the reason for termination and any regulatory issues.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-043","section":"2 - Products & Risks","stem":"A client seeks both capital appreciation and current income from a single mutual fund. Which fund type best meets this objective?","choices":{"A":"Growth fund","B":"Income fund","C":"Balanced fund","D":"Sector fund"},"answer":"C","explanation":"Balanced funds invest in both stocks (for growth) and bonds (for income), providing a combination of capital appreciation and current income. Growth funds focus only on appreciation, income funds focus on current income, and sector funds concentrate in specific industries.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-044","section":"2 - Products & Risks","stem":"Which statement is TRUE regarding balanced funds?","choices":{"A":"They invest exclusively in dividend-paying stocks","B":"They maintain positions in both equity and fixed-income securities","C":"They are more volatile than aggressive growth funds","D":"They focus on a single sector of the economy"},"answer":"B","explanation":"Balanced funds maintain allocations to both stocks and bonds, typically around 60% stocks and 40% bonds. This diversification across asset classes provides growth potential from equities and income/stability from fixed income, making them less volatile than pure equity funds.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-045","section":"2 - Products & Risks","stem":"A registered representative leaves the securities industry. After how long will the representative's securities licenses lapse?","choices":{"A":"1 year","B":"2 years","C":"4 years","D":"5 years"},"answer":"B","explanation":"If a registered representative leaves the industry and does not re-associate with a FINRA member firm within 2 years, their representative-level licenses (Series 7, 6, 63, etc.) lapse. The SIE remains valid for 4 years. After lapsing, the individual must retake the qualification exams.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-046","section":"2 - Products & Risks","stem":"A Series 7 representative left the industry 18 months ago. To return to the industry now, the representative must:","choices":{"A":"Retake only the SIE exam","B":"Retake both the SIE and Series 7 exams","C":"Associate with a firm and resume working without retaking exams","D":"Wait until 2 years have passed before rejoining"},"answer":"C","explanation":"Since only 18 months have passed (less than 2 years), the representative's Series 7 license has not lapsed and remains valid. The representative can simply associate with a new FINRA member firm and resume registered activities without retaking any exams.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-047","section":"2 - Products & Risks","stem":"When inflation rises significantly, what typically happens to interest rates?","choices":{"A":"Interest rates decrease to stimulate growth","B":"Interest rates remain unchanged","C":"Interest rates increase to combat inflation","D":"Interest rates are unrelated to inflation"},"answer":"C","explanation":"Interest rates and inflation have a positive correlation. When inflation rises, the Federal Reserve typically raises interest rates to slow economic activity and bring inflation under control. Higher rates make borrowing more expensive, reducing spending and investment.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-048","section":"2 - Products & Risks","stem":"What is the relationship between interest rates and inflation called?","choices":{"A":"Inverse correlation","B":"Positive correlation","C":"No correlation","D":"Lagging correlation"},"answer":"B","explanation":"Interest rates and inflation have a positive correlation - they tend to move in the same direction. When inflation increases, interest rates typically rise as the Fed tightens monetary policy. This positive relationship is a fundamental concept in economics and investing.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-049","section":"1 - Capital Markets","stem":"Municipal general obligation bonds in the secondary market are typically quoted on what basis?","choices":{"A":"Dollar price","B":"Yield to maturity","C":"Percentage of par","D":"Premium or discount amount"},"answer":"B","explanation":"Municipal bonds, especially general obligation bonds, are typically quoted on a yield basis (yield to maturity or YTM) in the secondary market. This allows easier comparison between bonds with different coupons and maturities. Corporate bonds are quoted on a dollar price basis.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-siepb2-050","section":"2 - Products & Risks","stem":"A municipal bond quoted at 4.50 is being offered at:","choices":{"A":"$45.00 per bond","B":"$450.00 per bond","C":"4.50% yield to maturity","D":"4.50% above par value"},"answer":"C","explanation":"Municipal bonds are quoted on a yield basis. A quote of 4.50 means the bond is offered at a price that would provide a 4.50% yield to maturity. This is different from corporate bonds, which are quoted as a percentage of par (like 104.50 meaning 104.5% of par).","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-051a","section":"2 - Products & Risks","stem":"A shareholder who cannot physically attend a corporation's annual meeting may still participate in voting decisions by:","choices":{"A":"Calling the company's investor relations department during the meeting","B":"Submitting a proxy form that authorizes another party to vote on their behalf","C":"Sending a letter to the CEO expressing their voting preferences","D":"Waiting until the next quarterly meeting to cast their vote"},"answer":"B","explanation":"Shareholders who cannot attend annual meetings in person can participate in voting by submitting a proxy. A proxy is a written authorization that allows another party (typically company management or a designated proxy holder) to vote on the shareholder's behalf.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-051b","section":"3 - Trading, Accounts & Prohibited","stem":"What document allows a common stockholder to transfer their voting rights to another party when they cannot attend the annual shareholders' meeting?","choices":{"A":"Power of attorney","B":"Stock certificate","C":"Proxy statement","D":"Tender offer"},"answer":"C","explanation":"A proxy statement (or proxy card) allows shareholders to transfer their voting rights to another party. Corporations send proxy materials to shareholders before annual meetings, enabling those who cannot attend to still exercise their voting rights.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-052a","section":"2 - Products & Risks","stem":"Which U.S. Treasury security would be LEAST affected by changes in interest rates?","choices":{"A":"30-year Treasury bonds","B":"10-year Treasury notes","C":"5-year Treasury notes","D":"13-week Treasury bills"},"answer":"D","explanation":"Interest rate risk is directly related to maturity - the shorter the maturity, the lower the interest rate risk. Treasury bills with 13-week maturities have the shortest duration among the options, making them least sensitive to interest rate fluctuations.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-052b","section":"2 - Products & Risks","stem":"An investor concerned about interest rate risk but wanting to invest in government securities should consider which of the following?","choices":{"A":"Treasury bonds maturing in 20+ years","B":"Treasury STRIPS","C":"Treasury bills maturing in 4-52 weeks","D":"Zero-coupon Treasury securities"},"answer":"C","explanation":"Treasury bills have maturities ranging from 4 to 52 weeks, making them the shortest-term Treasury securities. Short-term securities have minimal interest rate risk because their prices are less sensitive to rate changes due to their short duration.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-053a","section":"2 - Products & Risks","stem":"A mutual fund that primarily invests in investment-grade corporate bonds would be classified as which type of fund?","choices":{"A":"Growth fund","B":"Income fund","C":"Aggressive growth fund","D":"Sector fund"},"answer":"B","explanation":"A fund investing primarily in corporate bonds is classified as an income fund. Income funds focus on generating regular income through interest payments from bonds and dividends from stocks, rather than capital appreciation.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-053b","section":"2 - Products & Risks","stem":"An investor seeking regular interest payments would be MOST suited for which type of mutual fund?","choices":{"A":"Small-cap growth fund","B":"Technology sector fund","C":"Corporate bond income fund","D":"International equity fund"},"answer":"C","explanation":"A corporate bond income fund is designed for investors seeking regular interest payments. These funds invest in corporate bonds that pay periodic interest, making them ideal for income-oriented investors.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-054a","section":"2 - Products & Risks","stem":"For tax reporting purposes, when does a taxable event occur for a cash dividend received by an investor?","choices":{"A":"Declaration date","B":"Ex-dividend date","C":"Record date","D":"Payable date"},"answer":"D","explanation":"The taxable event for dividends occurs on the payable date, which is when the investor actually receives the dividend payment. Even if using cash basis accounting, this is when the income is recognized for tax purposes.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-054b","section":"4 - Regulatory Framework","stem":"XYZ Corporation declares a dividend on March 1, with an ex-date of March 15, record date of March 17, and payable date of April 1. For an investor receiving this dividend, in which year would they report it as taxable income?","choices":{"A":"The year containing March 1 (declaration date)","B":"The year containing March 15 (ex-dividend date)","C":"The year containing March 17 (record date)","D":"The year containing April 1 (payable date)"},"answer":"D","explanation":"Dividends are taxable in the year they are received, which is the payable date. In this case, the investor would report the dividend as taxable income in the year containing April 1, when the dividend was actually paid.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-055a","section":"2 - Products & Risks","stem":"A company wants to raise capital by selling securities only to residents of the state where it is incorporated and does business. Which SEC rule provides an exemption for this type of offering?","choices":{"A":"Rule 144","B":"Rule 144A","C":"Rule 147","D":"Rule 506"},"answer":"C","explanation":"Rule 147 (and Rule 147A) provides a safe harbor exemption for intrastate offerings. The issuer must be organized and doing business in the state, and all offerees and purchasers must be residents of that same state.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-055b","section":"2 - Products & Risks","stem":"Under Rule 147, which of the following would disqualify an offering from the intrastate exemption?","choices":{"A":"The issuer operates primarily in one state","B":"The offering is sold to residents of the same state as the issuer","C":"One of the purchasers resides in a different state","D":"The issuer is incorporated in the state where it sells securities"},"answer":"C","explanation":"Rule 147 requires that ALL offerees and purchasers be residents of the same state where the issuer is organized and doing business. Even a single out-of-state purchaser would disqualify the entire offering from the intrastate exemption.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-056a","section":"3 - Trading, Accounts & Prohibited","stem":"By what age must all assets in a Coverdell Education Savings Account be distributed to avoid tax penalties?","choices":{"A":"Age 18","B":"Age 21","C":"Age 30","D":"Age 59½"},"answer":"C","explanation":"Coverdell ESA assets must be distributed by the time the beneficiary reaches age 30. If not used for qualified education expenses by then, the remaining balance is subject to income tax plus a 10% penalty on earnings.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-056b","section":"3 - Trading, Accounts & Prohibited","stem":"If a Coverdell ESA beneficiary turns 30 and has $5,000 remaining in the account that was never used for education expenses, what are the tax consequences?","choices":{"A":"No tax consequences if rolled to a 529 plan","B":"The earnings portion is subject to income tax plus a 10% penalty","C":"The entire balance is forfeited to the government","D":"The beneficiary has until age 35 to use the remaining funds"},"answer":"B","explanation":"When a Coverdell ESA beneficiary reaches age 30 without using all the funds for qualified education expenses, the earnings portion of any remaining balance is subject to ordinary income tax plus a 10% penalty. The contribution basis is returned tax-free.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-057a","section":"2 - Products & Risks","stem":"In a mutual fund structure, which entity is responsible for the physical safekeeping of the fund's portfolio securities?","choices":{"A":"The investment adviser","B":"The transfer agent","C":"The custodian bank","D":"The principal underwriter"},"answer":"C","explanation":"The custodian bank (or custodian) holds and safeguards the mutual fund's portfolio securities. This separation of duties protects investors by ensuring the fund's assets are held by an independent third party.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-057b","section":"3 - Trading, Accounts & Prohibited","stem":"Which of the following is a key function of a mutual fund's custodian?","choices":{"A":"Selecting which securities to purchase for the portfolio","B":"Marketing fund shares to potential investors","C":"Holding the fund's cash and securities in safekeeping","D":"Processing purchases and redemptions of fund shares"},"answer":"C","explanation":"The custodian's primary function is holding the fund's cash and securities in safekeeping. Custodians, typically commercial banks, provide a secure location for the fund's assets and handle the physical receipt and delivery of securities.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-058a","section":"2 - Products & Risks","stem":"A REIT that invests in both commercial properties and mortgage-backed securities would be classified as:","choices":{"A":"Equity REIT","B":"Mortgage REIT","C":"Hybrid REIT","D":"Specialty REIT"},"answer":"C","explanation":"A Hybrid REIT combines features of both equity REITs (which own physical properties) and mortgage REITs (which invest in mortgages and mortgage-backed securities). This provides diversification across both property ownership and real estate lending.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-058b","section":"2 - Products & Risks","stem":"Which type of REIT would generate income from BOTH rental payments on owned properties AND interest on real estate loans?","choices":{"A":"Equity REIT","B":"Mortgage REIT","C":"Hybrid REIT","D":"Private REIT"},"answer":"C","explanation":"A Hybrid REIT generates income from both sources: rental income from owned properties (like an equity REIT) and interest income from mortgages and real estate loans (like a mortgage REIT). This dual income stream provides diversification.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-059a","section":"4 - Regulatory Framework","stem":"For a security trading with cash settlement (same-day settlement), when is the ex-dividend date relative to the record date?","choices":{"A":"Two business days before the record date","B":"One business day before the record date","C":"The same day as the record date","D":"One business day after the record date"},"answer":"C","explanation":"For cash settlement trades (T+0), the ex-dividend date is the same day as the record date. Since the trade settles immediately, the buyer must purchase before the record date to be the owner of record and receive the dividend.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-059b","section":"4 - Regulatory Framework","stem":"An investor purchases stock for cash settlement on the same day as the record date. Will they receive the declared dividend?","choices":{"A":"Yes, because cash settlement means they are owner of record that day","B":"No, because they needed to buy one day before the record date","C":"Yes, but only if they purchased before noon","D":"No, because dividends only go to shareholders who held for at least T+2"},"answer":"A","explanation":"With cash settlement (T+0), the trade settles the same day. If the investor purchases on the record date, they become the owner of record that day and will receive the dividend. For cash settlement, the ex-date equals the record date.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-060a","section":"2 - Products & Risks","stem":"A pharmaceutical company's stock declines after the FDA announces stricter approval requirements for new drugs. This is an example of:","choices":{"A":"Market risk","B":"Business risk","C":"Regulatory risk","D":"Credit risk"},"answer":"C","explanation":"Regulatory risk is the risk that government agencies or regulatory bodies will impose new rules, restrictions, or requirements that negatively impact a company or industry. The FDA imposing stricter requirements is a classic example of regulatory risk.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-060b","section":"4 - Regulatory Framework","stem":"Which of the following represents regulatory risk for a financial services firm?","choices":{"A":"A downturn in the overall stock market","B":"A major client defaulting on a loan","C":"New SEC rules requiring increased compliance costs","D":"The firm's CEO unexpectedly resigning"},"answer":"C","explanation":"Regulatory risk occurs when government agencies impose new rules or regulations that increase costs or restrict business activities. New SEC compliance requirements represent regulatory risk as they directly impact how the firm must operate and its associated costs.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-061a","section":"2 - Products & Risks","stem":"Commercial paper is primarily purchased by which type of investor?","choices":{"A":"Individual retail investors","B":"Small business owners","C":"Institutional investors such as money market funds","D":"First-time investors building a portfolio"},"answer":"C","explanation":"Commercial paper is typically issued in large denominations ($100,000 or more) and sold primarily to institutional investors like money market funds, banks, and corporations. The high minimum investment effectively excludes most retail investors.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-061b","section":"2 - Products & Risks","stem":"Why do retail investors typically NOT invest directly in commercial paper?","choices":{"A":"Commercial paper is only available to foreign investors","B":"The minimum denomination is typically too high for retail investors","C":"Commercial paper must be held for at least 10 years","D":"Retail investors are prohibited by law from buying commercial paper"},"answer":"B","explanation":"Commercial paper is typically issued in denominations of $100,000 or more, making it impractical for most retail investors. However, retail investors can gain exposure to commercial paper indirectly through money market funds that invest in these instruments.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-062a","section":"3 - Trading, Accounts & Prohibited","stem":"An investor places a limit order to buy 100 shares of XYZ at $50. Which of the following is TRUE about this order?","choices":{"A":"The order will execute immediately at the current market price","B":"The order will only execute at $50 or lower","C":"The order will execute at the next available price, regardless of amount","D":"The order guarantees execution within the trading day"},"answer":"B","explanation":"A buy limit order specifies the maximum price the investor is willing to pay. The order will only execute at the limit price ($50) or lower (better). While limit orders guarantee price, they do not guarantee execution.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-062b","section":"3 - Trading, Accounts & Prohibited","stem":"A sell limit order is placed at $75. At what price(s) could this order be executed?","choices":{"A":"Only at exactly $75","B":"At $75 or higher","C":"At $75 or lower","D":"At any price close to $75"},"answer":"B","explanation":"A sell limit order sets a minimum acceptable selling price. The order will execute only at the limit price ($75) or higher (better for the seller). This protects the seller from receiving less than their specified price.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-063a","section":"4 - Regulatory Framework","stem":"A broker-dealer routes a customer order through an affiliate firm that adds a markup before sending it to the market, even though direct market access was available. This practice is known as:","choices":{"A":"Front running","B":"Interpositioning","C":"Churning","D":"Bucketing"},"answer":"B","explanation":"Interpositioning is the unethical practice of inserting an unnecessary intermediary into a transaction, typically resulting in additional costs to the customer. FINRA prohibits this practice when it does not benefit the customer.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-063b","section":"4 - Regulatory Framework","stem":"Which FINRA violation involves adding an unnecessary party to a securities transaction that increases customer costs without providing any benefit?","choices":{"A":"Selling away","B":"Free riding","C":"Interpositioning","D":"Painting the tape"},"answer":"C","explanation":"Interpositioning occurs when a broker inserts a third party (middleman) into a transaction without justification, resulting in additional costs to the customer. This violates the broker's duty to seek best execution for customer orders.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-064a","section":"1 - Capital Markets","stem":"Securities that trade through a network of dealers rather than on a centralized exchange are said to trade:","choices":{"A":"On the primary market","B":"Over-the-counter (OTC)","C":"Through direct listing","D":"Via auction market"},"answer":"B","explanation":"Over-the-counter (OTC) trading occurs through a decentralized network of dealers, not on a centralized exchange like the NYSE. OTC markets include the OTC Bulletin Board and Pink Sheets for stocks, as well as the bond and forex markets.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-064b","section":"1 - Capital Markets","stem":"Which of the following securities typically trades over-the-counter rather than on an exchange?","choices":{"A":"NYSE-listed common stock","B":"S&P 500 index options","C":"Corporate bonds","D":"Exchange-traded funds"},"answer":"C","explanation":"Corporate bonds primarily trade over-the-counter through dealer networks rather than on exchanges. Most bond trading occurs OTC, where dealers negotiate prices directly with customers or other dealers.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-065a","section":"4 - Regulatory Framework","stem":"When a firm acts as an agent in a securities transaction, it earns compensation in the form of:","choices":{"A":"Markup on the sale price","B":"Commission","C":"Markdown on the purchase price","D":"Spread between bid and ask"},"answer":"B","explanation":"When acting as an agent (broker), the firm facilitates a transaction between buyer and seller without taking ownership of the securities. Brokers are compensated through commissions charged to the customer.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-065b","section":"4 - Regulatory Framework","stem":"A customer sells bonds to a broker-dealer who buys them for the firm's own inventory. The firm's compensation in this transaction is called:","choices":{"A":"Commission","B":"Sales charge","C":"Markdown","D":"Service fee"},"answer":"C","explanation":"When a dealer purchases securities from a customer for its own inventory, it acts as principal. The dealer's compensation is a markdown, which is the difference between the price paid to the customer and the current market value.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-066a","section":"2 - Products & Risks","stem":"Which of the following bonds would be MOST sensitive to interest rate changes?","choices":{"A":"2-year Treasury note","B":"5-year corporate bond","C":"10-year municipal bond","D":"30-year Treasury bond"},"answer":"D","explanation":"Interest rate sensitivity increases with maturity. The 30-year Treasury bond has the longest maturity among the options, giving it the highest duration and making it most sensitive to interest rate changes.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-066b","section":"2 - Products & Risks","stem":"If interest rates rise by 1%, which bond would experience the largest price decline?","choices":{"A":"1-year certificate of deposit","B":"5-year Treasury note","C":"15-year corporate bond","D":"30-year zero-coupon bond"},"answer":"D","explanation":"The 30-year zero-coupon bond would experience the largest price decline for two reasons: it has the longest maturity (greatest duration), and zero-coupon bonds are more sensitive to rate changes than coupon-bearing bonds of the same maturity.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-067a","section":"4 - Regulatory Framework","stem":"Under UGMA/UTMA regulations, which of the following activities is PROHIBITED in a custodial account?","choices":{"A":"Investing in mutual funds","B":"Trading on margin","C":"Purchasing common stock","D":"Receiving dividend payments"},"answer":"B","explanation":"Custodial accounts (UGMA/UTMA) cannot use margin trading because the custodian has a fiduciary duty to protect the minor's assets. Margin trading introduces the risk of losing more than the original investment, which is inappropriate for minors.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-067b","section":"3 - Trading, Accounts & Prohibited","stem":"A parent acting as custodian for their child's UTMA account wants to increase returns by using leverage. Can the custodian open a margin account for the UTMA?","choices":{"A":"Yes, with proper documentation from the broker-dealer","B":"Yes, if the child's assets exceed $10,000","C":"No, margin trading is prohibited in custodial accounts","D":"No, unless the custodian provides a written guarantee"},"answer":"C","explanation":"Margin trading is prohibited in UGMA/UTMA custodial accounts regardless of the account value or documentation provided. The fiduciary duty to the minor beneficiary prevents the use of leverage, which could result in losses exceeding the account value.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-068a","section":"1 - Capital Markets","stem":"When an investor buys shares of Apple stock on the New York Stock Exchange, they are participating in the:","choices":{"A":"Primary market","B":"Secondary market","C":"Third market","D":"Initial offering market"},"answer":"B","explanation":"Trading existing securities on exchanges like the NYSE is secondary market activity. The primary market is where new securities are first issued (IPOs), while the secondary market is where previously issued securities are traded among investors.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-068b","section":"1 - Capital Markets","stem":"Which of the following is a characteristic of secondary market transactions?","choices":{"A":"The issuing company receives the proceeds from the sale","B":"Securities are being sold to the public for the first time","C":"Existing securities are traded between investors","D":"Investment banks underwrite the transaction"},"answer":"C","explanation":"In secondary market transactions, existing securities are traded between investors. The issuing company does not receive proceeds from these trades - the selling investor receives payment from the buying investor.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-069a","section":"2 - Products & Risks","stem":"A company wants to issue stock to the public for the first time. Which type of financial institution typically manages this process?","choices":{"A":"Commercial bank","B":"Investment bank","C":"Credit union","D":"Savings and loan"},"answer":"B","explanation":"Investment banks specialize in underwriting public offerings, including IPOs. They help companies structure the offering, set the initial price, market the securities to investors, and often guarantee the sale by purchasing the shares themselves.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-069b","section":"1 - Capital Markets","stem":"In a firm commitment underwriting, the investment bank:","choices":{"A":"Sells securities on a best efforts basis with no guarantee","B":"Purchases all securities from the issuer and resells them to the public","C":"Acts only as an advisor without taking financial risk","D":"Waits for investor orders before committing to the offering"},"answer":"B","explanation":"In a firm commitment underwriting, the investment bank purchases all the securities from the issuer at a fixed price, assuming the risk of reselling them to the public. The underwriter profits from the spread between the purchase and resale prices.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-070a","section":"4 - Regulatory Framework","stem":"According to SEC record retention requirements, how long must a broker-dealer retain minutes of board of directors meetings?","choices":{"A":"3 years","B":"6 years","C":"10 years","D":"Lifetime of the firm"},"answer":"D","explanation":"Board of directors meeting minutes must be retained for the lifetime of the firm. These are considered permanent records that document corporate governance decisions and must be preserved as long as the firm exists.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-070b","section":"4 - Regulatory Framework","stem":"Which of the following broker-dealer records must be retained permanently (for the life of the firm)?","choices":{"A":"Customer account statements","B":"Trade confirmations","C":"Minutes of partners' or directors' meetings","D":"Order tickets"},"answer":"C","explanation":"Minutes of partners' or directors' meetings are classified as lifetime records and must be retained for the life of the firm. These documents record fundamental corporate decisions and governance actions.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-071a","section":"4 - Regulatory Framework","stem":"A broker-dealer receives a power of attorney form from a customer authorizing another person to trade on their behalf. For how long must this document be retained?","choices":{"A":"3 years","B":"6 years","C":"10 years","D":"Lifetime of the account"},"answer":"B","explanation":"Power of attorney forms are customer account documents that must be retained for 6 years. This retention period applies to most customer-related documentation including account agreements, trading authorizations, and correspondence.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-071b","section":"4 - Regulatory Framework","stem":"Which record retention period applies to customer trading authorizations and discretionary account agreements?","choices":{"A":"3 years from the date of creation","B":"6 years from the date of creation","C":"Until the account is closed","D":"Permanently"},"answer":"B","explanation":"Trading authorizations and discretionary account agreements are customer account records requiring 6-year retention. This includes power of attorney forms, limited trading authorizations, and any documents granting authority over customer accounts.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-072a","section":"2 - Products & Risks","stem":"When preemptive rights are first issued to shareholders, which component of their value is typically more significant?","choices":{"A":"Time value only, as they have no intrinsic value initially","B":"Intrinsic value only, as they have no time value","C":"Both intrinsic value and time value are significant","D":"Neither, as rights have no value when issued"},"answer":"C","explanation":"When rights are issued, they typically have both intrinsic value (the difference between market price and subscription price) AND time value (value based on time until expiration). Both components contribute to the right's total value.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-072b","section":"2 - Products & Risks","stem":"Which statement about stock rights at issuance is FALSE?","choices":{"A":"Rights may have intrinsic value if the market price exceeds the subscription price","B":"Rights have time value because there is time remaining until expiration","C":"Rights have NO time value and only intrinsic value matters","D":"Rights can be sold in the secondary market"},"answer":"C","explanation":"The FALSE statement is that rights have no time value. In reality, rights DO have time value at issuance because there is time remaining until expiration. Like options, rights have both intrinsic value (if any) and time value.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-073a","section":"2 - Products & Risks","stem":"A corporate bond has a call price of 103. What is the call premium per $1,000 bond?","choices":{"A":"$3","B":"$30","C":"$103","D":"$1,030"},"answer":"B","explanation":"The call premium is the amount above par value that the issuer must pay to call the bond. A call price of 103 means 103% of par ($1,030). The premium is $1,030 - $1,000 = $30 per bond.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-073b","section":"1 - Capital Markets","stem":"An issuer calls a bond at 105. For a bondholder owning 10 bonds, what is the total call premium received above par value?","choices":{"A":"$50","B":"$500","C":"$1,050","D":"$10,500"},"answer":"B","explanation":"A call price of 105 means 105% of par, or $1,050 per $1,000 bond. The premium per bond is $1,050 - $1,000 = $50. For 10 bonds: $50 x 10 = $500 total call premium.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-074a","section":"3 - Trading, Accounts & Prohibited","stem":"Which of the following information is typically included on an order ticket?","choices":{"A":"Customer's Social Security Number","B":"Current market price of the security","C":"Time limitations on the order (day, GTC, etc.)","D":"Customer's tax identification number"},"answer":"C","explanation":"Order tickets include time constraints such as day orders, Good-Till-Cancelled (GTC), or specific time limitations. Order tickets do NOT include the customer's SSN, TIN, or the current market price at the time of order entry.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-074b","section":"3 - Trading, Accounts & Prohibited","stem":"Which item would NOT be found on a customer order ticket?","choices":{"A":"Whether the order is a buy or sell","B":"The quantity of shares or bonds","C":"The customer's Tax Identification Number","D":"Whether the order is a limit or market order"},"answer":"C","explanation":"A customer's Tax Identification Number (TIN) is not included on order tickets. TINs are collected during account opening and maintained in account records. Order tickets contain transaction-specific information like buy/sell, quantity, order type, and time constraints.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-075a","section":"3 - Trading, Accounts & Prohibited","stem":"Standard equity options contracts expire at what time on expiration Friday?","choices":{"A":"4:00 PM ET (market close)","B":"5:30 PM ET","C":"11:59 PM ET","D":"12:00 midnight CT"},"answer":"C","explanation":"Standard equity options expire at 11:59 PM Eastern Time on the third Friday of the expiration month. This gives investors until the end of the day to make exercise decisions, even after the market closes.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-b3-075b","section":"4 - Regulatory Framework","stem":"An options holder wants to exercise their option on expiration Friday. By what time must they notify their broker of their exercise decision?","choices":{"A":"Before market open at 9:30 AM ET","B":"Before market close at 4:00 PM ET","C":"By their broker's exercise cutoff time, which may be before the 11:59 PM ET expiration","D":"Anytime before midnight ET"},"answer":"C","explanation":"While options officially expire at 11:59 PM ET, brokers typically set earlier cutoff times (often 4:00-5:30 PM ET) for exercise instructions. Investors must check their broker's specific requirements to ensure timely exercise notification.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-alt-001","section":"2 - Products & Risks","stem":"Which type of REIT generates income primarily by collecting rent from tenants who lease commercial properties?","choices":{"A":"Mortgage REIT","B":"Equity REIT","C":"Hybrid REIT","D":"Private REIT"},"answer":"B","explanation":"Equity REITs acquire and manage commercial real estate properties such as hotels, apartment complexes, office buildings, and shopping centers. They generate revenue primarily by collecting rent from tenants and businesses that lease the properties. Mortgage REITs, by contrast, invest in mortgages and generate income from interest payments.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-alt-002","section":"2 - Products & Risks","stem":"Mortgage REITs differ from equity REITs in that mortgage REITs:","choices":{"A":"Own physical real estate properties directly","B":"Generate income from interest on real estate loans","C":"Can benefit from property value appreciation","D":"Are exempt from SEC registration"},"answer":"B","explanation":"Mortgage REITs (also called debt REITs) lend money to real estate buyers and generate revenue by collecting interest on debt instruments such as mortgage loans and mezzanine loans. Unlike equity REITs, mortgage REITs do not own physical real estate, so they cannot benefit from property price appreciation. Equity REITs invest directly in properties.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-alt-003","section":"2 - Products & Risks","stem":"To qualify for favorable tax treatment under Subchapter M, a REIT must distribute what percentage of its net investment income to shareholders?","choices":{"A":"At least 50%","B":"At least 75%","C":"At least 90%","D":"100%"},"answer":"C","explanation":"REITs are subject to Subchapter M (the conduit rule), which allows them to avoid paying corporate-level taxes on income if they distribute at least 90% of their net investment income to shareholders. This pass-through structure means dividends are taxed only at the investor level, avoiding double taxation.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-alt-004","section":"2 - Products & Risks","stem":"Which type of REIT would most likely be affected by rising interest rates?","choices":{"A":"Equity REIT","B":"Mortgage REIT","C":"Hybrid REIT","D":"All REITs are equally affected"},"answer":"B","explanation":"Mortgage REITs are particularly sensitive to interest rate risk because they invest in mortgages and generate income from interest payments. When interest rates rise, the value of existing mortgage holdings typically declines, and borrowing costs increase. While all REITs can be affected by rate changes, mortgage REITs face the most direct impact.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-alt-005","section":"2 - Products & Risks","stem":"Which statement about non-traded REITs is TRUE?","choices":{"A":"They trade on the NYSE and NASDAQ","B":"They offer greater liquidity than publicly traded REITs","C":"They have limited liquidity and may be difficult to sell","D":"They are exempt from all SEC registration requirements"},"answer":"C","explanation":"Non-traded REITs (public non-listed REITs) are registered with the SEC but do not trade on national exchanges. This means they have limited liquidity compared to publicly traded REITs, as investors cannot easily sell shares on a secondary market. Share redemption programs may exist but are often limited or suspended.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-alt-006","section":"1 - Capital Markets","stem":"What is the primary tax advantage of investing in a Direct Participation Program (DPP)?","choices":{"A":"Capital gains are tax-free","B":"Losses and income flow through directly to investors","C":"Dividends are tax-deductible","D":"Investments grow tax-deferred until withdrawal"},"answer":"B","explanation":"The defining feature of DPPs is pass-through taxation. Unlike regular corporations that face double taxation (corporate and shareholder level), DPP profits and losses flow directly through to investors, who report them on their individual tax returns. This single taxation model allows investors to use losses to offset other income.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-alt-007","section":"2 - Products & Risks","stem":"In an oil and gas limited partnership, intangible drilling costs (IDCs) provide which benefit to investors?","choices":{"A":"Guaranteed returns on investment","B":"Tax deductions in the year incurred","C":"Protection against loss of principal","D":"Exemption from passive activity rules"},"answer":"B","explanation":"Intangible drilling costs (IDCs) are tax-deductible expenses not associated with actual drilling equipment, including fuel, relocation costs, and employee wages. These costs can be deducted in the year they are incurred, providing significant upfront tax benefits to investors in oil and gas programs.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-alt-008","section":"2 - Products & Risks","stem":"Which type of oil and gas limited partnership carries the LOWEST risk?","choices":{"A":"Exploratory (wildcat) wells","B":"Developmental wells","C":"Income (stripper) wells","D":"Offshore drilling programs"},"answer":"C","explanation":"Income wells (also called stripper wells) are investments in proven oil wells that are already producing. Since the oil reserves have been confirmed, income wells carry the lowest risk among oil and gas programs. Exploratory (wildcat) wells carry the highest risk as they drill in unproven areas, while developmental wells fall in between.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-alt-009","section":"1 - Capital Markets","stem":"Which of the following is typically NOT organized as a Direct Participation Program?","choices":{"A":"Real estate limited partnership","B":"Oil and gas exploration program","C":"Equipment leasing program","D":"Exchange-traded fund (ETF)"},"answer":"D","explanation":"ETFs are not DPPs - they are investment companies that trade on exchanges. Common types of DPPs include real estate limited partnerships (RELPs), oil and gas programs, equipment leasing programs, and non-traded REITs. DPPs are typically organized as limited partnerships, LLCs, or subchapter S corporations.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-alt-010","section":"1 - Capital Markets","stem":"What is a major liquidity concern with Direct Participation Programs?","choices":{"A":"They can only be sold after 5 years","B":"There is typically no secondary market for trading DPP units","C":"They require SEC approval before selling","D":"They can only be redeemed at the end of each quarter"},"answer":"B","explanation":"DPPs carry significant liquidity risk because there is typically no secondary market for trading limited partnership units. Investors should not invest in DPPs if they need quick access to their funds, as liquidating positions can be extremely difficult or impossible until the program terminates.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-alt-011","section":"2 - Products & Risks","stem":"In a limited partnership, which partner has unlimited liability for the debts of the partnership?","choices":{"A":"Limited partner only","B":"General partner only","C":"Both general and limited partners","D":"Neither partner has unlimited liability"},"answer":"B","explanation":"The general partner (GP) manages the limited partnership and has unlimited liability, meaning personal assets are at risk for partnership debts. Limited partners (LPs) are passive investors whose liability is limited to the amount of their investment. This is a fundamental distinction tested on the SIE exam.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-alt-012","section":"2 - Products & Risks","stem":"Under what circumstance could a limited partner lose their limited liability protection?","choices":{"A":"If they invest more than $100,000","B":"If they actively participate in managing the business","C":"If the partnership operates at a loss","D":"If they hold their investment for more than 10 years"},"answer":"B","explanation":"Limited partners can lose their limited liability protection if they take an active role in managing the business. If a creditor can prove that a limited partner acted in a way that led the creditor to believe the partner was a general partner, that limited partner can be held personally liable. LPs must remain passive investors.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-alt-013","section":"2 - Products & Risks","stem":"In a limited partnership, who is responsible for making investment decisions and managing day-to-day operations?","choices":{"A":"Limited partners through majority vote","B":"The general partner","C":"An independent board of directors","D":"The Securities and Exchange Commission"},"answer":"B","explanation":"The general partner is responsible for managing the limited partnership, including making investment decisions, overseeing operations, and managing the pooled capital. Limited partners are passive investors who contribute capital but do not participate in management decisions.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-alt-014","section":"2 - Products & Risks","stem":"What is the \"lock-up period\" in hedge fund investing?","choices":{"A":"The time required for SEC approval of the fund","B":"A period during which investors cannot withdraw their money","C":"The time between placing an order and execution","D":"The period when the fund cannot accept new investors"},"answer":"B","explanation":"The lock-up period is a predetermined time during which hedge fund investors cannot withdraw their capital, typically at least one year but sometimes longer. This allows fund managers to invest in illiquid assets without facing redemption pressures. Lock-up periods contribute to the general illiquidity of hedge fund investments.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-alt-015","section":"2 - Products & Risks","stem":"Hedge funds typically use leverage to:","choices":{"A":"Reduce investment risk","B":"Meet regulatory requirements","C":"Increase potential investment returns","D":"Qualify for tax exemptions"},"answer":"C","explanation":"Hedge funds often use leverage (borrowed money) to amplify potential investment returns. They may buy securities on margin or use credit lines from third-party lenders. However, leverage is a double-edged sword - while it can increase gains, it also magnifies losses if investments decline in value.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-alt-016","section":"1 - Capital Markets","stem":"To qualify as an accredited investor under SEC rules, an individual must meet which of the following requirements?","choices":{"A":"Net worth of at least $500,000 or annual income of $100,000","B":"Net worth exceeding $1 million (excluding primary residence) OR annual income of at least $200,000 ($300,000 with spouse)","C":"At least 5 years of investment experience","D":"A minimum investment of $50,000"},"answer":"B","explanation":"An accredited investor must have either: (1) a net worth exceeding $1 million (alone or with spouse), excluding the primary residence, OR (2) annual income of at least $200,000 ($300,000 jointly with spouse) for each of the past two years with expectation of the same. Holding certain FINRA licenses (Series 7, 65, or 82) also qualifies individuals.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-alt-017","section":"2 - Products & Risks","stem":"Which risk is MOST common among all types of alternative investments including REITs, DPPs, and hedge funds?","choices":{"A":"Currency risk","B":"Liquidity risk","C":"Call risk","D":"Reinvestment risk"},"answer":"B","explanation":"Liquidity risk is the most common characteristic of alternative investments. Non-traded REITs are difficult to sell, DPPs typically have no secondary market, and hedge funds impose lock-up periods. Investors in alternative investments must be prepared to have their capital tied up for extended periods and should not need quick access to their funds.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-opt-001","section":"2 - Products & Risks","stem":"An investor purchases a call option with a strike price of $50. This gives the investor the right to:","choices":{"A":"Sell 100 shares at $50 per share","B":"Buy 100 shares at $50 per share","C":"Receive $50 in dividends","D":"Borrow $50 per share from the broker"},"answer":"B","explanation":"A call option gives the holder (buyer) the RIGHT to BUY 100 shares of the underlying stock at the strike price. In this case, the investor has the right to buy 100 shares at $50 per share, regardless of where the market price moves. Standard equity options contracts represent 100 shares.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-opt-002","section":"2 - Products & Risks","stem":"Which of the following BEST describes a put option?","choices":{"A":"The obligation to buy shares at a specified price","B":"The right to sell shares at a specified price","C":"The obligation to sell shares at a specified price","D":"The right to receive dividends on shares"},"answer":"B","explanation":"A put option gives the holder (buyer) the RIGHT to SELL shares at a specified price (the strike price). Put buyers are typically bearish, as they profit when the stock price falls below the strike price. The keyword \"right\" is important - buyers have rights, while sellers have obligations.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-opt-003","section":"2 - Products & Risks","stem":"The price paid by an option buyer to acquire an options contract is called the:","choices":{"A":"Strike price","B":"Premium","C":"Exercise price","D":"Intrinsic value"},"answer":"B","explanation":"The premium is the price paid by the option buyer to the option seller (writer) in exchange for the rights conveyed by the option contract. The premium is determined by factors including time value and intrinsic value. This is the cost of acquiring the option.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-opt-004","section":"2 - Products & Risks","stem":"A call option with a strike price of $45 is trading while the underlying stock is at $52. This option is:","choices":{"A":"In-the-money by $7","B":"Out-of-the-money by $7","C":"At-the-money","D":"In-the-money by $45"},"answer":"A","explanation":"A call option is in-the-money (ITM) when the market price of the underlying stock is ABOVE the strike price. Here, the stock ($52) is trading $7 above the strike price ($45), so the call has $7 of intrinsic value and is $7 in-the-money. The holder could exercise to buy at $45 and immediately sell at $52.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-opt-005","section":"2 - Products & Risks","stem":"An investor holds a put option with a strike price of $60. The underlying stock is currently trading at $53. This put option is:","choices":{"A":"Out-of-the-money by $7","B":"At-the-money","C":"In-the-money by $7","D":"In-the-money by $53"},"answer":"C","explanation":"A put option is in-the-money (ITM) when the market price of the underlying stock is BELOW the strike price. The put holder has the right to sell at $60 when the stock is only worth $53, creating $7 of intrinsic value. The option is $7 in-the-money ($60 strike - $53 market = $7).","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-opt-006","section":"2 - Products & Risks","stem":"Which party to an options contract has an OBLIGATION rather than a right?","choices":{"A":"The call buyer","B":"The put buyer","C":"The option writer","D":"The option holder"},"answer":"C","explanation":"Option writers (sellers) have OBLIGATIONS, not rights. The call writer is obligated to sell shares if assigned, and the put writer is obligated to buy shares if assigned. Writers receive the premium in exchange for taking on this obligation. Option buyers (holders) have rights, not obligations.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-opt-007","section":"2 - Products & Risks","stem":"What is the maximum loss for a put option buyer?","choices":{"A":"Unlimited","B":"The strike price","C":"The premium paid","D":"The strike price minus the premium"},"answer":"C","explanation":"The maximum loss for any option BUYER (whether call or put) is limited to the premium paid for the option. If the option expires worthless (out-of-the-money), the buyer loses only the premium. This is a key advantage of buying options versus other bearish strategies.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-opt-008","section":"2 - Products & Risks","stem":"An investor writes (sells) a call option and receives a premium of $300. What is the MAXIMUM gain for this investor?","choices":{"A":"Unlimited","B":"$300","C":"The strike price","D":"The strike price plus $300"},"answer":"B","explanation":"The maximum gain for an option seller (writer) is always limited to the premium received. If the option expires worthless, the writer keeps the entire premium as profit. In this case, the maximum gain is the $300 premium received. Writers profit when options expire worthless.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-opt-009","section":"2 - Products & Risks","stem":"An investor owns 100 shares of XYZ stock purchased at $40 per share and writes 1 XYZ 45 call for a $3 premium. What is the maximum GAIN on this covered call position?","choices":{"A":"$300","B":"$500","C":"$800","D":"Unlimited"},"answer":"C","explanation":"In a covered call, maximum gain = (Strike price - Stock purchase price) + Premium received. Here: ($45 - $40) + $3 = $5 + $3 = $8 per share. With 100 shares, maximum gain = $8 x 100 = $800. This occurs if the stock rises to or above $45 and the call is exercised or assigned.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-opt-010","section":"2 - Products & Risks","stem":"An investor buys 100 shares of stock at $55 and purchases a protective put with a strike price of $50 for a $2 premium. What is the MAXIMUM LOSS on this position?","choices":{"A":"$200","B":"$500","C":"$700","D":"Unlimited"},"answer":"C","explanation":"A protective put limits downside risk. Maximum loss = (Stock purchase price - Put strike price) + Premium paid. Here: ($55 - $50) + $2 = $5 + $2 = $7 per share. With 100 shares, maximum loss = $7 x 100 = $700. The put guarantees the ability to sell at $50, limiting losses.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-opt-011","section":"2 - Products & Risks","stem":"Which organization issues standardized options contracts and guarantees their performance?","choices":{"A":"FINRA","B":"The Securities and Exchange Commission (SEC)","C":"The Options Clearing Corporation (OCC)","D":"The Federal Reserve Board"},"answer":"C","explanation":"The Options Clearing Corporation (OCC) is the issuer and guarantor of all listed options contracts in the United States. The OCC standardizes contracts and acts as the counterparty to every options trade, guaranteeing performance and eliminating counterparty risk between buyers and sellers.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-opt-012","section":"2 - Products & Risks","stem":"An investor buys a put option with a strike price of $40 and pays a premium of $3. What is the breakeven point for this investor?","choices":{"A":"$43","B":"$40","C":"$37","D":"$3"},"answer":"C","explanation":"For a put buyer, breakeven = Strike price - Premium. The stock must fall below this point for the buyer to profit. Here: $40 - $3 = $37. At $37, the $3 gain from exercising equals the $3 premium paid. Below $37, the put buyer profits.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-opt-013","section":"2 - Products & Risks","stem":"An investor sells a naked (uncovered) call option. Which statement about the risk of this position is TRUE?","choices":{"A":"Maximum loss is limited to the premium received","B":"Maximum loss is limited to the strike price","C":"Maximum loss is theoretically unlimited","D":"There is no risk since the writer received a premium"},"answer":"C","explanation":"Selling a naked call is one of the riskiest options strategies because the maximum loss is theoretically UNLIMITED. Since stock prices can rise indefinitely, the naked call writer may have to buy stock at very high market prices to deliver at the lower strike price. The premium received provides only minimal protection.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-opt-014","section":"2 - Products & Risks","stem":"When an option holder exercises their option, what happens to the option writer?","choices":{"A":"The writer receives an additional premium","B":"The writer is \"assigned\" and must fulfill their obligation","C":"The writer can choose whether to fulfill the contract","D":"The writer's position is cancelled with no obligation"},"answer":"B","explanation":"When an option holder exercises, the OCC randomly assigns the exercise to an option writer who has an open position. The assigned writer MUST fulfill their obligation - a call writer must sell shares at the strike price, and a put writer must buy shares at the strike price. Writers cannot refuse assignment.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-opt-015","section":"2 - Products & Risks","stem":"All else being equal, which option would have the HIGHEST time value?","choices":{"A":"An option expiring in 1 week","B":"An option expiring in 1 month","C":"An option expiring in 6 months","D":"An option expiring tomorrow"},"answer":"C","explanation":"Time value is highest when more time remains until expiration. More time means more opportunity for the underlying stock to move favorably, making the option more valuable. The 6-month option has the most time remaining and therefore the highest time value, all else being equal.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-sie-opt-016","section":"3 - Trading, Accounts & Prohibited","stem":"The Options Clearing Corporation (OCC) serves all of the following functions EXCEPT:","choices":{"A":"Issuing standardized options contracts","B":"Acting as the buyer to every seller and seller to every buyer","C":"Setting individual stock prices in the market","D":"Guaranteeing the performance of options contracts"},"answer":"C","explanation":"The OCC does NOT set stock prices - stock prices are determined by supply and demand in the securities markets. The OCC issues and standardizes options contracts, acts as the central counterparty (buyer to sellers, seller to buyers), and guarantees contract performance, but it has no role in determining underlying stock prices.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s7-pv30","section":"2 - Products & Risks","stem":"A stock that reinvests all earnings into business expansion rather than paying dividends is characteristic of a:","choices":{"A":"Growth stock","B":"Income stock","C":"Blue chip stock","D":"Defensive stock"},"answer":"A","explanation":"Growth stocks typically reinvest earnings into expansion rather than paying dividends. Investors buy for capital appreciation potential. Income stocks pay regular dividends, blue chips pay consistent dividends, and defensive stocks maintain stable dividends during downturns.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s7-pv45","section":"2 - Products & Risks","stem":"Which statement about corporate bond risks is TRUE?","choices":{"A":"Short-term bonds have more interest rate risk than long-term bonds","B":"Investment-grade bonds have more credit risk than high-yield bonds","C":"Long-term bonds have more interest rate risk than short-term bonds","D":"All corporate bonds are guaranteed against default"},"answer":"C","explanation":"Long-term bonds have greater interest rate (price) risk because their prices are more sensitive to rate changes - they have higher duration. When rates rise, long-term bonds fall more in price than short-term bonds.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s7-pv101","section":"2 - Products & Risks","stem":"Which statement about preferred stock is FALSE?","choices":{"A":"Preferred stockholders receive dividends before common stockholders","B":"Preferred stock typically pays a fixed dividend rate","C":"Preferred dividends must be paid by law, similar to bond interest","D":"Preferred stockholders have priority over common in liquidation"},"answer":"C","explanation":"Unlike bond interest, preferred dividends are NOT a legal obligation. The board of directors can choose to skip preferred dividends without triggering default. While preferred dividends have priority over common dividends, the company is not legally required to pay them.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s7-pv104","section":"4 - Regulatory Framework","stem":"The regulation of broker-dealers, exchanges, and trading of existing securities falls under which federal legislation?","choices":{"A":"Securities Exchange Act of 1934","B":"Securities Act of 1933","C":"Investment Company Act of 1940","D":"Investment Advisers Act of 1940"},"answer":"A","explanation":"The Securities Exchange Act of 1934 regulates the secondary market, including exchanges, broker-dealers, and the trading of existing securities. The 1933 Act focuses on new issues (primary market). The 1940 Acts govern investment companies and investment advisers.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s7-pv109","section":"2 - Products & Risks","stem":"During the 20-day cooling-off period for a new securities offering, which activities are PERMITTED?","choices":{"A":"Accepting binding orders from customers","B":"Distributing the final prospectus to potential investors","C":"Collecting indications of interest and distributing red herrings","D":"Guaranteeing allocation of shares to interested investors"},"answer":"C","explanation":"During the cooling-off period (registration review), the underwriter may: distribute preliminary prospectuses (red herrings), collect non-binding indications of interest, and conduct due diligence. They cannot accept binding orders, distribute final prospectuses, or guarantee share allocations until the effective date.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s7-pv110","section":"2 - Products & Risks","stem":"For which type of investment company can shares NEVER be purchased at a discount to NAV?","choices":{"A":"Closed-end fund trading on an exchange","B":"Unit investment trust","C":"Open-end mutual fund","D":"Exchange-traded fund"},"answer":"C","explanation":"Open-end mutual funds issue and redeem shares at NAV (plus any applicable sales charge). Shares cannot trade at a discount to NAV. Closed-end funds and ETFs trade on exchanges and can trade at premiums or discounts. UITs are also priced at NAV plus sales charge.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s7-pv111","section":"2 - Products & Risks","stem":"An investor seeking to minimize interest rate risk should invest in which security?","choices":{"A":"30-year Treasury bonds","B":"90-day commercial paper","C":"10-year corporate bonds","D":"20-year municipal bonds"},"answer":"B","explanation":"Commercial paper (typically 270 days or less maturity) has the least interest rate risk because of its very short duration. Interest rate risk increases with maturity - longer-term bonds experience greater price volatility when interest rates change. The 90-day maturity minimizes exposure to rate changes.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s7-pv112","section":"4 - Regulatory Framework","stem":"A registered representative receives an adverse ruling in a FINRA disciplinary proceeding. What is the representative's appeal option?","choices":{"A":"Appeal to FINRA's National Adjudicatory Council only","B":"Appeal directly to federal district court","C":"Appeal the decision to the SEC","D":"No appeals are permitted for FINRA disciplinary decisions"},"answer":"C","explanation":"After exhausting FINRA's internal appeal process (National Adjudicatory Council), a person subject to an adverse FINRA disciplinary decision may appeal to the SEC. The SEC has oversight authority over FINRA as a self-regulatory organization. Further appeals may go to federal courts.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s7-pv119","section":"2 - Products & Risks","stem":"Under the Investment Company Act of 1940, which of the following is NOT classified as an investment company?","choices":{"A":"Open-end management company","B":"Hedge fund","C":"Unit investment trust","D":"Closed-end management company"},"answer":"B","explanation":"Hedge funds are NOT investment companies under the 1940 Act. They rely on exemptions (typically Section 3(c)(1) or 3(c)(7)) to avoid registration. The three types of investment companies are: open-end management companies (mutual funds), closed-end management companies, and unit investment trusts.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s7-pv120","section":"4 - Regulatory Framework","stem":"Commercial paper is exempt from SEC registration if it meets which conditions?","choices":{"A":"Maturity of 270 days or less and used for current transactions","B":"Maturity of 1 year or less and rated investment grade","C":"Minimum denomination of $100,000","D":"Sold only to institutional investors"},"answer":"A","explanation":"Commercial paper is exempt from SEC registration under Section 3(a)(3) if: (1) maturity does not exceed 270 days, (2) proceeds are used for current transactions (working capital), and (3) it is not offered to the general public (typically sold to institutions). Being investment grade enhances marketability but is not a registration requirement.","source":"OpenExamPrep.com (683 free, no signup)"},{"id":"qb-s7-pv124","section":"4 - Regulatory Framework","stem":"When opening a new brokerage account, a customer may choose which types of accounts?","choices":{"A":"Only cash accounts are available initially","B":"Cash accounts and/or margin accounts","C":"Only margin accounts for trading securities","D":"Custodial accounts only for first-time investors"},"answer":"B","explanation":"Customers may open cash accounts (pay in full) and/or margin accounts (borrow from broker). Margin accounts require additional documentation (margin agreement, loan consent, hypothecation agreement) and approval but are not restricted to experienced investors. The customer chooses based on their needs.","source":"OpenExamPrep.com (683 free, no signup)"}];
